-- Poems batch 443
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-0','奉和嚴中丞西城晚眺十韻','杜甫','唐','御定全唐诗','yuding','','[]','汲黯匡君切，廉頗出將頻。直詞才不世，雄略動如神。',120,'御定全唐詩/json/227.json','["汲黯匡君切，廉頗出將頻。直詞才不世，雄略動如神。", "政簡移風速，詩清立意新。層城臨暇景，絕域望餘春。", "旗尾蛟龍會，樓頭燕雀馴。地平江動蜀，天闊樹浮秦。", "帝念深分閫，軍須遠算緡。花羅封蛺蝶，瑞錦送麒麟。", "辭第輸高義，觀圖憶古人。征南多興緒，事業闇相親。"]'),
('yuding-1','嚴中丞枉駕見過','杜甫','唐','御定全唐诗','yuding','','[]','元戎小隊出郊坰，問柳尋花到野亭。川合東西瞻使節，',40,'御定全唐詩/json/227.json','["元戎小隊出郊坰，問柳尋花到野亭。川合東西瞻使節，", "寂寞江天雲霧裏，何人道有少微星。"]'),
('yuding-2','廣州段功曹到得楊五長史譚書功曹卻歸聊寄此詩','杜甫','唐','御定全唐诗','yuding','','[]','衛青開幕府，楊僕將樓船。漢節梅花外，春城海水邊。',48,'御定全唐詩/json/227.json','["衛青開幕府，楊僕將樓船。漢節梅花外，春城海水邊。", "銅梁書遠及，珠浦使將旋。貧病他鄉老，煩君萬里傳。"]'),
('yuding-3','得廣州張判官叔卿書，使還，以詩代意','杜甫','唐','御定全唐诗','yuding','','[]','鄉關胡騎遠，宇宙蜀城偏。忽得炎州信，遙從月峽傳。',48,'御定全唐詩/json/227.json','["鄉關胡騎遠，宇宙蜀城偏。忽得炎州信，遙從月峽傳。", "雲深驃騎幕，夜隔孝廉船。卻寄雙愁眼，相思淚點懸。"]'),
('yuding-4','送段功曹歸廣州','杜甫','唐','御定全唐诗','yuding','','[]','南海春天外，功曹幾月程。峽雲籠樹小，湖日落船明。',48,'御定全唐詩/json/227.json','["南海春天外，功曹幾月程。峽雲籠樹小，湖日落船明。", "交趾丹砂重，韶州白葛輕。幸君因旅客，時寄錦官城。"]'),
('yuding-5','絕句漫興九首','杜甫','唐','御定全唐诗','yuding','','[]','眼見客愁愁不醒，無賴春色到江亭。',288,'御定全唐詩/json/227.json','["眼見客愁愁不醒，無賴春色到江亭。", "即遣花開深造次，便覺鶯語太丁寧。", "手種桃李非無主，野老牆低還似家。", "恰似春風相欺得，夜來吹折數枝花。", "熟知茅齋絕低小，江上燕子故來頻。", "銜泥點汙琴書內，更接飛蟲打著人。", "二月已破三月來，漸老逢春能幾回。", "莫思身外無窮事，且盡生前有限杯。", "腸斷春江欲盡頭，杖藜徐步立芳洲。", "顛狂柳絮隨風去，輕薄桃花逐水流。", "懶慢無堪不出村，呼兒日在掩柴門。", "蒼苔濁酒林中靜，碧水春風野外昏。", "糝徑楊花鋪白氈，點溪荷葉疊青錢。", "筍根稚子無人見，沙上鳧雛傍母眠。", "舍西柔桑葉可拈，江畔細麥複纖纖。", "人生幾何春已夏，不放香醪如蜜甜。", "隔戶楊柳弱嫋嫋，恰似十五女兒腰。", "誰謂朝來不作意，狂風挽斷最長條。"]'),
('yuding-6','江畔獨步尋花七絕句','杜甫','唐','御定全唐诗','yuding','','[]','江上被花惱不徹，無處告訴只顛狂。',224,'御定全唐詩/json/227.json','["江上被花惱不徹，無處告訴只顛狂。", "走覓南鄰愛酒伴，經旬出飲獨空床。", "稠花亂蕊畏江濱，行步欹危實怕春。", "詩酒尚堪驅使在，未須料理白頭人。", "江深竹靜兩三家，多事紅花映白花。", "報答春光知有處，應須美酒送生涯。", "東望少城花滿煙，百花高樓更可憐。", "誰能載酒開金盞，喚取佳人舞繡筵。", "黃師塔前江水東，春光懶困倚微風。", "桃花一簇開無主，可愛深紅愛淺紅。", "黃四娘家花滿蹊，千朵萬朵壓枝低。", "留連戲蝶時時舞，自在嬌鶯恰恰啼。", "不是愛花即肯死，只恐花盡老相催。", "繁枝容易紛紛落，嫩葉商量細細開。"]'),
('yuding-7','三絕句','杜甫','唐','御定全唐诗','yuding','','[]','楸樹馨香倚釣磯，斬新花蕊未應飛。',96,'御定全唐詩/json/227.json','["楸樹馨香倚釣磯，斬新花蕊未應飛。", "不如醉裏風吹盡，可忍醒時雨打稀。", "門外鸕鷀去不來，沙頭忽見眼相猜。", "自今已後知人意，一日須來一百回。", "無數春筍滿林生，柴門密掩斷人行。", "會須上番看成竹，客至從嗔不出迎。"]'),
('yuding-8','戲為六絕句','杜甫','唐','御定全唐诗','yuding','','[]','庾信文章老更成，淩雲健筆意縱橫。',192,'御定全唐詩/json/227.json','["庾信文章老更成，淩雲健筆意縱橫。", "今人嗤點流傳賦，不覺前賢畏後生。", "楊王盧駱當時體，輕薄為文哂未休。", "爾曹身與名俱滅，不廢江河萬古流。", "縱使盧王操翰墨，劣于漢魏近風騷。", "龍文虎脊皆君馭，曆塊過都見爾曹。", "才力應難誇數公，凡今誰是出群雄。", "或看翡翠蘭苕上，未掣鯨魚碧海中。", "不薄今人愛古人，清詞麗句必為鄰。", "竊攀屈宋宜方駕，恐與齊梁作後塵。", "未及前賢更勿疑，遞相祖述複先誰。", "別裁偽體親風雅，轉益多師是汝師。"]'),
('yuding-9','江頭四詠：丁香','杜甫','唐','御定全唐诗','yuding','','[]','丁香體柔弱，亂結枝猶墊。細葉帶浮毛，疏花披素豔。',48,'御定全唐詩/json/227.json','["丁香體柔弱，亂結枝猶墊。細葉帶浮毛，疏花披素豔。", "深栽小齋後，庶近幽人占。晚墮蘭麝中，休懷粉身念。"]'),
('yuding-10','江頭四詠：梔子','杜甫','唐','御定全唐诗','yuding','','[]','梔子比眾木，人間誠未多。于身色有用，與道氣傷和。',48,'御定全唐詩/json/227.json','["梔子比眾木，人間誠未多。于身色有用，與道氣傷和。", "紅取風霜實，青看雨露柯。無情移得汝，貴在映江波。"]'),
('yuding-11','江頭四詠：鸂鶒','杜甫','唐','御定全唐诗','yuding','','[]','故使籠寬織，須知動損毛。看雲莫悵望，失水任呼號。',48,'御定全唐詩/json/227.json','["故使籠寬織，須知動損毛。看雲莫悵望，失水任呼號。", "六翮曾經剪，孤飛卒未高。且無鷹隼慮，留滯莫辭勞。"]'),
('yuding-12','江頭四詠：花鴨','杜甫','唐','御定全唐诗','yuding','','[]','花鴨無泥滓，階前每緩行。羽毛知獨立，黑白太分明。',48,'御定全唐詩/json/227.json','["花鴨無泥滓，階前每緩行。羽毛知獨立，黑白太分明。", "不覺群心妒，休牽眾眼驚。稻粱沾汝在，作意莫先鳴。"]'),
('yuding-13','畏人','杜甫','唐','御定全唐诗','yuding','','[]','早花隨處發，春鳥異方啼。萬里清江上，三年落日低。',48,'御定全唐詩/json/227.json','["早花隨處發，春鳥異方啼。萬里清江上，三年落日低。", "畏人成小築，褊性合幽棲。門徑從榛草，無心走馬蹄。"]'),
('yuding-14','遠遊','杜甫','唐','御定全唐诗','yuding','','[]','賤子何人記，迷芳著處家。竹風連野色，江沫擁春沙。',48,'御定全唐詩/json/227.json','["賤子何人記，迷芳著處家。竹風連野色，江沫擁春沙。", "種藥扶衰病，吟詩解歎嗟。似聞胡騎走，失喜問京華。"]'),
('yuding-15','野望','杜甫','唐','御定全唐诗','yuding','','[]','西山白雪三奇戍，南浦清江萬里橋。海內風塵諸弟隔，',40,'御定全唐詩/json/227.json','["西山白雪三奇戍，南浦清江萬里橋。海內風塵諸弟隔，", "跨馬出郊時極目，不堪人事日蕭條。"]'),
('yuding-16','官池春雁二首','杜甫','唐','御定全唐诗','yuding','','[]','自古稻粱多不足，至今鸂鶒亂為群。',64,'御定全唐詩/json/227.json','["自古稻粱多不足，至今鸂鶒亂為群。", "且休悵望看春水，更恐歸飛隔暮雲。", "青春欲盡急還鄉，紫塞甯論尚有霜。", "翅在雲天終不遠，力微矰繳絕須防。"]'),
('yuding-17','水檻遣心二首','杜甫','唐','御定全唐诗','yuding','','[]','去郭軒楹敞，無村眺望賒。澄江平少岸，幽樹晚多花。',96,'御定全唐詩/json/227.json','["去郭軒楹敞，無村眺望賒。澄江平少岸，幽樹晚多花。", "細雨魚兒出，微風燕子斜。城中十萬戶，此地兩三家。", "蜀天常夜雨，江檻已朝晴。葉潤林塘密，衣幹枕席清。", "不堪祗老病，何得尚浮名。淺把涓涓酒，深憑送此生。"]'),
('yuding-18','屏跡三首','杜甫','唐','御定全唐诗','yuding','','[]','用拙存吾道，幽居近物情。桑麻深雨露，燕雀半生成。',144,'御定全唐詩/json/227.json','["用拙存吾道，幽居近物情。桑麻深雨露，燕雀半生成。", "村鼓時時急，漁舟個個輕。杖藜從白首，心跡喜雙清。", "晚起家何事，無營地轉幽。竹光團野色，舍影漾江流。", "失學從兒懶，長貧任婦愁。百年渾得醉，一月不梳頭。", "衰顏甘屏跡，幽事供高臥。鳥下竹根行，龜開萍葉過。", "年荒酒價乏，日並園蔬課。猶酌甘泉歌，歌長擊樽破。"]'),
('yuding-19','奉酬嚴公寄題野亭之作','杜甫','唐','御定全唐诗','yuding','','[]','拾遺曾奏數行書，懶性從來水竹居。奉引濫騎沙苑馬，',40,'御定全唐詩/json/227.json','["拾遺曾奏數行書，懶性從來水竹居。奉引濫騎沙苑馬，", "枉沐旌麾出城府，草茅無徑欲教鋤。"]'),
('yuding-20','中丞嚴公雨中垂寄見憶一絕，奉答二絕','杜甫','唐','御定全唐诗','yuding','','[]','雨映行宮辱贈詩，元戎肯赴野人期。',64,'御定全唐詩/json/227.json','["雨映行宮辱贈詩，元戎肯赴野人期。", "江邊老病雖無力，強擬晴天理釣絲。", "何日雨晴雲出溪，白沙青石先無泥。", "只須伐竹開荒徑，倚杖穿花聽馬嘶。"]'),
('yuding-21','謝嚴中丞送青城山道士乳酒一瓶','杜甫','唐','御定全唐诗','yuding','','[]','山瓶乳酒下青雲，氣味濃香幸見分。',32,'御定全唐詩/json/227.json','["山瓶乳酒下青雲，氣味濃香幸見分。", "鳴鞭走送憐漁父，洗盞開嘗對馬軍。"]'),
('yuding-22','嚴公仲夏枉駕草堂，兼攜酒饌','杜甫','唐','御定全唐诗','yuding','','[]','竹裏行廚洗玉盤，花邊立馬簇金鞍。非關使者徵求急，',40,'御定全唐詩/json/227.json','["竹裏行廚洗玉盤，花邊立馬簇金鞍。非關使者徵求急，", "看弄漁舟移白日，老農何有罄交歡。"]'),
('yuding-23','嚴公廳宴，同詠蜀道畫圖','杜甫','唐','御定全唐诗','yuding','','[]','日臨公館靜，畫滿地圖雄。劍閣星橋北，松州雪嶺東。',48,'御定全唐詩/json/227.json','["日臨公館靜，畫滿地圖雄。劍閣星橋北，松州雪嶺東。", "華夷山不斷，吳蜀水相通。興與煙霞會，清樽幸不空。"]'),
('yuding-24','奉送嚴公入朝十韻','杜甫','唐','御定全唐诗','yuding','','[]','鼎湖瞻望遠，象闕憲章新。四海猶多難，中原憶舊臣。',120,'御定全唐詩/json/227.json','["鼎湖瞻望遠，象闕憲章新。四海猶多難，中原憶舊臣。", "與時安反側，自昔有經綸。感激張天步，從容靜塞塵。", "南圖回羽翮，北極捧星辰。漏鼓還思晝，宮鶯罷囀春。", "空留玉帳術，愁殺錦城人。閣道通丹地，江潭隱白蘋。", "此生那老蜀，不死會歸秦。公若登臺輔，臨危莫愛身。"]'),
('yuding-25','送嚴侍郎到綿州，同登杜使君江樓','杜甫','唐','御定全唐诗','yuding','','[]','野興每難盡，江樓延賞心。歸朝送使節，落景惜登臨。',120,'御定全唐詩/json/227.json','["野興每難盡，江樓延賞心。歸朝送使節，落景惜登臨。", "稍稍煙集渚，微微風動襟。重船依淺瀨，輕鳥度層陰。", "檻峻背幽谷，窗虛交茂林。燈光散遠近，月彩靜高深。", "城擁朝來客，天橫醉後參。窮途衰謝意，苦調短長吟。", "此會共能幾，諸孫賢至今。不勞朱戶閉，自待白河沉。"]'),
('yuding-26','奉濟驛重送嚴公四韻','杜甫','唐','御定全唐诗','yuding','','[]','遠送從此別，青山空複情。幾時杯重把，昨夜月同行。',48,'御定全唐詩/json/227.json','["遠送從此別，青山空複情。幾時杯重把，昨夜月同行。", "列郡謳歌惜，三朝出入榮。江村獨歸處，寂寞養殘生。"]'),
('yuding-27','送梓州李使君之任','杜甫','唐','御定全唐诗','yuding','','[]','籍甚黃丞相，能名自潁川。近看除刺史，還喜得吾賢。',96,'御定全唐詩/json/227.json','["籍甚黃丞相，能名自潁川。近看除刺史，還喜得吾賢。", "五馬何時到，雙魚會早傳。老思筇竹杖，冬要錦衾眠。", "不作臨岐恨，惟聽舉最先。火雲揮汗日，山驛醒心泉。", "遇害陳公殞，於今蜀道憐。君行射洪縣，為我一潸然。"]'),
('yuding-28','巴西驛亭觀江漲，呈竇使君','杜甫','唐','御定全唐诗','yuding','','[]','宿雨南江漲，波濤亂遠峰。孤亭淩噴薄，萬井逼舂容。',48,'御定全唐詩/json/227.json','["宿雨南江漲，波濤亂遠峰。孤亭淩噴薄，萬井逼舂容。", "霄漢愁高鳥，泥沙困老龍。天邊同客舍，攜我豁心胸。"]'),
('yuding-29','九日登梓州城','杜甫','唐','御定全唐诗','yuding','','[]','伊昔黃花酒，如今白髮翁。追歡筋力異，望遠歲時同。',48,'御定全唐詩/json/227.json','["伊昔黃花酒，如今白髮翁。追歡筋力異，望遠歲時同。", "弟妹悲歌裏，朝廷醉眼中。兵戈與關塞，此日意無窮。"]'),
('yuding-30','九日奉寄嚴大夫','杜甫','唐','御定全唐诗','yuding','','[]','九日應愁思，經時冒險艱。不眠持漢節，何路出巴山。',48,'御定全唐詩/json/227.json','["九日應愁思，經時冒險艱。不眠持漢節，何路出巴山。", "小驛香醪嫩，重岩細菊斑。遙知簇鞍馬，回首白雲間。"]'),
('yuding-31','黃草','杜甫','唐','御定全唐诗','yuding','','[]','黃草峽西船不歸，赤甲山下行人稀。秦中驛使無消息，',40,'御定全唐詩/json/227.json','["黃草峽西船不歸，赤甲山下行人稀。秦中驛使無消息，", "莫愁劍閣終堪據，聞道松州已被圍。"]'),
('yuding-32','懷舊','杜甫','唐','御定全唐诗','yuding','','[]','地下蘇司業，情親獨有君。那因喪亂後，便有死生分。',48,'御定全唐詩/json/227.json','["地下蘇司業，情親獨有君。那因喪亂後，便有死生分。", "老罷知明鏡，悲來望白雲。自從失詞伯，不復更論文。"]'),
('yuding-33','所思','杜甫','唐','御定全唐诗','yuding','','[]','鄭老身仍竄，台州信所傳。為農山澗曲，臥病海雲邊。',48,'御定全唐詩/json/227.json','["鄭老身仍竄，台州信所傳。為農山澗曲，臥病海雲邊。", "世已疏儒素，人猶乞酒錢。徒勞望牛鬥，無計劚龍泉。"]'),
('yuding-34','不見','杜甫','唐','御定全唐诗','yuding','','[]','不見李生久，佯狂真可哀。世人皆欲殺，吾意獨憐才。',48,'御定全唐詩/json/227.json','["不見李生久，佯狂真可哀。世人皆欲殺，吾意獨憐才。", "敏捷詩千首，飄零酒一杯。匡山讀書處，頭白好歸來。"]'),
('yuding-35','題玄武禪師屋壁','杜甫','唐','御定全唐诗','yuding','','[]','何年顧虎頭，滿壁畫瀛州。赤日石林氣，青天江海流。',48,'御定全唐詩/json/227.json','["何年顧虎頭，滿壁畫瀛州。赤日石林氣，青天江海流。", "錫飛常近鶴，杯度不驚鷗。似得廬山路，真隨惠遠遊。"]'),
('yuding-36','客夜','杜甫','唐','御定全唐诗','yuding','','[]','客睡何曾著，秋天不肯明。捲簾殘月影，高枕遠江聲。',48,'御定全唐詩/json/227.json','["客睡何曾著，秋天不肯明。捲簾殘月影，高枕遠江聲。", "計拙無衣食，途窮仗友生。老妻書數紙，應悉未歸情。"]'),
('yuding-37','客亭','杜甫','唐','御定全唐诗','yuding','','[]','秋窗猶曙色，落木更天風。日出寒山外，江流宿霧中。',48,'御定全唐詩/json/227.json','["秋窗猶曙色，落木更天風。日出寒山外，江流宿霧中。", "聖朝無棄物，老病已成翁。多少殘生事，飄零似轉蓬。"]'),
('yuding-38','秋盡','杜甫','唐','御定全唐诗','yuding','','[]','秋盡東行且未回，茅齋寄在少城隈。籬邊老卻陶潛菊，',40,'御定全唐詩/json/227.json','["秋盡東行且未回，茅齋寄在少城隈。籬邊老卻陶潛菊，", "不辭萬里長為客，懷抱何時得好開。"]'),
('yuding-39','陪王侍禦宴通泉東山野亭','杜甫','唐','御定全唐诗','yuding','','[]','江水東流去，清樽日複斜。異方同宴賞，何處是京華。',48,'御定全唐詩/json/227.json','["江水東流去，清樽日複斜。異方同宴賞，何處是京華。", "亭景臨山水，村煙對浦沙。狂歌過於勝，得醉即為家。"]'),
('yuding-40','野望','杜甫','唐','御定全唐诗','yuding','','[]','金華山北涪水西，仲冬風日始淒淒。山連越巂蟠三蜀，',40,'御定全唐詩/json/227.json','["金華山北涪水西，仲冬風日始淒淒。山連越巂蟠三蜀，", "射洪春酒寒仍綠，目極傷神誰為攜。"]'),
('yuding-41','聞官軍收河南河北','杜甫','唐','御定全唐诗','yuding','','[]','劍外忽傳收薊北，初聞涕淚滿衣裳。卻看妻子愁何在，',40,'御定全唐詩/json/227.json','["劍外忽傳收薊北，初聞涕淚滿衣裳。卻看妻子愁何在，", "即從巴峽穿巫峽，便下襄陽向洛陽。"]'),
('yuding-42','涪江泛舟送韋班歸京','杜甫','唐','御定全唐诗','yuding','','[]','追餞同舟日，傷春一水間。飄零為客久，衰老羨君還。',48,'御定全唐詩/json/227.json','["追餞同舟日，傷春一水間。飄零為客久，衰老羨君還。", "花遠重重樹，雲輕處處山。天涯故人少，更益鬢毛斑。"]'),
('yuding-43','春日梓州登樓二首','杜甫','唐','御定全唐诗','yuding','','[]','行路難如此，登樓望欲迷。身無卻少壯，跡有但羈棲。',96,'御定全唐詩/json/227.json','["行路難如此，登樓望欲迷。身無卻少壯，跡有但羈棲。", "江水流城郭，春風入鼓鼙。雙雙新燕子，依舊已銜泥。", "天畔登樓眼，隨春入故園。戰場今始定，移柳更能存。", "厭蜀交遊冷，思吳勝事繁。應須理舟楫，長嘯下荊門。"]'),
('yuding-44','郪城西原送李判官兄、武判官弟赴成都府','杜甫','唐','御定全唐诗','yuding','','[]','憑高送所親，久坐惜芳辰。遠水非無浪，他山自有春。',48,'御定全唐詩/json/227.json','["憑高送所親，久坐惜芳辰。遠水非無浪，他山自有春。", "野花隨處發，官柳著行新。天際傷愁別，離筵何太頻。"]'),
('yuding-45','泛江送魏十八倉曹還京，因寄岑中允參、范郎中季明','杜甫','唐','御定全唐诗','yuding','','[]','遲日深春水，輕舟送別筵。帝鄉愁緒外，春色淚痕邊。',48,'御定全唐詩/json/227.json','["遲日深春水，輕舟送別筵。帝鄉愁緒外，春色淚痕邊。", "見酒須相憶，將詩莫浪傳。若逢岑與範，為報各衰年。"]'),
('yuding-46','送路六侍禦入朝','杜甫','唐','御定全唐诗','yuding','','[]','童稚情親四十年，中間消息兩茫然。更為後會知何地，',40,'御定全唐詩/json/227.json','["童稚情親四十年，中間消息兩茫然。更為後會知何地，", "劍南春色還無賴，觸忤愁人到酒邊。"]'),
('yuding-47','泛江送客','杜甫','唐','御定全唐诗','yuding','','[]','二月頻送客，東津江欲平。煙花山際重，舟楫浪前輕。',48,'御定全唐詩/json/227.json','["二月頻送客，東津江欲平。煙花山際重，舟楫浪前輕。", "淚逐勸杯下，愁連吹笛生。離筵不隔日，那得易為情。"]'),
('yuding-48','上牛頭寺','杜甫','唐','御定全唐诗','yuding','','[]','青山意不盡，袞袞上牛頭。無複能拘礙，真成浪出遊。',48,'御定全唐詩/json/227.json','["青山意不盡，袞袞上牛頭。無複能拘礙，真成浪出遊。", "花濃春寺靜，竹細野池幽。何處鶯啼切，移時獨未休。"]'),
('yuding-49','望牛頭寺','杜甫','唐','御定全唐诗','yuding','','[]','牛頭見鶴林，梯逕繞幽深。春色浮山外，天河宿殿陰。',48,'御定全唐詩/json/227.json','["牛頭見鶴林，梯逕繞幽深。春色浮山外，天河宿殿陰。", "傳燈無白日，布地有黃金。休作狂歌老，回看不住心。"]'),
('yuding-50','上兜率寺','杜甫','唐','御定全唐诗','yuding','','[]','兜率知名寺，真如會法堂。江山有巴蜀，棟宇自齊梁。',48,'御定全唐詩/json/227.json','["兜率知名寺，真如會法堂。江山有巴蜀，棟宇自齊梁。", "庾信哀雖久，何顒好不忘。白牛車遠近，且欲上慈航。"]'),
('yuding-51','望兜率寺','杜甫','唐','御定全唐诗','yuding','','[]','樹密當山徑，江深隔寺門。霏霏雲氣重，閃閃浪花翻。',48,'御定全唐詩/json/227.json','["樹密當山徑，江深隔寺門。霏霏雲氣重，閃閃浪花翻。", "不復知天大，空餘見佛尊。時應清盥罷，隨喜給孤園。"]'),
('yuding-52','甘園','杜甫','唐','御定全唐诗','yuding','','[]','春日清江岸，千甘二頃園。青雲羞葉密，白雪避花繁。',48,'御定全唐詩/json/227.json','["春日清江岸，千甘二頃園。青雲羞葉密，白雪避花繁。", "結子隨邊使，開筒近至尊。後於桃李熟，終得獻金門。"]'),
('yuding-53','數陪李梓州泛江，有女樂在諸舫，戲為豔曲二首贈李','杜甫','唐','御定全唐诗','yuding','','[]','上客回空騎，佳人滿近船。江清歌扇底，野曠舞衣前。',96,'御定全唐詩/json/227.json','["上客回空騎，佳人滿近船。江清歌扇底，野曠舞衣前。", "玉袖淩風並，金壺隱浪偏。競將明媚色，偷眼豔陽天。", "白日移歌袖，清霄近笛床。翠眉縈度曲，雲鬢儼分行。", "立馬千山暮，回舟一水香。使君自有婦，莫學野鴛鴦。"]'),
('yuding-54','登牛頭山亭子','杜甫','唐','御定全唐诗','yuding','','[]','路出雙林外，亭窺萬井中。江城孤照日，山谷遠含風。',48,'御定全唐詩/json/227.json','["路出雙林外，亭窺萬井中。江城孤照日，山谷遠含風。", "兵革身將老，關河信不通。猶殘數行淚，忍對百花叢。"]'),
('yuding-55','陪李梓州、王閬州、蘇遂州、李果州四使君登惠義寺','杜甫','唐','御定全唐诗','yuding','','[]','春日無人境，虛空不住天。鶯花隨世界，樓閣寄山巔。',48,'御定全唐詩/json/227.json','["春日無人境，虛空不住天。鶯花隨世界，樓閣寄山巔。", "遲暮身何得，登臨意惘然。誰能解金印，瀟灑共安禪。"]'),
('yuding-56','送何侍禦歸朝','杜甫','唐','御定全唐诗','yuding','','[]','舟楫諸侯餞，車輿使者歸。山花相映發，水鳥自孤飛。',48,'御定全唐詩/json/227.json','["舟楫諸侯餞，車輿使者歸。山花相映發，水鳥自孤飛。", "春日垂霜鬢，天隅把繡衣。故人從此去，寥落寸心違。"]'),
('yuding-57','江亭送眉州辛別駕升之','杜甫','唐','御定全唐诗','yuding','','[]','柳影含雲幕，江波近酒壺。異方驚會面，終宴惜征途。',48,'御定全唐詩/json/227.json','["柳影含雲幕，江波近酒壺。異方驚會面，終宴惜征途。", "沙晚低風蝶，天晴喜浴鳧。別離傷老大，意緒日荒蕪。"]'),
('yuding-58','涪城縣香積寺官閣','杜甫','唐','御定全唐诗','yuding','','[]','寺下春江深不流，山腰官閣迥添愁。含風翠壁孤雲細，',40,'御定全唐詩/json/227.json','["寺下春江深不流，山腰官閣迥添愁。含風翠壁孤雲細，", "諸天合在藤蘿外，昏黑應須到上頭。"]'),
('yuding-59','戲題寄上漢中王三首','杜甫','唐','御定全唐诗','yuding','','[]','西漢親王子，成都老客星。百年雙白鬢，一別五秋螢。',144,'御定全唐詩/json/227.json','["西漢親王子，成都老客星。百年雙白鬢，一別五秋螢。", "忍斷杯中物，祗看座右銘。不能隨皂蓋，自醉逐浮萍。", "策杖時能出，王門異昔遊。已知嗟不起，未許醉相留。", "蜀酒濃無敵，江魚美可求。終思一酩酊，淨掃雁池頭。", "群盜無歸路，衰顏會遠方。尚憐詩警策，猶記酒顛狂。", "魯衛彌尊重，徐陳略喪亡。空餘枚叟在，應念早升堂。"]'),
('yuding-60','陪章留後侍禦宴南樓','杜甫','唐','御定全唐诗','yuding','','[]','絕域長夏晚，茲樓清宴同。朝廷燒棧北，鼓角滿天東。',96,'御定全唐詩/json/227.json','["絕域長夏晚，茲樓清宴同。朝廷燒棧北，鼓角滿天東。", "屢食將軍第，仍騎禦史驄。本無丹灶術，那免白頭翁。", "寇盜狂歌外，形骸痛飲中。野雲低渡水，簷雨細隨風。", "出號江城黑，題詩蠟炬紅。此身醒複醉，不擬哭途窮。"]'),
('yuding-61','臺上','杜甫','唐','御定全唐诗','yuding','','[]','改席台能迥，留門月複光。雲行遺暑濕，山谷進風涼。',48,'御定全唐詩/json/227.json','["改席台能迥，留門月複光。雲行遺暑濕，山谷進風涼。", "老去一杯足，誰憐屢舞長。何須把官燭，似惱鬢毛蒼。"]'),
('yuding-62','送王十五判官扶侍還黔中','杜甫','唐','御定全唐诗','yuding','','[]','大家東征逐子回，風生洲渚錦帆開。青青竹筍迎船出，',40,'御定全唐詩/json/227.json','["大家東征逐子回，風生洲渚錦帆開。青青竹筍迎船出，", "黔陽信使應稀少，莫怪頻頻勸酒杯。"]'),
('yuding-63','《倦夜','杜甫','唐','御定全唐诗','yuding','','[]','竹涼侵臥內，野月滿庭隅。重露成涓滴，稀星乍有無。',48,'御定全唐詩/json/227.json','["竹涼侵臥內，野月滿庭隅。重露成涓滴，稀星乍有無。", "暗飛螢自照，水宿鳥相呼。萬事干戈裏，空悲清夜徂。"]'),
('yuding-64','悲秋','杜甫','唐','御定全唐诗','yuding','','[]','涼風動萬里，群盜尚縱橫。家遠傳書日，秋來為客情。',48,'御定全唐詩/json/227.json','["涼風動萬里，群盜尚縱橫。家遠傳書日，秋來為客情。", "愁窺高鳥過，老逐眾人行。始欲投三峽，何由見兩京。"]'),
('yuding-65','對雨','杜甫','唐','御定全唐诗','yuding','','[]','莽莽天涯雨，江邊獨立時。不愁巴道路，恐濕漢旌旗。',48,'御定全唐詩/json/227.json','["莽莽天涯雨，江邊獨立時。不愁巴道路，恐濕漢旌旗。", "雪嶺防秋急，繩橋戰勝遲。西戎甥舅禮，未敢背恩私。"]'),
('yuding-66','警急','杜甫','唐','御定全唐诗','yuding','','[]','才名舊楚將，妙略擁兵機。玉壘雖傳檄，松州會解圍。',48,'御定全唐詩/json/227.json','["才名舊楚將，妙略擁兵機。玉壘雖傳檄，松州會解圍。", "和親知拙計，公主漫無歸。青海今誰得，西戎實飽飛。"]'),
('yuding-67','王命','杜甫','唐','御定全唐诗','yuding','','[]','漢北豺狼滿，巴西道路難。血埋諸將甲，骨斷使臣鞍。',48,'御定全唐詩/json/227.json','["漢北豺狼滿，巴西道路難。血埋諸將甲，骨斷使臣鞍。", "牢落新燒棧，蒼茫舊築壇。深懷喻蜀意，慟哭望王官。"]'),
('yuding-68','征夫','杜甫','唐','御定全唐诗','yuding','','[]','十室幾人在，千山空自多。路衢唯見哭，城市不聞歌。',48,'御定全唐詩/json/227.json','["十室幾人在，千山空自多。路衢唯見哭，城市不聞歌。", "漂梗無安地，銜枚有荷戈。官軍未通蜀，吾道竟如何。"]'),
('yuding-69','有感五首','杜甫','唐','御定全唐诗','yuding','','[]','將帥蒙恩澤，兵戈有歲年。至今勞聖主，可以報皇天。',240,'御定全唐詩/json/227.json','["將帥蒙恩澤，兵戈有歲年。至今勞聖主，可以報皇天。", "白骨新交戰，雲台舊拓邊。乘槎斷消息，無處覓張騫。", "幽薊餘蛇豕，乾坤尚虎狼。諸侯春不貢，使者日相望。", "慎勿吞青海，無勞問越裳。大君先息戰，歸馬華山陽。", "洛下舟車入，天中貢賦均。日聞紅粟腐，寒待翠華春。", "莫取金湯固，長令宇宙新。不過行儉德，盜賊本王臣。", "丹桂風霜急，青梧日夜凋。由來強幹地，未有不臣朝。", "受鉞親賢往，卑宮制詔遙。終依古封建，豈獨聽簫韶。", "盜滅人還亂，兵殘將自疑。登壇名絕假，報主爾何遲。", "領郡輒無色，之官皆有詞。願聞哀痛詔，端拱問瘡痍。"]'),
('yuding-70','送元二適江左','杜甫','唐','御定全唐诗','yuding','','[]','亂後今相見，秋深複遠行。風塵為客日，江海送君情。',48,'御定全唐詩/json/227.json','["亂後今相見，秋深複遠行。風塵為客日，江海送君情。", "晉室丹陽尹，公孫白帝城。經過自愛惜，取次莫論兵。"]'),
('yuding-71','章梓州水亭','杜甫','唐','御定全唐诗','yuding','','[]','城晚通雲霧，亭深到芰荷。吏人橋外少，秋水席邊多。',48,'御定全唐詩/json/227.json','["城晚通雲霧，亭深到芰荷。吏人橋外少，秋水席邊多。", "近屬淮王至，高門薊子過。荊州愛山簡，吾醉亦長歌。"]'),
('yuding-72','玩月呈漢中王','杜甫','唐','御定全唐诗','yuding','','[]','夜深露氣清，江月滿江城。浮客轉危坐，歸舟應獨行。',48,'御定全唐詩/json/227.json','["夜深露氣清，江月滿江城。浮客轉危坐，歸舟應獨行。", "關山同一照，烏鵲自多驚。欲得淮王術，風吹暈已生。"]'),
('yuding-73','戲作寄上漢中王二首','杜甫','唐','御定全唐诗','yuding','','[]','雲裏不聞雙雁過，掌中貪見一珠新。',64,'御定全唐詩/json/227.json','["雲裏不聞雙雁過，掌中貪見一珠新。", "秋風嫋嫋吹江漢，只在他鄉何處人。", "謝安舟楫風還起，梁苑池台雪欲飛。", "杳杳東山攜漢妓，泠泠修竹待王歸。"]'),
('yuding-74','投簡梓州幕府，兼簡韋十郎官','杜甫','唐','御定全唐诗','yuding','','[]','幕下郎官安穩無，從來不奉一行書。',32,'御定全唐詩/json/227.json','["幕下郎官安穩無，從來不奉一行書。", "固知貧病人須棄，能使韋郎跡也疏。"]'),
('yuding-75','登高','杜甫','唐','御定全唐诗','yuding','','[]','風急天高猿嘯哀，渚清沙白鳥飛回。無邊落木蕭蕭下，',40,'御定全唐詩/json/227.json','["風急天高猿嘯哀，渚清沙白鳥飛回。無邊落木蕭蕭下，", "艱難苦恨繁霜鬢，潦倒新停濁酒杯。"]'),
('yuding-76','九日','杜甫','唐','御定全唐诗','yuding','','[]','去年登高郪縣北，今日重在涪江濱。苦遭白髮不相放，',40,'御定全唐詩/json/227.json','["去年登高郪縣北，今日重在涪江濱。苦遭白髮不相放，", "酒闌卻憶十年事，腸斷驪山清路塵。"]'),
('yuding-77','遣憤','杜甫','唐','御定全唐诗','yuding','','[]','聞道花門將，論功未盡歸。自從收帝裏，誰複總戎機。',48,'御定全唐詩/json/227.json','["聞道花門將，論功未盡歸。自從收帝裏，誰複總戎機。", "蜂蠆終懷毒，雷霆可震威。莫令鞭血地，再濕漢臣衣。"]'),
('yuding-78','章梓州橘亭餞成都竇少尹','杜甫','唐','御定全唐诗','yuding','','[]','秋日野亭千橘香，玉盤錦席高雲涼。主人送客何所作，',40,'御定全唐詩/json/227.json','["秋日野亭千橘香，玉盤錦席高雲涼。主人送客何所作，", "預傳籍籍新京尹，青史無勞數趙張。"]'),
('yuding-79','送陵州路使君赴任','杜甫','唐','御定全唐诗','yuding','','[]','王室比多難，高官皆武臣。幽燕通使者，岳牧用詞人。',96,'御定全唐詩/json/227.json','["王室比多難，高官皆武臣。幽燕通使者，岳牧用詞人。", "國待賢良急，君當拔擢新。佩刀成氣象，行蓋出風塵。", "戰伐乾坤破，瘡痍府庫貧。眾僚宜潔白，萬役但平均。", "霄漢瞻佳士，泥途任此身。秋天正搖落，回首大江濱。"]'),
('yuding-80','薄暮','杜甫','唐','御定全唐诗','yuding','','[]','江水長流地，山雲薄暮時。寒花隱亂草，宿鳥擇深枝。',48,'御定全唐詩/json/227.json','["江水長流地，山雲薄暮時。寒花隱亂草，宿鳥擇深枝。", "舊國見何日，高秋心苦悲。人生不再好，鬢髮白成絲。"]'),
('yuding-81','西山三首','杜甫','唐','御定全唐诗','yuding','','[]','彝界荒山頂，蕃州積雪邊。築城依白帝，轉粟上青天。',144,'御定全唐詩/json/227.json','["彝界荒山頂，蕃州積雪邊。築城依白帝，轉粟上青天。", "蜀將分旗鼓，羌兵助井泉。西戎背和好，殺氣日相纏。", "辛苦三城戍，長防萬里秋。煙塵侵火井，雨雪閉松州。", "風動將軍幕，天寒使者裘。漫山賊營壘，回首得無憂。", "子弟猶深入，關城未解圍。蠶崖鐵馬瘦，灌口米船稀。", "辯士安邊策，元戎決勝威。今朝烏鵲喜，欲報凱歌歸。"]'),
('yuding-82','薄游','杜甫','唐','御定全唐诗','yuding','','[]','淅淅風生砌，團團日隱牆。遙空秋雁滅，半嶺暮雲長。',48,'御定全唐詩/json/227.json','["淅淅風生砌，團團日隱牆。遙空秋雁滅，半嶺暮雲長。", "病葉多先墜，寒花只暫香。巴城添淚眼，今夜複清光。"]'),
('yuding-83','贈韋贊善別','杜甫','唐','御定全唐诗','yuding','','[]','扶病送君發，自憐猶不歸。只應盡客淚，複作掩荊扉。',48,'御定全唐詩/json/227.json','["扶病送君發，自憐猶不歸。只應盡客淚，複作掩荊扉。", "江漢故人少，音書從此稀。往還二十載，歲晚寸心違。"]'),
('yuding-84','送李卿曄','杜甫','唐','御定全唐诗','yuding','','[]','王子思歸日，長安已亂兵。沾衣問行在，走馬向承明。',48,'御定全唐詩/json/227.json','["王子思歸日，長安已亂兵。沾衣問行在，走馬向承明。", "暮景巴蜀僻，春風江漢清。晉山雖自棄，魏闕尚含情。"]'),
('yuding-85','絕句','杜甫','唐','御定全唐诗','yuding','','[]','江邊踏青罷，回首見旌旗。風起春城暮，高樓鼓角悲。',24,'御定全唐詩/json/227.json','["江邊踏青罷，回首見旌旗。風起春城暮，高樓鼓角悲。"]'),
('yuding-86','城上','杜甫','唐','御定全唐诗','yuding','','[]','草滿巴西綠，空城白日長。風吹花片片，春動水茫茫。',48,'御定全唐詩/json/227.json','["草滿巴西綠，空城白日長。風吹花片片，春動水茫茫。", "八駿隨天子，群臣從武皇。遙聞出巡守，早晚遍遐荒。"]'),
('yuding-87','舍弟占歸草堂檢校聊示此詩','杜甫','唐','御定全唐诗','yuding','','[]','久客應吾道，相隨獨爾來。孰知江路近，頻為草堂回。',48,'御定全唐詩/json/227.json','["久客應吾道，相隨獨爾來。孰知江路近，頻為草堂回。", "鵝鴨宜長數，柴荊莫浪開。東林竹影薄，臘月更須栽。"]'),
('yuding-0','傷春五首','杜甫','唐','御定全唐诗','yuding','','[]','天下兵雖滿，春光日自濃。西京疲百戰，北闕任群凶。',360,'御定全唐詩/json/228.json','["天下兵雖滿，春光日自濃。西京疲百戰，北闕任群凶。", "關塞三千里，煙花一萬重。蒙塵清路急，禦宿且誰供。", "殷複前王道，周遷舊國容。蓬萊足雲氣，應合總從龍。", "鶯入新年語，花開滿故枝。天青風卷幔，草碧水通池。", "牢落官軍速，蕭條萬事危。鬢毛元自白，淚點向來垂。", "不是無兄弟，其如有別離。巴山春色靜，北望轉逶迤。", "日月還相鬥，星辰屢合圍。不成誅執法，焉得變危機。", "大角纏兵氣，鉤陳出帝畿。煙塵昏禦道，耆舊把天衣。", "行在諸軍闕，來朝大將稀。賢多隱屠釣，王肯載同歸。", "再有朝廷亂，難知消息真。近傳王在洛，複道使歸秦。", "奪馬悲公主，登車泣貴嬪。蕭關迷北上，滄海欲東巡。", "敢料安危體，猶多老大臣。豈無嵇紹血，沾灑屬車塵。", "聞說初東幸，孤兒卻走多。難分太倉粟，競棄魯陽戈。", "胡虜登前殿，王公出禦河。得無中夜舞，誰憶大風歌。", "春色生烽燧，幽人泣薜蘿。君臣重修德，猶足見時和。"]'),
('yuding-1','王閬州筵奉酬十一舅惜別之作','杜甫','唐','御定全唐诗','yuding','','[]','萬壑樹聲滿，千崖秋氣高。浮舟出郡郭，別酒寄江濤。',72,'御定全唐詩/json/228.json','["萬壑樹聲滿，千崖秋氣高。浮舟出郡郭，別酒寄江濤。", "良會不復久，此生何太勞。窮愁但有骨，群盜尚如毛。", "吾舅惜分手，使君寒贈袍。沙頭暮黃鵠，失侶自哀號。"]'),
('yuding-2','放船','杜甫','唐','御定全唐诗','yuding','','[]','送客蒼溪縣，山寒雨不開。直愁騎馬滑，故作泛舟回。',48,'御定全唐詩/json/228.json','["送客蒼溪縣，山寒雨不開。直愁騎馬滑，故作泛舟回。", "青惜峰巒過，黃知橘柚來。江流大自在，坐穩興悠哉。"]'),
('yuding-3','奉待嚴大夫','杜甫','唐','御定全唐诗','yuding','','[]','殊方又喜故人來，重鎮還須濟世才。常怪偏裨終日待，',40,'御定全唐詩/json/228.json','["殊方又喜故人來，重鎮還須濟世才。常怪偏裨終日待，", "身老時危思會面，一生襟抱向誰開。"]'),
('yuding-4','奉寄高常侍','杜甫','唐','御定全唐诗','yuding','','[]','汶上相逢年頗多，飛騰無那故人何。總戎楚蜀應全未，',40,'御定全唐詩/json/228.json','["汶上相逢年頗多，飛騰無那故人何。總戎楚蜀應全未，", "天涯春色催遲暮，別淚遙添錦水波。"]'),
('yuding-5','奉寄章十侍禦','杜甫','唐','御定全唐诗','yuding','','[]','淮海維揚一俊人，金章紫綬照青春。指麾能事回天地，',40,'御定全唐詩/json/228.json','["淮海維揚一俊人，金章紫綬照青春。指麾能事回天地，", "朝覲從容問幽仄，勿雲江漢有垂綸。"]'),
('yuding-6','將赴荊南，寄別李劍州','杜甫','唐','御定全唐诗','yuding','','[]','使君高義驅今古，寥落三年坐劍州。但見文翁能化俗，',40,'御定全唐詩/json/228.json','["使君高義驅今古，寥落三年坐劍州。但見文翁能化俗，", "戎馬相逢更何日，春風回首仲宣樓。"]'),
('yuding-7','奉寄別馬巴州','杜甫','唐','御定全唐诗','yuding','','[]','勳業終歸馬伏波，功曹非複漢蕭何。扁舟系纜沙邊久，',40,'御定全唐詩/json/228.json','["勳業終歸馬伏波，功曹非複漢蕭何。扁舟系纜沙邊久，", "知君未愛春湖色，興在驪駒白玉珂。"]'),
('yuding-8','泛江','杜甫','唐','御定全唐诗','yuding','','[]','方舟不用楫，極目總無波。長日容杯酒，深江淨綺羅。',48,'御定全唐詩/json/228.json','["方舟不用楫，極目總無波。長日容杯酒，深江淨綺羅。", "亂離還奏樂，飄泊且聽歌。故國流清渭，如今花正多。"]'),
('yuding-9','陪王使君晦日泛江就黃家亭子二首','杜甫','唐','御定全唐诗','yuding','','[]','山豁何時斷，江平不肯流。稍知花改岸，始驗鳥隨舟。',96,'御定全唐詩/json/228.json','["山豁何時斷，江平不肯流。稍知花改岸，始驗鳥隨舟。", "結束多紅粉，歡娛恨白頭。非君愛人客，晦日更添愁。", "有徑金沙軟，無人碧草芳。野畦連蛺蝶，江檻俯鴛鴦。", "日晚煙花亂，風生錦繡香。不須吹急管，衰老易悲傷。"]'),
('yuding-10','南征','杜甫','唐','御定全唐诗','yuding','','[]','春岸桃花水，雲帆楓樹林。偷生長避地，適遠更沾襟。',48,'御定全唐詩/json/228.json','["春岸桃花水，雲帆楓樹林。偷生長避地，適遠更沾襟。", "老病南征日，君恩北望心。百年歌自苦，未見有知音。"]'),
('yuding-11','久客','杜甫','唐','御定全唐诗','yuding','','[]','羈旅知交態，淹留見俗情。衰顏聊自哂，小吏最相輕。',48,'御定全唐詩/json/228.json','["羈旅知交態，淹留見俗情。衰顏聊自哂，小吏最相輕。", "去國哀王粲，傷時哭賈生。狐狸何足道，豺虎正縱橫。"]'),
('yuding-12','春遠','杜甫','唐','御定全唐诗','yuding','','[]','肅肅花絮晚，菲菲紅素輕。日長唯鳥雀，春遠獨柴荊。',48,'御定全唐詩/json/228.json','["肅肅花絮晚，菲菲紅素輕。日長唯鳥雀，春遠獨柴荊。", "數有關中亂，何曾劍外清。故鄉歸不得，地入亞夫營。"]'),
('yuding-13','暮寒','杜甫','唐','御定全唐诗','yuding','','[]','霧隱平郊樹，風含廣岸波。沉沉春色靜，慘慘暮寒多。',48,'御定全唐詩/json/228.json','["霧隱平郊樹，風含廣岸波。沉沉春色靜，慘慘暮寒多。", "戍鼓猶長擊，林鶯遂不歌。忽思高宴會，朱袖拂雲和。"]'),
('yuding-14','雙燕','杜甫','唐','御定全唐诗','yuding','','[]','旅食驚雙燕，銜泥入此堂。應同避燥濕，且複過炎涼。',48,'御定全唐詩/json/228.json','["旅食驚雙燕，銜泥入此堂。應同避燥濕，且複過炎涼。", "養子風塵際，來時道路長。今秋天地在，吾亦離殊方。"]'),
('yuding-15','百舌','杜甫','唐','御定全唐诗','yuding','','[]','百舌來何處，重重只報春。知音兼眾語，整翮豈多身。',48,'御定全唐詩/json/228.json','["百舌來何處，重重只報春。知音兼眾語，整翮豈多身。", "花密藏難見，枝高聽轉新。過時如發口，君側有讒人。"]'),
('yuding-16','地隅','杜甫','唐','御定全唐诗','yuding','','[]','江漢山重阻，風雲地一隅。年年非故物，處處是窮途。',48,'御定全唐詩/json/228.json','["江漢山重阻，風雲地一隅。年年非故物，處處是窮途。", "喪亂秦公子，悲涼楚大夫。平生心已折，行路日荒蕪。"]'),
('yuding-17','遊子','杜甫','唐','御定全唐诗','yuding','','[]','巴蜀愁誰語，吳門興杳然。九江春草外，三峽暮帆前。',48,'御定全唐詩/json/228.json','["巴蜀愁誰語，吳門興杳然。九江春草外，三峽暮帆前。", "厭就成都蔔，休為吏部眠。蓬萊如可到，衰白問群仙。"]'),
('yuding-18','歸夢','杜甫','唐','御定全唐诗','yuding','','[]','道路時通塞，江山日寂寥。偷生唯一老，伐叛已三朝。',48,'御定全唐詩/json/228.json','["道路時通塞，江山日寂寥。偷生唯一老，伐叛已三朝。", "雨急青楓暮，雲深黑水遙。夢歸歸未得，不用楚辭招。"]'),
('yuding-19','江亭王閬州筵餞蕭遂州','杜甫','唐','御定全唐诗','yuding','','[]','離亭非舊國，春色是他鄉。老畏歌聲斷，愁隨舞曲長。',48,'御定全唐詩/json/228.json','["離亭非舊國，春色是他鄉。老畏歌聲斷，愁隨舞曲長。", "二天開寵餞，五馬爛生光。川路風煙接，俱宜下鳳凰。"]'),
('yuding-20','絕句二首','杜甫','唐','御定全唐诗','yuding','','[]','遲日江山麗，春風花草香。泥融飛燕子，沙暖睡鴛鴦。',48,'御定全唐詩/json/228.json','["遲日江山麗，春風花草香。泥融飛燕子，沙暖睡鴛鴦。", "江碧鳥逾白，山青花欲燃。今春看又過，何日是歸年。"]'),
('yuding-21','滕王亭子','杜甫','唐','御定全唐诗','yuding','','[]','君王台榭枕巴山，萬丈丹梯尚可攀。春日鶯啼修竹裏，',40,'御定全唐詩/json/228.json','["君王台榭枕巴山，萬丈丹梯尚可攀。春日鶯啼修竹裏，", "人到於今歌出牧，來遊此地不知還。"]'),
('yuding-22','玉台觀','杜甫','唐','御定全唐诗','yuding','','[]','中天積翠玉台遙，上帝高居絳節朝。遂有馮夷來擊鼓，',40,'御定全唐詩/json/228.json','["中天積翠玉台遙，上帝高居絳節朝。遂有馮夷來擊鼓，", "更肯紅顏生羽翼，便應黃發老漁樵。"]'),
('yuding-23','滕王亭子','杜甫','唐','御定全唐诗','yuding','','[]','寂寞春山路，君王不復行。古牆猶竹色，虛閣自松聲。',48,'御定全唐詩/json/228.json','["寂寞春山路，君王不復行。古牆猶竹色，虛閣自松聲。", "鳥雀荒村暮，雲霞過客情。尚思歌吹入，千騎把霓旌。"]'),
('yuding-24','玉台觀','杜甫','唐','御定全唐诗','yuding','','[]','浩劫因王造，平臺訪古遊。彩雲蕭史駐，文字魯恭留。',48,'御定全唐詩/json/228.json','["浩劫因王造，平臺訪古遊。彩雲蕭史駐，文字魯恭留。", "宮闕通群帝，乾坤到十洲。人傳有笙鶴，時過此山頭。"]'),
('yuding-25','渡江','杜甫','唐','御定全唐诗','yuding','','[]','春江不可渡，二月已風濤。舟楫欹斜疾，魚龍偃臥高。',48,'御定全唐詩/json/228.json','["春江不可渡，二月已風濤。舟楫欹斜疾，魚龍偃臥高。", "渚花兼素錦，汀草亂青袍。戲問垂綸客，悠悠見汝曹。"]'),
('yuding-26','喜雨','杜甫','唐','御定全唐诗','yuding','','[]','南國旱無雨，今朝江出雲。入空才漠漠，灑迥已紛紛。',48,'御定全唐詩/json/228.json','["南國旱無雨，今朝江出雲。入空才漠漠，灑迥已紛紛。", "巢燕高飛盡，林花潤色分。晚來聲不絕，應得夜深聞。"]'),
('yuding-27','送韋郎司直歸成都','杜甫','唐','御定全唐诗','yuding','','[]','竄身來蜀地，同病得韋郎。天下干戈滿，江邊歲月長。',48,'御定全唐詩/json/228.json','["竄身來蜀地，同病得韋郎。天下干戈滿，江邊歲月長。", "別筵花欲暮，春日鬢俱蒼。為問南溪竹，抽梢合過牆。"]'),
('yuding-28','將赴成都草堂途中有作，先寄嚴鄭公五首','杜甫','唐','御定全唐诗','yuding','','[]','得歸茅屋赴成都，直為文翁再剖符。但使閭閻還揖讓，',200,'御定全唐詩/json/228.json','["得歸茅屋赴成都，直為文翁再剖符。但使閭閻還揖讓，", "五馬舊曾諳小徑，幾回書劄待潛夫。", "處處青江帶白蘋，故園猶得見殘春。雪山斥候無兵馬，", "習池未覺風流盡，況複荊州賞更新。", "竹寒沙碧浣花溪，菱刺藤梢咫尺迷。過客徑須愁出入，", "豈藉荒庭春草色，先判一飲醉如泥。", "常苦沙崩損藥欄，也從江檻落風湍。新松恨不高千尺，", "三年奔走空皮骨，信有人間行路難。", "錦官城西生事微，烏皮幾在還思歸。昔去為憂亂兵入，", "共說總戎雲鳥陣，不妨遊子芰荷衣。"]'),
('yuding-29','別房太尉墓','杜甫','唐','御定全唐诗','yuding','','[]','他鄉複行役，駐馬別孤墳。近淚無干土，低空有斷雲。',48,'御定全唐詩/json/228.json','["他鄉複行役，駐馬別孤墳。近淚無干土，低空有斷雲。", "對棋陪謝傅，把劍覓徐君。唯見林花落，鶯啼送客聞。"]'),
('yuding-30','自閬州領妻子卻赴蜀山行三首','杜甫','唐','御定全唐诗','yuding','','[]','汩汩避群盜，悠悠經十年。不成向南國，複作遊西川。',144,'御定全唐詩/json/228.json','["汩汩避群盜，悠悠經十年。不成向南國，複作遊西川。", "物役水虛照，魂傷山寂然。我生無倚著，盡室畏途邊。", "長林偃風色，回復意猶迷。衫裛翠微潤，馬銜青草嘶。", "棧懸斜避石，橋斷卻尋溪。何日干戈盡，飄飄愧老妻。", "行色遞隱見，人煙時有無。僕夫穿竹語，稚子入雲呼。", "轉石驚魑魅，抨弓落狖鼯。真供一笑樂，似欲慰窮途。"]'),
('yuding-31','山館','杜甫','唐','御定全唐诗','yuding','','[]','南國晝多霧，北風天正寒。路危行木杪，身遠宿雲端。',48,'御定全唐詩/json/228.json','["南國晝多霧，北風天正寒。路危行木杪，身遠宿雲端。", "山鬼吹燈滅，廚人語夜闌。雞鳴問前館，世亂敢求安。"]'),
('yuding-32','行次鹽亭縣聊題四韻奉簡嚴遂州蓬州兩使君諮議諸昆季','杜甫','唐','御定全唐诗','yuding','','[]','馬首見鹽亭，高山擁縣青。雲溪花淡淡，春郭水泠泠。',48,'御定全唐詩/json/228.json','["馬首見鹽亭，高山擁縣青。雲溪花淡淡，春郭水泠泠。", "全蜀多名士，嚴家聚德星。長歌意無極，好為老夫聽。"]'),
('yuding-33','倚杖','杜甫','唐','御定全唐诗','yuding','','[]','看花雖郭內，倚杖即溪邊。山縣早休市，江橋春聚船。',48,'御定全唐詩/json/228.json','["看花雖郭內，倚杖即溪邊。山縣早休市，江橋春聚船。", "狎鷗輕白浪，歸雁喜青天。物色兼生意，淒涼憶去年。"]'),
('yuding-34','陪王漢州留杜綿州泛房公西湖','杜甫','唐','御定全唐诗','yuding','','[]','舊相恩追後，春池賞不稀。闕庭分未到，舟楫有光輝。',48,'御定全唐詩/json/228.json','["舊相恩追後，春池賞不稀。闕庭分未到，舟楫有光輝。", "豉化蓴絲熟，刀鳴鱠縷飛。使君雙皂蓋，灘淺正相依。"]'),
('yuding-35','舟前小鵝兒','杜甫','唐','御定全唐诗','yuding','','[]','鵝兒黃似酒，對酒愛新鵝。引頸嗔船逼，無行亂眼多。',48,'御定全唐詩/json/228.json','["鵝兒黃似酒，對酒愛新鵝。引頸嗔船逼，無行亂眼多。", "翅開遭宿雨，力小困滄波。客散層城暮，狐狸奈若何。"]'),
('yuding-36','得房公池鵝','杜甫','唐','御定全唐诗','yuding','','[]','房相西亭鵝一群，眠沙泛浦白於雲。',32,'御定全唐詩/json/228.json','["房相西亭鵝一群，眠沙泛浦白於雲。", "鳳凰池上應回首，為報籠隨王右軍。"]'),
('yuding-37','答楊梓州','杜甫','唐','御定全唐诗','yuding','','[]','悶到房公池水頭，坐逢楊子鎮東州。',32,'御定全唐詩/json/228.json','["悶到房公池水頭，坐逢楊子鎮東州。", "卻向青溪不相見，回船應載阿戎遊。"]'),
('yuding-38','登樓','杜甫','唐','御定全唐诗','yuding','','[]','花近高樓傷客心，萬方多難此登臨。錦江春色來天地，',40,'御定全唐詩/json/228.json','["花近高樓傷客心，萬方多難此登臨。錦江春色來天地，", "可憐後主還祠廟，日暮聊為梁甫吟。"]'),
('yuding-39','春歸','杜甫','唐','御定全唐诗','yuding','','[]','苔徑臨江竹，茅簷覆地花。別來頻甲子，倏忽又春華。',72,'御定全唐詩/json/228.json','["苔徑臨江竹，茅簷覆地花。別來頻甲子，倏忽又春華。", "倚杖看孤石，傾壺就淺沙。遠鷗浮水靜，輕燕受風斜。", "世路雖多梗，吾生亦有涯。此身醒複醉，乘興即為家。"]'),
('yuding-40','歸雁','杜甫','唐','御定全唐诗','yuding','','[]','東來萬里客，亂定幾年歸。腸斷江城雁，高高正北飛。',24,'御定全唐詩/json/228.json','["東來萬里客，亂定幾年歸。腸斷江城雁，高高正北飛。"]'),
('yuding-41','贈王二十四侍禦契四十韻','杜甫','唐','御定全唐诗','yuding','','[]','往往雖相見，飄飄愧此身。不關輕紱冕，俱是避風塵。',480,'御定全唐詩/json/228.json','["往往雖相見，飄飄愧此身。不關輕紱冕，俱是避風塵。", "一別星橋夜，三移斗柄春。敗亡非赤壁，奔走為黃巾。", "子去何瀟灑，余藏異隱淪。書成無過雁，衣故有懸鶉。", "恐懼行裝數，伶俜臥疾頻。曉鶯工迸淚，秋月解傷神。", "會面嗟黧黑，含淒話苦辛。接輿還入楚，王粲不歸秦。", "錦裏殘丹灶，花溪得釣綸。消中只自惜，晚起索誰親。", "伏柱聞周史，乘槎有漢臣。鴛鴻不易狎，龍虎未宜馴。", "客則掛冠至，交非傾蓋新。由來意氣合，直取性情真。", "浪跡同生死，無心恥賤貧。偶然存蔗芋，幸各對松筠。", "粗飯依他日，窮愁怪此辰。女長裁褐穩，男大卷書勻。", "漰口江如練，蠶崖雪似銀。名園當翠巘，野棹沒青蘋。", "屢喜王侯宅，時邀江海人。追隨不覺晚，款曲動彌旬。", "但使芝蘭秀，何煩棟宇鄰。山陽無俗物，鄭驛正留賓。", "出入並鞍馬，光輝參席珍。重遊先主廟，更曆少城闉。", "石鏡通幽魄，琴台隱絳唇。送終惟糞土，結愛獨荊榛。", "置酒高林下，觀棋積水濱。區區甘累趼，稍稍息勞筋。", "網聚粘圓鯽，絲繁煮細蓴。長歌敲柳癭，小睡憑藤輪。", "農月須知課，田家敢忘勤。浮生難去食，良會惜清晨。", "列國兵戈暗，今王德教淳。要聞除猰貐，休作畫麒麟。", "洗眼看輕薄，虛懷任屈伸。莫令膠漆地，萬古重雷陳。"]'),
('yuding-42','寄董卿嘉榮十韻','杜甫','唐','御定全唐诗','yuding','','[]','聞道君牙帳，防秋近赤霄。下臨千雪嶺，卻背五繩橋。',120,'御定全唐詩/json/228.json','["聞道君牙帳，防秋近赤霄。下臨千雪嶺，卻背五繩橋。", "海內久戎服，京師今晏朝。犬羊曾爛熳，宮闕尚蕭條。", "猛將宜嘗膽，龍泉必在腰。黃圖遭污辱，月窟可焚燒。", "會取干戈利，無令斥候驕。居然雙捕虜，自是一嫖姚。", "落日思輕騎，高天憶射雕。雲台畫形像，皆為掃氛妖。"]'),
('yuding-43','寄司馬山人十二韻','杜甫','唐','御定全唐诗','yuding','','[]','關內昔分袂，天邊今轉蓬。驅馳不可說，談笑偶然同。',144,'御定全唐詩/json/228.json','["關內昔分袂，天邊今轉蓬。驅馳不可說，談笑偶然同。", "道術曾留意，先生早擊蒙。家家迎薊子，處處識壺公。", "長嘯峨嵋北，潛行玉壘東。有時騎猛虎，虛室使仙童。", "發少何勞白，顏衰肯更紅。望雲悲轗軻，畢景羨沖融。", "喪亂形仍役，淒涼信不通。懸旌要路口，倚劍短亭中。", "永作殊方客，殘生一老翁。相哀骨可換，亦遣馭清風。"]'),
('yuding-44','黃河二首','杜甫','唐','御定全唐诗','yuding','','[]','黃河北岸海西軍，椎鼓鳴鐘天下聞。',64,'御定全唐詩/json/228.json','["黃河北岸海西軍，椎鼓鳴鐘天下聞。", "鐵馬長鳴不知數，胡人高鼻動成群。", "黃河西岸是吾蜀，欲須供給家無粟。", "願驅眾庶戴君王，混一車書棄金玉。"]'),
('yuding-45','寄李十四員外布十二韻','杜甫','唐','御定全唐诗','yuding','','[]','名參漢望苑，職述景題輿。巫峽將之郡，荊門好附書。',144,'御定全唐詩/json/228.json','["名參漢望苑，職述景題輿。巫峽將之郡，荊門好附書。", "遠行無自苦，內熱比何如。正是炎天闊，那堪野館疏。", "黃牛平駕浪，畫鷁上淩虛。試待盤渦歇，方期解纜初。", "悶能過小徑，自為摘嘉蔬。渚柳元幽僻，村花不掃除。", "宿陰繁素柰，過雨亂紅蕖。寂寂夏先晚，泠泠風有餘。", "江清心可瑩，竹冷發堪梳。直作移巾幾，秋帆發弊廬。"]'),
('yuding-46','歸來','杜甫','唐','御定全唐诗','yuding','','[]','客裏有所過，歸來知路難。開門野鼠走，散帙壁魚幹。',48,'御定全唐詩/json/228.json','["客裏有所過，歸來知路難。開門野鼠走，散帙壁魚幹。", "洗杓開新醞，低頭拭小盤。憑誰給麹蘖，細酌老江幹。"]'),
('yuding-47','王錄事許修草堂貲不到，聊小詰','杜甫','唐','御定全唐诗','yuding','','[]','為嗔王錄事，不寄草堂貲。昨屬愁春雨，能忘欲漏時。',24,'御定全唐詩/json/228.json','["為嗔王錄事，不寄草堂貲。昨屬愁春雨，能忘欲漏時。"]'),
('yuding-48','寄邛州崔錄事','杜甫','唐','御定全唐诗','yuding','','[]','邛州崔錄事，聞在果園坊。久待無消息，終朝有底忙。',48,'御定全唐詩/json/228.json','["邛州崔錄事，聞在果園坊。久待無消息，終朝有底忙。", "應愁江樹遠，怯見野亭荒。浩蕩風塵外，誰知酒熟香。"]'),
('yuding-49','過故斛斯校書莊二首','杜甫','唐','御定全唐诗','yuding','','[]','此老已雲歿，鄰人嗟亦休。竟無宣室召，徒有茂陵求。',96,'御定全唐詩/json/228.json','["此老已雲歿，鄰人嗟亦休。竟無宣室召，徒有茂陵求。", "妻子寄他食，園林非昔遊。空餘繐帷在，淅淅野風秋。", "燕入非旁舍，鷗歸只故池。斷橋無複板，臥柳自生枝。", "遂有山陽作，多慚鮑叔知。素交零落盡，白首淚雙垂。"]'),
('yuding-50','立秋雨院中有作','杜甫','唐','御定全唐诗','yuding','','[]','山雲行絕塞，大火複西流。飛雨動華屋，蕭蕭梁棟秋。',96,'御定全唐詩/json/228.json','["山雲行絕塞，大火複西流。飛雨動華屋，蕭蕭梁棟秋。", "窮途愧知己，暮齒借前籌。已費清晨謁，那成長者謀。", "解衣開北戶，高枕對南樓。樹濕風涼進，江喧水氣浮。", "禮寬心有適，節爽病微瘳。主將歸調鼎，吾還訪舊丘。"]'),
('yuding-51','奉和嚴大夫軍城早秋','杜甫','唐','御定全唐诗','yuding','','[]','秋風褭褭動高旌，玉帳分弓射虜營。',32,'御定全唐詩/json/228.json','["秋風褭褭動高旌，玉帳分弓射虜營。", "已收滴博雲間戍，更奪蓬婆雪外城。"]'),
('yuding-52','院中晚晴懷西郭茅舍','杜甫','唐','御定全唐诗','yuding','','[]','幕府秋風日夜清，澹雲疏雨過高城。葉心朱實看時落，',40,'御定全唐詩/json/228.json','["幕府秋風日夜清，澹雲疏雨過高城。葉心朱實看時落，", "浣花溪裏花饒笑，肯信吾兼吏隱名。"]'),
('yuding-53','到村','杜甫','唐','御定全唐诗','yuding','','[]','碧澗雖多雨，秋沙先少泥。蛟龍引子過，荷芰逐花低。',72,'御定全唐詩/json/228.json','["碧澗雖多雨，秋沙先少泥。蛟龍引子過，荷芰逐花低。", "老去參戎幕，歸來散馬蹄。稻粱須就列，榛草即相迷。", "蓄積思江漢，疏頑惑町畦。稍酬知己分，還入故林棲。"]'),
('yuding-54','宿府','杜甫','唐','御定全唐诗','yuding','','[]','清秋幕府井梧寒，獨宿江城蠟炬殘。永夜角聲悲自語，',40,'御定全唐詩/json/228.json','["清秋幕府井梧寒，獨宿江城蠟炬殘。永夜角聲悲自語，", "已忍伶俜十年事，強移棲息一枝安。"]'),
('yuding-55','遣悶奉呈嚴公二十韻','杜甫','唐','御定全唐诗','yuding','','[]','白水魚竿客，清秋鶴發翁。胡為來幕下，只合在舟中。',240,'御定全唐詩/json/228.json','["白水魚竿客，清秋鶴發翁。胡為來幕下，只合在舟中。", "黃卷真如律，青袍也自公。老妻憂坐痹，幼女問頭風。", "平地專欹倒，分曹失異同。禮甘衰力就，義忝上官通。", "疇昔論詩早，光輝仗鉞雄。寬容存性拙，剪拂念途窮。", "露裛思藤架，煙霏想桂叢。信然龜觸網，直作鳥窺籠。", "西嶺紆村北，南江繞舍東。竹皮寒舊翠，椒實雨新紅。", "浪簸船應坼，杯幹甕即空。藩籬生野徑，斤斧任樵童。", "束縛酬知己，蹉跎效小忠。周防期稍稍，太簡遂匆匆。", "曉入朱扉啟，昏歸畫角終。不成尋別業，未敢息微躬。", "烏鵲愁銀漢，駑駘怕錦幪。會希全物色，時放倚梧桐。"]'),
('yuding-56','送舍弟頻赴齊州三首','杜甫','唐','御定全唐诗','yuding','','[]','岷嶺南蠻北，徐關東海西。此行何日到，送汝萬行啼。',144,'御定全唐詩/json/228.json','["岷嶺南蠻北，徐關東海西。此行何日到，送汝萬行啼。", "絕域惟高枕，清風獨杖藜。危時暫相見，衰白意都迷。", "風塵暗不開，汝去幾時來。兄弟分離苦，形容老病催。", "江通一柱觀，日落望鄉台。客意長東北，齊州安在哉。", "諸姑今海畔，兩弟亦山東。去傍干戈覓，來看道路通。", "短衣防戰地，匹馬逐秋風。莫作俱流落，長瞻碣石鴻。"]'),
('yuding-57','嚴鄭公階下新松','杜甫','唐','御定全唐诗','yuding','','[]','弱質豈自負，移根方爾瞻。細聲聞玉帳，疏翠近珠簾。',48,'御定全唐詩/json/228.json','["弱質豈自負，移根方爾瞻。細聲聞玉帳，疏翠近珠簾。", "未見紫煙集，虛蒙清露沾。何當一百丈，欹蓋擁高簷。"]'),
('yuding-58','嚴鄭公宅同詠竹','杜甫','唐','御定全唐诗','yuding','','[]','綠竹半含籜，新梢才出牆。色侵書帙晚，陰過酒樽涼。',48,'御定全唐詩/json/228.json','["綠竹半含籜，新梢才出牆。色侵書帙晚，陰過酒樽涼。", "雨洗娟娟淨，風吹細細香。但令無剪伐，會見拂雲長。"]'),
('yuding-59','奉觀嚴鄭公廳事岷山沱江畫圖十韻','杜甫','唐','御定全唐诗','yuding','','[]','沱水流中座，岷山到此堂。白波吹粉壁，青嶂插雕梁。',120,'御定全唐詩/json/228.json','["沱水流中座，岷山到此堂。白波吹粉壁，青嶂插雕梁。", "直訝杉松冷，兼疑菱荇香。雪雲虛點綴，沙草得微茫。", "嶺雁隨毫末，川蜺飲練光。霏紅洲蕊亂，拂黛石蘿長。", "暗谷非關雨，丹楓不為霜。秋成玄圃外，景物洞庭旁。", "繪事功殊絕，幽襟興激昂。從來謝太傅，丘壑道難忘。"]'),
('yuding-60','晚秋陪嚴鄭公摩訶池泛舟','杜甫','唐','御定全唐诗','yuding','','[]','湍駛風醒酒，船回霧起堤。高城秋自落，雜樹晚相迷。',48,'御定全唐詩/json/228.json','["湍駛風醒酒，船回霧起堤。高城秋自落，雜樹晚相迷。", "坐觸鴛鴦起，巢傾翡翠低。莫須驚白鷺，為伴宿清溪。"]'),
('yuding-61','初冬','杜甫','唐','御定全唐诗','yuding','','[]','垂老戎衣窄，歸休寒色深。漁舟上急水，獵火著高林。',48,'御定全唐詩/json/228.json','["垂老戎衣窄，歸休寒色深。漁舟上急水，獵火著高林。", "日有習池醉，愁來梁甫吟。干戈未偃息，出處遂何心。"]'),
('yuding-62','至後','杜甫','唐','御定全唐诗','yuding','','[]','冬至至後日初長，遠在劍南思洛陽。青袍白馬有何意，',40,'御定全唐詩/json/228.json','["冬至至後日初長，遠在劍南思洛陽。青袍白馬有何意，", "愁極本憑詩遣興，詩成吟詠轉淒涼。"]'),
('yuding-63','正月三日歸溪上有作，簡院內諸公','杜甫','唐','御定全唐诗','yuding','','[]','野外堂依竹，籬邊水向城。蟻浮仍臘味，鷗泛已春聲。',48,'御定全唐詩/json/228.json','["野外堂依竹，籬邊水向城。蟻浮仍臘味，鷗泛已春聲。", "藥許鄰人劚，書從稚子擎。白頭趨幕府，深覺負平生。"]'),
('yuding-64','弊廬遣興，奉寄嚴公','杜甫','唐','御定全唐诗','yuding','','[]','野水準橋路，春沙映竹村。風輕粉蝶喜，花暖蜜蜂喧。',72,'御定全唐詩/json/228.json','["野水準橋路，春沙映竹村。風輕粉蝶喜，花暖蜜蜂喧。", "把酒宜深酌，題詩好細論。府中瞻暇日，江上憶詞源。", "跡忝朝廷舊，情依節制尊。還思長者轍，恐避席為門。"]'),
('yuding-65','春日江村五首','杜甫','唐','御定全唐诗','yuding','','[]','農務村村急，春流岸岸深。乾坤萬里眼，時序百年心。',240,'御定全唐詩/json/228.json','["農務村村急，春流岸岸深。乾坤萬里眼，時序百年心。", "茅屋還堪賦，桃源自可尋。艱難賤生理，飄泊到如今。", "迢遞來三蜀，蹉跎有六年。客身逢故舊，發興自林泉。", "過懶從衣結，頻游任履穿。藩籬無限景，恣意買江天。", "種竹交加翠，栽桃爛熳紅。經心石鏡月，到面雪山風。", "赤管隨王命，銀章付老翁。豈知牙齒落，名玷薦賢中。", "扶病垂朱紱，歸休步紫苔。郊扉存晚計，幕府愧群材。", "燕外晴絲卷，鷗邊水葉開。鄰家送魚鱉，問我數能來。", "群盜哀王粲，中年召賈生。登樓初有作，前席竟為榮。", "宅入先賢傳，才高處士名。異時懷二子，春日複含情。"]'),
('yuding-66','絕句六首','杜甫','唐','御定全唐诗','yuding','','[]','日出籬東水，雲生舍北泥。竹高鳴翡翠，沙僻舞鶤雞。',144,'御定全唐詩/json/228.json','["日出籬東水，雲生舍北泥。竹高鳴翡翠，沙僻舞鶤雞。", "藹藹花蕊亂，飛飛蜂蝶多。幽棲身懶動，客至欲如何。", "鑿井交棕葉，開渠斷竹根。扁舟輕褭纜，小徑曲通村。", "急雨捎溪足，斜暉轉樹腰。隔巢黃鳥並，翻藻白魚跳。", "捨下筍穿壁，庭中藤刺簷。地晴絲冉冉，江白草纖纖。", "江動月移石，溪虛雲傍花。鳥棲知故道，帆過宿誰家。"]'),
('yuding-67','絕句四首','杜甫','唐','御定全唐诗','yuding','','[]','堂西長筍別開門，塹北行椒卻背村。',128,'御定全唐詩/json/228.json','["堂西長筍別開門，塹北行椒卻背村。", "梅熟許同朱老吃，松高擬對阮生論。", "欲作魚梁雲複湍，因驚四月雨聲寒。", "青溪先有蛟龍窟，竹石如山不敢安。", "兩個黃鸝鳴翠柳，一行白鷺上青天。", "窗含西嶺千秋雪，門泊東吳萬里船。", "藥條藥甲潤青青，色過棕亭入草亭。", "苗滿空山慚取譽，根居隙地怯成形。"]'),
('yuding-0','哭嚴僕射歸櫬','杜甫','唐','御定全唐诗','yuding','','[]','素幔隨流水，歸舟返舊京。老親如宿昔，部曲異平生。',48,'御定全唐詩/json/229.json','["素幔隨流水，歸舟返舊京。老親如宿昔，部曲異平生。", "風送蛟龍雨，天長驃騎營。一哀三峽暮，遺後見君情。"]'),
('yuding-1','宴戎州楊使君東樓','杜甫','唐','御定全唐诗','yuding','','[]','勝絕驚身老，情忘發興奇。座從歌妓密，樂任主人為。',48,'御定全唐詩/json/229.json','["勝絕驚身老，情忘發興奇。座從歌妓密，樂任主人為。", "重碧拈春酒，輕紅擘荔枝。樓高欲愁思，橫笛未休吹。"]'),
('yuding-2','渝州候嚴六侍禦不到，先下峽','杜甫','唐','御定全唐诗','yuding','','[]','聞道乘驄發，沙邊待至今。不知雲雨散，虛費短長吟。',48,'御定全唐詩/json/229.json','["聞道乘驄發，沙邊待至今。不知雲雨散，虛費短長吟。", "山帶烏蠻闊，江連白帝深。船經一柱觀，留眼共登臨。"]'),
('yuding-3','撥悶','杜甫','唐','御定全唐诗','yuding','','[]','聞道雲安麹米春，才傾一盞即醺人。乘舟取醉非難事，',40,'御定全唐詩/json/229.json','["聞道雲安麹米春，才傾一盞即醺人。乘舟取醉非難事，", "已辦青錢防雇直，當令美味入吾唇。"]'),
('yuding-4','聞高常侍亡','杜甫','唐','御定全唐诗','yuding','','[]','歸朝不相見，蜀使忽傳亡。虛曆金華省，何殊地下郎。',48,'御定全唐詩/json/229.json','["歸朝不相見，蜀使忽傳亡。虛曆金華省，何殊地下郎。", "致君丹檻折，哭友白雲長。獨步詩名在，只令故舊傷。"]'),
('yuding-5','宴忠州使君侄宅','杜甫','唐','御定全唐诗','yuding','','[]','出守吾家侄，殊方此日歡。自須游阮巷，不是怕湖灘。',48,'御定全唐詩/json/229.json','["出守吾家侄，殊方此日歡。自須游阮巷，不是怕湖灘。", "樂助長歌逸，杯饒旅思寬。昔曾如意舞，牽率強為看。"]'),
('yuding-6','禹廟','杜甫','唐','御定全唐诗','yuding','','[]','禹廟空山裏，秋風落日斜。荒庭垂橘柚，古屋畫龍蛇。',48,'御定全唐詩/json/229.json','["禹廟空山裏，秋風落日斜。荒庭垂橘柚，古屋畫龍蛇。", "雲氣生虛壁，江聲走白沙。早知乘四載，疏鑿控三巴。"]'),
('yuding-7','題忠州龍興寺所居院壁','杜甫','唐','御定全唐诗','yuding','','[]','忠州三峽內，井邑聚雲根。小市常爭米，孤城早閉門。',48,'御定全唐詩/json/229.json','["忠州三峽內，井邑聚雲根。小市常爭米，孤城早閉門。", "空看過客淚，莫覓主人恩。淹泊仍愁虎，深居賴獨園。"]'),
('yuding-8','旅夜書懷','杜甫','唐','御定全唐诗','yuding','','[]','細草微風岸，危檣獨夜舟。星垂平野闊，月湧大江流。',48,'御定全唐詩/json/229.json','["細草微風岸，危檣獨夜舟。星垂平野闊，月湧大江流。", "名豈文章著，官因老病休。飄飄何所似，天地一沙鷗。"]'),
('yuding-9','別常征君','杜甫','唐','御定全唐诗','yuding','','[]','兒扶猶杖策，臥病一秋強。白髮少新洗，寒衣寬總長。',48,'御定全唐詩/json/229.json','["兒扶猶杖策，臥病一秋強。白髮少新洗，寒衣寬總長。", "故人憂見及，此別淚相忘。各逐萍流轉，來書細作行。"]'),
('yuding-10','三絕句','杜甫','唐','御定全唐诗','yuding','','[]','前年渝州殺刺史，今年開州殺刺史。',96,'御定全唐詩/json/229.json','["前年渝州殺刺史，今年開州殺刺史。", "群盜相隨劇虎狼，食人更肯留妻子。", "二十一家同入蜀，惟殘一人出駱穀。", "自說二女齧臂時，回頭卻向秦雲哭。", "殿前兵馬雖驍雄，縱暴略與羌渾同。", "聞道殺人漢水上，婦女多在官軍中。"]'),
('yuding-11','十二月一日三首','杜甫','唐','御定全唐诗','yuding','','[]','今朝臘月春意動，雲安縣前江可憐。一聲何處送書雁，',120,'御定全唐詩/json/229.json','["今朝臘月春意動，雲安縣前江可憐。一聲何處送書雁，", "明光起草人所羨，肺病幾時朝日邊。", "寒輕市上山煙碧，日滿樓前江霧黃。負鹽出井此溪女，", "春花不愁不爛漫，楚客唯聽棹相將。", "即看燕子入山扉，豈有黃鸝曆翠微。短短桃花臨水岸，", "他日一杯難強進，重嗟筋力故山違。"]'),
('yuding-12','又雪','杜甫','唐','御定全唐诗','yuding','','[]','南雪不到地，青崖沾未消。微微向日薄，脈脈去人遙。',48,'御定全唐詩/json/229.json','["南雪不到地，青崖沾未消。微微向日薄，脈脈去人遙。", "冬熱鴛鴦病，峽深豺虎驕。愁邊有江水，焉得北之朝。"]'),
('yuding-13','奉漢中王手劄','杜甫','唐','御定全唐诗','yuding','','[]','國有乾坤大，王今叔父尊。剖符來蜀道，歸蓋取荊門。',168,'御定全唐詩/json/229.json','["國有乾坤大，王今叔父尊。剖符來蜀道，歸蓋取荊門。", "峽險通舟過，水長注海奔。主人留上客，避暑得名園。", "前後緘書報，分明饌玉恩。天雲浮絕壁，風竹在華軒。", "已覺良宵永，何看駭浪翻。入期朱邸雪，朝傍紫微垣。", "枚乘文章老，河間禮樂存。悲秋宋玉宅，失路武陵源。", "淹薄俱崖口，東西異石根。夷音迷咫尺，鬼物傍黃昏。", "犬馬誠為戀，狐狸不足論。從容草奏罷，宿昔奉清樽。"]'),
('yuding-14','贈崔十三評事公輔','杜甫','唐','御定全唐诗','yuding','','[]','飄飄西極馬，來自渥窪池。颯飁定山桂，低徊風雨枝。',240,'御定全唐詩/json/229.json','["飄飄西極馬，來自渥窪池。颯飁定山桂，低徊風雨枝。", "我聞龍正直，道屈爾何為。且有元戎命，悲歌識者誰。", "官聯辭冗長，行路洗欹危。脫劍主人贈，去帆春色隨。", "陰沉鐵鳳闕，教練羽林兒。天子朝侵早，雲台仗數移。", "分軍應供給，百姓日支離。黠吏因封己，公才或守雌。", "燕王買駿骨，渭老得熊羆。活國名公在，拜壇群寇疑。", "冰壺動瑤碧，野水失蛟螭。入幕諸彥集，渴賢高選宜。", "騫騰坐可致，九萬起於斯。複進出矛戟，昭然開鼎彝。", "會看之子貴，歎及老夫衰。豈但江曾決，還思霧一披。", "暗塵生古鏡，拂匣照西施。舅氏多人物，無慚困翮垂。"]'),
('yuding-15','長江二首','杜甫','唐','御定全唐诗','yuding','','[]','眾水會涪萬，瞿塘爭一門。朝宗人共挹，盜賊爾誰尊。',96,'御定全唐詩/json/229.json','["眾水會涪萬，瞿塘爭一門。朝宗人共挹，盜賊爾誰尊。", "孤石隱如馬，高蘿垂飲猿。歸心異波浪，何事即飛翻。", "浩浩終不息，乃知東極臨。眾流歸海意，萬國奉君心。", "色借瀟湘闊，聲驅灩澦深。未辭添霧雨，接上遇衣襟。"]'),
('yuding-16','承聞故房相公靈櫬自閬州啟殯歸葬東都有作二首','杜甫','唐','御定全唐诗','yuding','','[]','遠聞房太守，歸葬陸渾山。一德興王后，孤魂久客間。',96,'御定全唐詩/json/229.json','["遠聞房太守，歸葬陸渾山。一德興王后，孤魂久客間。", "孔明多故事，安石竟崇班。他日嘉陵涕，仍沾楚水還。", "丹旐飛飛日，初傳發閬州。風塵終不解，江漢忽同流。", "劍動新身匣，書歸故國樓。盡哀知有處，為客恐長休。"]'),
('yuding-17','雲安九日，鄭十八攜酒陪諸公宴','杜甫','唐','御定全唐诗','yuding','','[]','寒花開已盡，菊蕊獨盈枝。舊摘人頻異，輕香酒暫隨。',48,'御定全唐詩/json/229.json','["寒花開已盡，菊蕊獨盈枝。舊摘人頻異，輕香酒暫隨。", "地偏初衣夾，山擁更登危。萬國皆戎馬，酣歌淚欲垂。"]'),
('yuding-18','答鄭十七郎一絕','杜甫','唐','御定全唐诗','yuding','','[]','雨後過畦潤，花殘步屐遲。把文驚小陸，好客見當時。',24,'御定全唐詩/json/229.json','["雨後過畦潤，花殘步屐遲。把文驚小陸，好客見當時。"]'),
('yuding-19','將曉二首','杜甫','唐','御定全唐诗','yuding','','[]','石城除擊柝，鐵鎖欲開關。鼓角悲荒塞，星河落曙山。',96,'御定全唐詩/json/229.json','["石城除擊柝，鐵鎖欲開關。鼓角悲荒塞，星河落曙山。", "巴人常小梗，蜀使動無還。垂老孤帆色，飄飄犯百蠻。", "軍吏回官燭，舟人自楚歌。寒沙蒙薄霧，落月去清波。", "壯惜身名晚，衰慚應接多。歸朝日簪笏，筋力定如何。"]'),
('yuding-20','懷錦水居止二首','杜甫','唐','御定全唐诗','yuding','','[]','軍旅西征僻，風塵戰伐多。猶聞蜀父老，不忘舜謳歌。',96,'御定全唐詩/json/229.json','["軍旅西征僻，風塵戰伐多。猶聞蜀父老，不忘舜謳歌。", "天險終難立，柴門豈重過。朝朝巫峽水，遠逗錦江波。", "萬里橋南宅，百花潭北莊。層軒皆面水，老樹飽經霜。", "雪嶺界天白，錦城曛日黃。惜哉形勝地，回首一茫茫。"]'),
('yuding-21','子規','杜甫','唐','御定全唐诗','yuding','','[]','峽裏雲安縣，江樓翼瓦齊。兩邊山木合，終日子規啼。',48,'御定全唐詩/json/229.json','["峽裏雲安縣，江樓翼瓦齊。兩邊山木合，終日子規啼。", "眇眇春風見，蕭蕭夜色淒。客愁那聽此，故作傍人低。"]'),
('yuding-22','立春','杜甫','唐','御定全唐诗','yuding','','[]','春日春盤細生菜，忽憶兩京梅發時。盤出高門行白玉，',40,'御定全唐詩/json/229.json','["春日春盤細生菜，忽憶兩京梅發時。盤出高門行白玉，", "此身未知歸定處，呼兒覓紙一題詩。"]'),
('yuding-23','漫成一絕','杜甫','唐','御定全唐诗','yuding','','[]','江月去人只數尺，風燈照夜欲三更。',32,'御定全唐詩/json/229.json','["江月去人只數尺，風燈照夜欲三更。", "沙頭宿鷺聯拳靜，船尾跳魚撥剌鳴。"]'),
('yuding-24','老病','杜甫','唐','御定全唐诗','yuding','','[]','老病巫山裏，稽留楚客中。藥殘他日裹，花發去年叢。',48,'御定全唐詩/json/229.json','["老病巫山裏，稽留楚客中。藥殘他日裹，花發去年叢。", "夜足沾沙雨，春多逆水風。合分雙賜筆，猶作一飄蓬。"]'),
('yuding-25','南楚','杜甫','唐','御定全唐诗','yuding','','[]','南楚青春異，暄寒早早分。無名江上草，隨意嶺頭雲。',48,'御定全唐詩/json/229.json','["南楚青春異，暄寒早早分。無名江上草，隨意嶺頭雲。", "正月蜂相見，非時鳥共聞。杖藜妨躍馬，不是故離群。"]'),
('yuding-26','寄常征君','杜甫','唐','御定全唐诗','yuding','','[]','白水青山空複春，征君晚節傍風塵。楚妃堂上色殊眾，',40,'御定全唐詩/json/229.json','["白水青山空複春，征君晚節傍風塵。楚妃堂上色殊眾，", "開州入夏知涼冷，不似雲安毒熱新。"]'),
('yuding-27','寄岑嘉州','杜甫','唐','御定全唐诗','yuding','','[]','不見故人十年餘，不道故人無素書。願逢顏色關塞遠，',48,'御定全唐詩/json/229.json','["不見故人十年餘，不道故人無素書。願逢顏色關塞遠，", "謝脁每篇堪諷誦，馮唐已老聽吹噓。泊船秋夜經春草，"]'),
('yuding-28','移居夔州郭','杜甫','唐','御定全唐诗','yuding','','[]','伏枕雲安縣，遷居白帝城。春知催柳別，江與放船清。',48,'御定全唐詩/json/229.json','["伏枕雲安縣，遷居白帝城。春知催柳別，江與放船清。", "農事聞人說，山光見鳥情。禹功饒斷石，且就土微平。"]'),
('yuding-29','船下夔州郭宿，雨濕不得上岸，別王十二判官','杜甫','唐','御定全唐诗','yuding','','[]','依沙宿舸船，石瀨月娟娟。風起春燈亂，江鳴夜雨懸。',48,'御定全唐詩/json/229.json','["依沙宿舸船，石瀨月娟娟。風起春燈亂，江鳴夜雨懸。", "晨鐘雲外濕，勝地石堂煙。柔櫓輕鷗外，含淒覺汝賢。"]'),
('yuding-30','雨不絕','杜甫','唐','御定全唐诗','yuding','','[]','鳴雨既過漸細微，映空搖颺如絲飛。階前短草泥不亂，',40,'御定全唐詩/json/229.json','["鳴雨既過漸細微，映空搖颺如絲飛。階前短草泥不亂，", "眼邊江舸何匆促，未待安流逆浪歸。"]'),
('yuding-31','崔評事弟許相迎不到應慮老夫見泥雨怯出必愆佳期走筆戲簡','杜甫','唐','御定全唐诗','yuding','','[]','江閣要賓許馬迎，午時起坐自天明。浮雲不負青春色，',40,'御定全唐詩/json/229.json','["江閣要賓許馬迎，午時起坐自天明。浮雲不負青春色，", "虛疑皓首沖泥怯，實少銀鞍傍險行。"]'),
('yuding-32','宿江邊閣','杜甫','唐','御定全唐诗','yuding','','[]','暝色延山徑，高齋次水門。薄雲岩際宿，孤月浪中翻。',48,'御定全唐詩/json/229.json','["暝色延山徑，高齋次水門。薄雲岩際宿，孤月浪中翻。", "鸛鶴追飛靜，豺狼得食喧。不眠憂戰伐，無力正乾坤。"]'),
('yuding-33','夜宿西閣，曉呈元二十一曹長','杜甫','唐','御定全唐诗','yuding','','[]','城暗更籌急，樓高雨雪微。稍通綃幕霽，遠帶玉繩稀。',48,'御定全唐詩/json/229.json','["城暗更籌急，樓高雨雪微。稍通綃幕霽，遠帶玉繩稀。", "門鵲晨光起，牆烏宿處飛。寒江流甚細，有意待人歸。"]'),
('yuding-34','西閣口號','杜甫','唐','御定全唐诗','yuding','','[]','山木抱雲稠，寒江繞上頭。雪崖才變石，風幔不依樓。',48,'御定全唐詩/json/229.json','["山木抱雲稠，寒江繞上頭。雪崖才變石，風幔不依樓。", "社稷堪流涕，安危在運籌。看君話王室，感動幾銷憂。"]'),
('yuding-35','西閣雨望','杜甫','唐','御定全唐诗','yuding','','[]','樓雨沾雲幔，山寒著水城。徑添沙面出，湍減石棱生。',48,'御定全唐詩/json/229.json','["樓雨沾雲幔，山寒著水城。徑添沙面出，湍減石棱生。", "菊蕊淒疏放，松林駐遠情。滂沱朱檻濕，萬慮傍簷楹。"]'),
('yuding-36','不離西閣二首','杜甫','唐','御定全唐诗','yuding','','[]','江柳非時發，江花冷色頻。地偏應有瘴，臘近已含春。',96,'御定全唐詩/json/229.json','["江柳非時發，江花冷色頻。地偏應有瘴，臘近已含春。", "失學從愚子，無家住老身。不知西閣意，肯別定留人。", "西閣從人別，人今亦故亭。江雲飄素練，石壁斷空青。", "滄海先迎日，銀河倒列星。平生耽勝事，籲駭始初經。"]'),
('yuding-37','西閣三度期大昌嚴明府同宿不到','杜甫','唐','御定全唐诗','yuding','','[]','問子能來宿，今疑索故要。匣琴虛夜夜，手板自朝朝。',48,'御定全唐詩/json/229.json','["問子能來宿，今疑索故要。匣琴虛夜夜，手板自朝朝。", "金吼霜鐘徹，花催臘炬銷。早鳧江檻底，雙影漫飄颻。"]'),
('yuding-38','西閣二首','杜甫','唐','御定全唐诗','yuding','','[]','巫山小搖落，碧色見松林。百鳥各相命，孤雲無自心。',144,'御定全唐詩/json/229.json','["巫山小搖落，碧色見松林。百鳥各相命，孤雲無自心。", "層軒俯江壁，要路亦高深。朱紱猶紗帽，新詩近玉琴。", "功名不早立，衰病謝知音。哀世非王粲，終然學越吟。", "懶心似江水，日夜向滄洲。不道含香賤，其如鑷白休。", "經過調碧柳，蕭索倚朱樓。畢娶何時竟，消中得自由。", "豪華看古往，服食寄冥搜。詩盡人間興，兼須入海求。"]'),
('yuding-39','閣夜','杜甫','唐','御定全唐诗','yuding','','[]','歲暮陰陽催短景，天涯霜雪霽寒宵。五更鼓角聲悲壯，',40,'御定全唐詩/json/229.json','["歲暮陰陽催短景，天涯霜雪霽寒宵。五更鼓角聲悲壯，", "臥龍躍馬終黃土，人事依依漫寂寥。"]'),
('yuding-40','西閣夜','杜甫','唐','御定全唐诗','yuding','','[]','恍惚寒山暮，逶迤白霧昏。山虛風落石，樓靜月侵門。',48,'御定全唐詩/json/229.json','["恍惚寒山暮，逶迤白霧昏。山虛風落石，樓靜月侵門。", "擊柝可憐子，無衣何處村。時危關百慮，盜賊爾猶存。"]'),
('yuding-41','瀼西寒望','杜甫','唐','御定全唐诗','yuding','','[]','水色含群動，朝光切太虛。年侵頻悵望，興遠一蕭疏。',48,'御定全唐詩/json/229.json','["水色含群動，朝光切太虛。年侵頻悵望，興遠一蕭疏。", "猿掛時相學，鷗行炯自如。瞿唐春欲至，定卜瀼西居。"]'),
('yuding-42','入宅三首','杜甫','唐','御定全唐诗','yuding','','[]','奔峭背赤甲，斷崖當白鹽。客居愧遷次，春酒漸多添。',144,'御定全唐詩/json/229.json','["奔峭背赤甲，斷崖當白鹽。客居愧遷次，春酒漸多添。", "花亞欲移竹，鳥窺新捲簾。衰年不敢恨，勝概欲相兼。", "亂後居難定，春歸客未還。水生魚複浦，雲暖麝香山。", "半頂梳頭白，過眉拄杖斑。相看多使者，一一問函關。", "宋玉歸州宅，雲通白帝城。吾人淹老病，旅食豈才名。", "峽口風常急，江流氣不平。只應與兒子，飄轉任浮生。"]'),
('yuding-43','赤甲','杜甫','唐','御定全唐诗','yuding','','[]','卜居赤甲遷居新，兩見巫山楚水春。炙背可以獻天子，',40,'御定全唐詩/json/229.json','["卜居赤甲遷居新，兩見巫山楚水春。炙背可以獻天子，", "笑接郎中評事飲，病從深酌道吾真。"]'),
('yuding-44','卜居','杜甫','唐','御定全唐诗','yuding','','[]','歸羨遼東鶴，吟同楚執珪。未成游碧海，著處覓丹梯。',48,'御定全唐詩/json/229.json','["歸羨遼東鶴，吟同楚執珪。未成游碧海，著處覓丹梯。", "雲障寬江左，春耕破瀼西。桃紅客若至，定似昔人迷。"]'),
('yuding-45','暮春題瀼西新賃草屋五首','杜甫','唐','御定全唐诗','yuding','','[]','久嗟三峽客，再與暮春期。百舌欲無語，繁花能幾時。',240,'御定全唐詩/json/229.json','["久嗟三峽客，再與暮春期。百舌欲無語，繁花能幾時。", "谷虛雲氣薄，波亂日華遲。戰伐何由定，哀傷不在茲。", "此邦千樹橘，不見比封君。養拙干戈際，全生麋鹿群。", "畏人江北草，旅食瀼西雲。萬里巴渝曲，三年實飽聞。", "彩雲陰複白，錦樹曉來青。身世雙蓬鬢，乾坤一草亭。", "哀歌時自短，醉舞為誰醒。細雨荷鋤立，江猿吟翠屏。", "壯年學書劍，他日委泥沙。事主非無祿，浮生即有涯。", "高齋依藥餌，絕域改春華。喪亂丹心破，王臣未一家。", "欲陳濟世策，已老尚書郎。未息豺虎鬥，空慚鴛鷺行。", "時危人事急，風逆羽毛傷。落日悲江漢，中宵淚滿床。"]'),
('yuding-46','園','杜甫','唐','御定全唐诗','yuding','','[]','仲夏流多水，清晨向小園。碧溪搖艇闊，朱果爛枝繁。',48,'御定全唐詩/json/229.json','["仲夏流多水，清晨向小園。碧溪搖艇闊，朱果爛枝繁。", "始為江山靜，終防市井喧。畦蔬繞茅屋，自足媚盤餐。"]'),
('yuding-47','豎子至','杜甫','唐','御定全唐诗','yuding','','[]','楂梨且綴碧，梅杏半傳黃。小子幽園至，輕籠熟柰香。',48,'御定全唐詩/json/229.json','["楂梨且綴碧，梅杏半傳黃。小子幽園至，輕籠熟柰香。", "山風猶滿把，野露及新嘗。欲寄江湖客，提攜日月長。"]'),
('yuding-48','示獠奴阿段','杜甫','唐','御定全唐诗','yuding','','[]','山木蒼蒼落日曛，竹竿褭褭細泉分。郡人入夜爭餘瀝，',40,'御定全唐詩/json/229.json','["山木蒼蒼落日曛，竹竿褭褭細泉分。郡人入夜爭餘瀝，", "曾驚陶侃胡奴異，怪爾常穿虎豹群。"]'),
('yuding-49','秋野五首','杜甫','唐','御定全唐诗','yuding','','[]','秋野日疏蕪，寒江動碧虛。系舟蠻井絡，卜宅楚村墟。',240,'御定全唐詩/json/229.json','["秋野日疏蕪，寒江動碧虛。系舟蠻井絡，卜宅楚村墟。", "棗熟從人打，葵荒欲自鋤。盤餐老夫食，分減及溪魚。", "易識浮生理，難教一物違。水深魚極樂，林茂鳥知歸。", "吾老甘貧病，榮華有是非。秋風吹几杖，不厭此山薇。", "禮樂攻吾短，山林引興長。掉頭紗帽仄，曝背竹書光。", "風落收松子，天寒割蜜房。稀疏小紅翠，駐屐近微香。", "遠岸秋沙白，連山晚照紅。潛鱗輸駭浪，歸翼會高風。", "砧響家家發，樵聲個個同。飛霜任青女，賜被隔南宮。", "身許麒麟畫，年衰鴛鷺群。大江秋易盛，空峽夜多聞。", "徑隱千重石，帆留一片雲。兒童解蠻語，不必作參軍。"]'),
('yuding-50','溪上','杜甫','唐','御定全唐诗','yuding','','[]','峽內淹留客，溪邊四五家。古苔生迮地，秋竹隱疏花。',48,'御定全唐詩/json/229.json','["峽內淹留客，溪邊四五家。古苔生迮地，秋竹隱疏花。", "塞俗人無井，山田飯有沙。西江使船至，時複問京華。"]'),
('yuding-51','樹間','杜甫','唐','御定全唐诗','yuding','','[]','岑寂雙甘樹，婆娑一院香。交柯低几杖，垂實礙衣裳。',48,'御定全唐詩/json/229.json','["岑寂雙甘樹，婆娑一院香。交柯低几杖，垂實礙衣裳。", "滿歲如松碧，同時待菊黃。幾回沾葉露，乘月坐胡床。"]'),
('yuding-52','課小豎鉏斫舍北果林，枝蔓荒穢，淨訖移床三首','杜甫','唐','御定全唐诗','yuding','','[]','病枕依茅棟，荒鉏淨果林。背堂資僻遠，在野興清深。',144,'御定全唐詩/json/229.json','["病枕依茅棟，荒鉏淨果林。背堂資僻遠，在野興清深。", "山雉防求敵，江猿應獨吟。泄雲高不去，隱幾亦無心。", "眾壑生寒早，長林卷霧齊。青蟲懸就日，朱果落封泥。", "薄俗防人面，全身學馬蹄。吟詩坐回首，隨意葛巾低。", "籬弱門何向，沙虛岸只摧。日斜魚更食，客散鳥還來。", "寒水光難定，秋山響易哀。天涯稍曛黑，倚杖更裴回。"]'),
('yuding-53','寒雨朝行視園樹','杜甫','唐','御定全唐诗','yuding','','[]','柴門雜樹向千株，丹橘黃甘此地無。江上今朝寒雨歇，',72,'御定全唐詩/json/229.json','["柴門雜樹向千株，丹橘黃甘此地無。江上今朝寒雨歇，", "鎖石藤稍元自落，倚天松骨見來枯。林香出實垂將盡，", "衰顏更覓藜床坐，緩步仍須竹杖扶。散騎未知雲閣處，"]'),
('yuding-54','季秋江村','杜甫','唐','御定全唐诗','yuding','','[]','喬木村墟古，疏籬野蔓懸。清琴將暇日，白首望霜天。',48,'御定全唐詩/json/229.json','["喬木村墟古，疏籬野蔓懸。清琴將暇日，白首望霜天。", "登俎黃甘重，支床錦石圓。遠遊雖寂寞，難見此山川。"]'),
('yuding-55','小園','杜甫','唐','御定全唐诗','yuding','','[]','由來巫峽水，本自楚人家。客病留因藥，春深買為花。',48,'御定全唐詩/json/229.json','["由來巫峽水，本自楚人家。客病留因藥，春深買為花。", "秋庭風落果，瀼岸雨頹沙。問俗營寒事，將詩待物華。"]'),
('yuding-56','自瀼西荊扉且移居東屯茅屋四首','杜甫','唐','御定全唐诗','yuding','','[]','白鹽危嶠北，赤甲古城東。平地一川穩，高山四面同。',192,'御定全唐詩/json/229.json','["白鹽危嶠北，赤甲古城東。平地一川穩，高山四面同。", "煙霜淒野日，粳稻熟天風。人事傷蓬轉，吾將守桂叢。", "東屯複瀼西，一種住青溪。來往皆茅屋，淹留為稻畦。", "市喧宜近利，林僻此無蹊。若訪衰翁語，須令剩客迷。", "道北馮都使，高齋見一川。子能渠細石，吾亦沼清泉。", "枕帶還相似，柴荊即有焉。斫畬應費日，解纜不知年。", "牢落西江外，參差北戶間。久游巴子國，臥病楚人山。", "幽獨移佳境，清深隔遠關。寒空見鴛鷺，回首憶朝班。"]'),
('yuding-57','茅堂檢校收稻二首','杜甫','唐','御定全唐诗','yuding','','[]','香稻三秋末，平田百頃間。喜無多屋宇，幸不礙雲山。',96,'御定全唐詩/json/229.json','["香稻三秋末，平田百頃間。喜無多屋宇，幸不礙雲山。", "禦夾侵寒氣，嘗新破旅顏。紅鮮終日有，玉粒未吾慳。", "稻米炊能白，秋葵煮複新。誰雲滑易飽，老藉軟俱勻。", "種幸房州熟，苗同伊闕春。無勞映渠碗，自有色如銀。"]'),
('yuding-58','東屯月夜','杜甫','唐','御定全唐诗','yuding','','[]','抱疾漂萍老，防邊舊穀屯。春農親異俗，歲月在衡門。',96,'御定全唐詩/json/229.json','["抱疾漂萍老，防邊舊穀屯。春農親異俗，歲月在衡門。", "青女霜楓重，黃牛峽水喧。泥留虎鬥跡，月掛客愁村。", "喬木澄稀影，輕雲倚細根。數驚聞雀噪，暫睡想猿蹲。", "日轉東方白，風來北斗昏。天寒不成寢，無夢寄歸魂。"]'),
('yuding-59','東屯北崦','杜甫','唐','御定全唐诗','yuding','','[]','盜賊浮生困，誅求異俗貧。空村惟見鳥，落日未逢人。',48,'御定全唐詩/json/229.json','["盜賊浮生困，誅求異俗貧。空村惟見鳥，落日未逢人。", "步壑風吹面，看松露滴身。遠山回白首，戰地有黃塵。"]'),
('yuding-60','從驛次草堂複至東屯二首','杜甫','唐','御定全唐诗','yuding','','[]','峽內歸田客，江邊借馬騎。非尋戴安道，似向習家池。',96,'御定全唐詩/json/229.json','["峽內歸田客，江邊借馬騎。非尋戴安道，似向習家池。", "峽險風煙僻，天寒橘柚垂。築場看斂積，一學楚人為。", "短景難高臥，衰年強此身。山家蒸栗暖，野飯謝麋新。", "世路知交薄，門庭畏客頻。牧童斯在眼，田父實為鄰。"]'),
('yuding-61','暫往白帝複還東屯','杜甫','唐','御定全唐诗','yuding','','[]','複作歸田去，猶殘獲稻功。築場憐穴蟻，拾穗許村童。',48,'御定全唐詩/json/229.json','["複作歸田去，猶殘獲稻功。築場憐穴蟻，拾穗許村童。", "落杵光輝白，除芒子粒紅。加餐可扶老，倉庾慰飄蓬。"]'),
('yuding-62','刈稻了詠懷','杜甫','唐','御定全唐诗','yuding','','[]','稻獲空雲水，川平對石門。寒風疏落木，旭日散雞豚。',48,'御定全唐詩/json/229.json','["稻獲空雲水，川平對石門。寒風疏落木，旭日散雞豚。", "野哭初聞戰，樵歌稍出村。無家問消息，作客信乾坤。"]'),
('yuding-63','上白帝城','杜甫','唐','御定全唐诗','yuding','','[]','城峻隨天壁，樓高更女牆。江流思夏後，風至憶襄王。',48,'御定全唐詩/json/229.json','["城峻隨天壁，樓高更女牆。江流思夏後，風至憶襄王。", "老去聞悲角，人扶報夕陽。公孫初恃險，躍馬意何長。"]'),
('yuding-64','上白帝城二首','杜甫','唐','御定全唐诗','yuding','','[]','江城含變態，一上一回新。天欲今朝雨，山歸萬古春。',144,'御定全唐詩/json/229.json','["江城含變態，一上一回新。天欲今朝雨，山歸萬古春。", "英雄餘事業，衰邁久風塵。取醉他鄉客，相逢故國人。", "兵戈猶擁蜀，賦斂強輸秦。不是煩形勝，深慚畏損神。", "白帝空祠廟，孤雲自往來。江山城宛轉，棟宇客裴回。", "勇略今何在，當年亦壯哉。後人將酒肉，虛殿日塵埃。", "穀鳥鳴還過，林花落又開。多慚病無力，騎馬入青苔。"]'),
('yuding-65','武侯廟','杜甫','唐','御定全唐诗','yuding','','[]','遺廟丹青落，空山草木長。猶聞辭後主，不復臥南陽。',24,'御定全唐詩/json/229.json','["遺廟丹青落，空山草木長。猶聞辭後主，不復臥南陽。"]'),
('yuding-66','八陣圖','杜甫','唐','御定全唐诗','yuding','','[]','功蓋三分國，名高八陣圖。江流石不轉，遺恨失吞吳。',24,'御定全唐詩/json/229.json','["功蓋三分國，名高八陣圖。江流石不轉，遺恨失吞吳。"]'),
('yuding-67','謁先主廟','杜甫','唐','御定全唐诗','yuding','','[]','慘澹風雲會，乘時各有人。力侔分社稷，志屈偃經綸。',192,'御定全唐詩/json/229.json','["慘澹風雲會，乘時各有人。力侔分社稷，志屈偃經綸。", "複漢留長策，中原仗老臣。雜耕心未已，歐血事酸辛。", "霸氣西南歇，雄圖歷數屯。錦江元過楚，劍閣複通秦。", "舊俗存祠廟，空山立鬼神。虛簷交鳥道，枯木半龍鱗。", "竹送清溪月，苔移玉座春。閭閻兒女換，歌舞歲時新。", "絕域歸舟遠，荒城系馬頻。如何對搖落，況乃久風塵。", "孰與關張並，功臨耿鄧親。應天才不小，得士契無鄰。", "遲暮堪帷幄，飄零且釣緡。向來憂國淚，寂寞灑衣巾。"]'),
('yuding-68','白鹽山','杜甫','唐','御定全唐诗','yuding','','[]','卓立群峰外，蟠根積水邊。他皆任厚地，爾獨近高天。',48,'御定全唐詩/json/229.json','["卓立群峰外，蟠根積水邊。他皆任厚地，爾獨近高天。", "白榜千家邑，清秋萬估船。詞人取佳句，刻畫竟誰傳。"]'),
('yuding-69','灩澦堆','杜甫','唐','御定全唐诗','yuding','','[]','巨積水中央，江寒出水長。沈牛答雲雨，如馬戒舟航。',48,'御定全唐詩/json/229.json','["巨積水中央，江寒出水長。沈牛答雲雨，如馬戒舟航。", "天意存傾覆，神功接混茫。干戈連解纜，行止憶垂堂。"]'),
('yuding-70','灩澦','杜甫','唐','御定全唐诗','yuding','','[]','灩澦既沒孤根深，西來水多愁太陰。江天漠漠鳥雙去，',40,'御定全唐詩/json/229.json','["灩澦既沒孤根深，西來水多愁太陰。江天漠漠鳥雙去，", "寄語舟航惡年少，休翻鹽井橫黃金。"]'),
('yuding-71','白帝','杜甫','唐','御定全唐诗','yuding','','[]','白帝城中雲出門，白帝城下雨翻盆。高江急峽雷霆鬥，',40,'御定全唐詩/json/229.json','["白帝城中雲出門，白帝城下雨翻盆。高江急峽雷霆鬥，", "哀哀寡婦誅求盡，慟哭秋原何處村。"]'),
('yuding-72','白帝城樓','杜甫','唐','御定全唐诗','yuding','','[]','江度寒山閣，城高絕塞樓。翠屏宜晚對，白谷會深遊。',48,'御定全唐詩/json/229.json','["江度寒山閣，城高絕塞樓。翠屏宜晚對，白谷會深遊。", "急急能鳴雁，輕輕不下鷗。彝陵春色起，漸擬放扁舟。"]'),
('yuding-73','曉望白帝城鹽山','杜甫','唐','御定全唐诗','yuding','','[]','徐步移班杖，看山仰白頭。翠深開斷壁，紅遠結飛樓。',48,'御定全唐詩/json/229.json','["徐步移班杖，看山仰白頭。翠深開斷壁，紅遠結飛樓。", "日出清江望，暄和散旅愁。春城見松雪，始擬進歸舟。"]'),
('yuding-74','白帝城最高樓','杜甫','唐','御定全唐诗','yuding','','[]','城尖徑昃旌旆愁，獨立縹緲之飛樓。峽坼雲霾龍虎臥，',40,'御定全唐詩/json/229.json','["城尖徑昃旌旆愁，獨立縹緲之飛樓。峽坼雲霾龍虎臥，", "杖藜歎世者誰子，泣血迸空回白頭。"]'),
('yuding-75','白帝樓','杜甫','唐','御定全唐诗','yuding','','[]','漠漠虛無裏，連連睥睨侵。樓光去日遠，峽影入江深。',48,'御定全唐詩/json/229.json','["漠漠虛無裏，連連睥睨侵。樓光去日遠，峽影入江深。", "臘破思端綺，春歸待一金。去年梅柳意，還欲攪邊心。"]'),
('yuding-76','陪諸公上白帝城宴越公堂之作','杜甫','唐','御定全唐诗','yuding','','[]','此堂存古制，城上俯江郊。落構垂雲雨，荒階蔓草茅。',72,'御定全唐詩/json/229.json','["此堂存古制，城上俯江郊。落構垂雲雨，荒階蔓草茅。", "柱穿蜂溜蜜，棧缺燕添巢。坐接春杯氣，心傷豔蕊梢。", "英靈如過隙，宴衎願投膠。莫問東流水，生涯未即拋。"]'),
('yuding-77','峽隘','杜甫','唐','御定全唐诗','yuding','','[]','聞說江陵府，雲沙靜眇然。白魚如切玉，朱橘不論錢。',48,'御定全唐詩/json/229.json','["聞說江陵府，雲沙靜眇然。白魚如切玉，朱橘不論錢。", "水有遠湖樹，人今何處船。青山各在眼，卻望峽中天。"]'),
('yuding-78','諸葛廟','杜甫','唐','御定全唐诗','yuding','','[]','久游巴子國，屢入武侯祠。竹日斜虛寢，溪風滿薄帷。',72,'御定全唐詩/json/229.json','["久游巴子國，屢入武侯祠。竹日斜虛寢，溪風滿薄帷。", "君臣當共濟，賢聖亦同時。翊戴歸先主，併吞更出師。", "蟲蛇穿畫壁，巫覡醉蛛絲。欻憶吟梁父，躬耕也未遲。"]'),
('yuding-79','峽口二首','杜甫','唐','御定全唐诗','yuding','','[]','峽口大江間，西南控百蠻。城欹連粉堞，岸斷更青山。',96,'御定全唐詩/json/229.json','["峽口大江間，西南控百蠻。城欹連粉堞，岸斷更青山。", "開闢多天險，防隅一水關。亂離聞鼓角，秋氣動衰顏。", "時清關失險，世亂戟如林。去矣英雄事，荒哉割據心。", "蘆花留客晚，楓樹坐猿深。疲苶煩親故，諸侯數賜金。"]'),
('yuding-80','天池','杜甫','唐','御定全唐诗','yuding','','[]','天池馬不到，嵐壁鳥才通。百頃青雲杪，層波白石中。',120,'御定全唐詩/json/229.json','["天池馬不到，嵐壁鳥才通。百頃青雲杪，層波白石中。", "鬱紆騰秀氣，蕭瑟浸寒空。直對巫山出，兼疑夏禹功。", "魚龍開闢有，菱芡古今同。聞道奔雷黑，初看浴日紅。", "飄零神女雨，斷續楚王風。欲問支機石，如臨獻寶宮。", "九秋驚雁序，萬里狎漁翁。更是無人處，誅茅任薄躬。"]'),
('yuding-81','瞿塘兩崖','杜甫','唐','御定全唐诗','yuding','','[]','三峽傳何處，雙崖壯此門。入天猶石色，穿水忽雲根。',48,'御定全唐詩/json/229.json','["三峽傳何處，雙崖壯此門。入天猶石色，穿水忽雲根。", "猱玃須髯古，蛟龍窟宅尊。羲和冬馭近，愁畏日車翻。"]'),
('yuding-82','夔州歌十絕句','杜甫','唐','御定全唐诗','yuding','','[]','中巴之東巴東山，江水開闢流其間。',320,'御定全唐詩/json/229.json','["中巴之東巴東山，江水開闢流其間。", "白帝高為三峽鎮，夔州險過百牢關。", "白帝夔州各異城，蜀江楚峽混殊名。", "英雄割據非天意，霸主併吞在物情。", "群雄競起問前朝，王者無外見今朝。", "比訝漁陽結怨恨，元聽舜日舊簫韶。", "赤甲白鹽俱刺天，閭閻繚繞接山巔。", "楓林橘樹丹青合，複道重樓錦繡懸。", "瀼東瀼西一萬家，江北江南春冬花。", "背飛鶴子遺瓊蕊，相趁鳧雛入蔣牙。", "東屯稻畦一百頃，北有澗水通青苗。", "晴浴狎鷗分處處，雨隨神女下朝朝。", "蜀麻吳鹽自古通，萬斛之舟行若風。", "長年三老長歌裏，白晝攤錢高浪中。", "憶昔咸陽都市合，山水之圖張賣時。", "巫峽曾經寶屏見，楚宮猶對碧峰疑。", "武侯祠堂不可忘，中有松柏參天長。", "干戈滿地客愁破，雲日如火炎天涼。", "閬風玄圃與蓬壺，中有高堂天下無。", "借問夔州壓何處，峽門江腹擁城隅。"]'),
('yuding-83','上卿翁請修武侯廟，遺像缺落，時崔卿權夔州','杜甫','唐','御定全唐诗','yuding','','[]','大賢為政即多聞，刺史真符不必分。',32,'御定全唐詩/json/229.json','["大賢為政即多聞，刺史真符不必分。", "尚有西郊諸葛廟，臥龍無首對江濆。"]'),
('yuding-0','偶題','杜甫','唐','御定全唐诗','yuding','','[]','文章千古事，得失寸心知。作者皆殊列，名聲豈浪垂。',264,'御定全唐詩/json/230.json','["文章千古事，得失寸心知。作者皆殊列，名聲豈浪垂。", "騷人嗟不見，漢道盛於斯。前輩飛騰入，餘波綺麗為。", "後賢兼舊列，歷代各清規。法自儒家有，心從弱歲疲。", "永懷江左逸，多病鄴中奇。騄驥皆良馬，騏驎帶好兒。", "車輪徒已斫，堂構惜仍虧。漫作潛夫論，虛傳幼婦碑。", "緣情慰漂蕩，抱疾屢遷移。經濟慚長策，飛棲假一枝。", "塵沙傍蜂蠆，江峽繞蛟螭。蕭瑟唐虞遠，聯翩楚漢危。", "聖朝兼盜賊，異俗更喧卑。鬱鬱星辰劍，蒼蒼雲雨池。", "兩都開幕府，萬宇插軍麾。南海殘銅柱，東風避月支。", "音書恨烏鵲，號怒怪熊羆。稼穡分詩興，柴荊學土宜。", "故山迷白閣，秋水隱黃陂。不敢要佳句，愁來賦別離。"]'),
('yuding-1','秋興八首','杜甫','唐','御定全唐诗','yuding','','[]','玉露凋傷楓樹林，巫山巫峽氣蕭森。江間波浪兼天湧，',320,'御定全唐詩/json/230.json','["玉露凋傷楓樹林，巫山巫峽氣蕭森。江間波浪兼天湧，", "寒衣處處催刀尺，白帝城高急暮砧。", "夔府孤城落日斜，每依南斗望京華。聽猿實下三聲淚，", "請看石上藤蘿月，已映洲前蘆荻花。", "千家山郭靜朝暉，一日江樓坐翠微。信宿漁人還泛泛，", "同學少年多不賤，五陵衣馬自輕肥。", "聞道長安似弈棋，百年世事不勝悲。王侯第宅皆新主，", "魚龍寂寞秋江冷，故國平居有所思。", "蓬萊宮闕對南山，承露金莖霄漢間。西望瑤池降王母，", "一臥滄江驚歲晚，幾回青瑣照朝班。", "瞿唐峽口曲江頭，萬里風煙接素秋。花萼夾城通禦氣，", "回首可憐歌舞地，秦中自古帝王州。", "昆明池水漢時功，武帝旌旗在眼中。織女機絲虛月夜，", "關塞極天唯鳥道，江湖滿地一漁翁。", "昆吾禦宿自逶迤，紫閣峰陰入渼陂。香稻啄餘鸚鵡粒，", "彩筆昔遊幹氣象，白頭吟望苦低垂。"]'),
('yuding-2','詠懷古跡五首','杜甫','唐','御定全唐诗','yuding','','[]','支離東北風塵際，漂泊西南天地間。三峽樓臺淹日月，',200,'御定全唐詩/json/230.json','["支離東北風塵際，漂泊西南天地間。三峽樓臺淹日月，", "庾信平生最蕭瑟，暮年詩賦動江關。", "搖落深知宋玉悲，風流儒雅亦吾師。悵望千秋一灑淚，", "最是楚宮俱泯滅，舟人指點到今疑。", "群山萬壑赴荊門，生長明妃尚有村。一去紫台連朔漠，", "千載琵琶作胡語，分明怨恨曲中論。", "蜀主窺吳幸三峽，崩年亦在永安宮。翠華想像空山裏，", "武侯祠屋常鄰近，一體君臣祭祀同。", "諸葛大名垂宇宙，宗臣遺像肅清高。三分割據紆籌策，", "福移漢祚難恢復，志決身殲軍務勞。"]'),
('yuding-3','諸將五首','杜甫','唐','御定全唐诗','yuding','','[]','漢朝陵墓對南山，胡虜千秋尚入關。昨日玉魚蒙葬地，',200,'御定全唐詩/json/230.json','["漢朝陵墓對南山，胡虜千秋尚入關。昨日玉魚蒙葬地，", "多少材官守涇渭，將軍且莫破愁顏。", "韓公本意築三城，擬絕天驕拔漢旌。豈謂盡煩回紇馬，", "獨使至尊憂社稷，諸君何以答升平。", "洛陽宮殿化為烽，休道秦關百二重。滄海未全歸禹貢，", "稍喜臨邊王相國，肯銷金甲事春農。", "回首扶桑銅柱標，冥冥氛祲未全銷。越裳翡翠無消息，", "炎風朔雪天王地，只在忠臣翊聖朝。", "錦江春色逐人來，巫峽清秋萬壑哀。正憶往時嚴僕射，", "西蜀地形天下險，安危須仗出群材。"]'),
('yuding-4','秋日夔府詠懷奉寄鄭監李賓客一百韻','杜甫','唐','御定全唐诗','yuding','','[]','絕塞烏蠻北，孤城白帝邊。飄零仍百里，消渴已三年。',576,'御定全唐詩/json/230.json','["絕塞烏蠻北，孤城白帝邊。飄零仍百里，消渴已三年。", "雄劍鳴開匣，群書滿系船。亂離心不展，衰謝日蕭然。", "筋力妻孥問，菁華歲月遷。登臨多物色，陶冶賴詩篇。", "峽束滄江起，岩排石樹圓。拂雲霾楚氣，朝海蹴吳天。", "煮井為鹽速，燒畬度地偏。有時驚疊嶂，何處覓平川。", "鸂鶒雙雙舞，獼猿壘壘懸。碧蘿長似帶，錦石小如錢。", "春草何曾歇，寒花亦可憐。獵人吹戍火，野店引山泉。", "喚起搔頭急，扶行幾屐穿。兩京猶薄產，四海絕隨肩。", "幕府初交辟，郎官幸備員。瓜時猶旅寓，萍泛苦夤緣。", "藥餌虛狼藉，秋風灑靜便。開襟驅瘴癘，明目掃雲煙。", "高宴諸侯禮，佳人上客前。哀箏傷老大，華屋豔神仙。", "南內開元曲，常時弟子傳。法歌聲變轉，滿座涕潺湲。", "吊影夔州僻，回腸杜曲煎。即今龍廄水，莫帶犬戎膻。", "耿賈扶王室，蕭曹拱禦筵。乘威滅蜂蠆，戮力效鷹鸇。", "舊物森猶在，凶徒惡未悛。國須行戰伐，人憶止戈鋋。", "奴僕何知禮，恩榮錯與權。胡星一彗孛，黔首遂拘攣。", "哀痛絲綸切，煩苛法令蠲。業成陳始王，兆喜出於畋。", "宮禁經綸密，臺階翊戴全。熊羆載呂望，鴻雁美周宣。", "側聽中興主，長吟不世賢。音徽一柱數，道裏下牢千。", "鄭李光時論，文章並我先。陰何尚清省，沈宋欻聯翩。", "律比昆侖竹，音知燥濕弦。風流俱善價，愜當久忘筌。", "置驛常如此，登龍蓋有焉。雖雲隔禮數，不敢墜周旋。", "高視收人表，虛心味道玄。馬來皆汗血，鶴唳必青田。", "羽翼商山起，蓬萊漢閣連。管甯紗帽淨，江令錦袍鮮。"]'),
('yuding-5','贈李八秘書別三十韻','杜甫','唐','御定全唐诗','yuding','','[]','往時中補右，扈蹕上元初。反氣淩行在，妖星下直廬。',360,'御定全唐詩/json/230.json','["往時中補右，扈蹕上元初。反氣淩行在，妖星下直廬。", "六龍瞻漢闕，萬騎略姚墟。玄朔回天步，神都憶帝車。", "一戎才汗馬，百姓免為魚。通籍蟠螭印，差肩列鳳輿。", "事殊迎代邸，喜異賞朱虛。寇盜方歸順，乾坤欲晏如。", "不才同補袞，奉詔許牽裾。鴛鷺叨雲閣，麒麟滯玉除。", "文園多病後，中散舊交疏。飄泊哀相見，平生意有餘。", "風煙巫峽遠，台榭楚宮虛。觸目非論故，新文尚起予。", "清秋凋碧柳，別浦落紅蕖。消息多旗幟，經過歎裏閭。", "戰連唇齒國，軍急羽毛書。幕府籌頻問，山家藥正鋤。", "台星入朝謁，使節有吹噓。西蜀災長弭，南翁憤始攄。", "對揚抏士卒，幹沒費倉儲。勢藉兵須用，功無禮忽諸。", "禦鞍金騕褭，宮硯玉蟾蜍。拜舞銀鉤落，恩波錦帕舒。", "此行非不濟，良友昔相于。去旆依顏色，沿流想疾徐。", "沈綿疲井臼，倚薄似樵漁。乞米煩佳客，鈔詩聽小胥。", "杜陵斜晚照，潏水帶寒淤。莫話清溪發，蕭蕭白映梳。"]'),
('yuding-6','寄劉峽州伯華使君四十韻','杜甫','唐','御定全唐诗','yuding','','[]','峽內多雲雨，秋來尚鬱蒸。遠山朝白帝，深水謁彝陵。',481,'御定全唐詩/json/230.json','["峽內多雲雨，秋來尚鬱蒸。遠山朝白帝，深水謁彝陵。", "遲暮嗟為客，西南喜得朋。哀猿更起坐，落雁失飛騰。", "伏枕思瓊樹，臨軒對玉繩。青松寒不落，碧海闊逾澄。", "昔歲文為理，群公價盡增。家聲同令聞，時論以儒稱。", "太后當朝肅，多才接跡升。翠虛捎魍魎，丹極上鶤鵬。", "宴引春壺滿，恩分夏簟冰。雕章五色筆，紫殿九華燈。", "學並盧王敏，書偕褚薛能。老兄真不墜，小子獨無承。", "近有風流作，聊從月繼征。放蹄知赤驥，捩翅服蒼鷹。", "卷軸來何晚，襟懷庶可憑。會期吟諷數，益破旅愁凝。", "雕刻初誰料，纖毫欲自矜。神融躡飛動，戰勝洗侵淩。", "妙取筌蹄棄，高宜百萬層。白頭遺恨在，青竹幾人登。", "回首追談笑，勞歌局寢興。年華紛已矣，世故莽相仍。", "刺史諸侯貴，郎官列宿應。潘生驂閣遠，黃霸璽書增。", "乳rP號攀石，饑鼯訴落藤。藥囊親道士，灰劫問胡僧。", "憑久烏皮折，簪稀白帽棱。林居看蟻穴，野食行魚罾。", "筋力交凋喪，飄零免戰兢。皆為百里宰，正似六安丞。", "姹女縈新裹，丹砂冷舊秤。但求椿壽永，莫慮杞天崩。", "煉骨調情性，張兵撓棘矜。養生終自惜，伐數必全懲。", "政術甘疏誕，詞場愧服膺。展懷詩誦魯，割愛酒如澠。", "咄咄寧書字，冥冥欲避矰。江湖多白鳥，天地有青蠅。"]'),
('yuding-7','夔府書懷四十韻','杜甫','唐','御定全唐诗','yuding','','[]','昔罷河西尉，初興薊北師。不才名位晚，敢恨省郎遲。',480,'御定全唐詩/json/230.json','["昔罷河西尉，初興薊北師。不才名位晚，敢恨省郎遲。", "扈聖崆峒日，端居灩澦時。萍流仍汲引，樗散尚恩慈。", "遂阻雲台宿，常懷湛露詩。翠華森遠矣，白首颯淒其。", "拙被林泉滯，生逢酒賦欺。文園終寂寞，漢閣自磷緇。", "病隔君臣議，慚紆德澤私。揚鑣驚主辱，拔劍撥年衰。", "社稷經綸地，風雲際會期。血流紛在眼，涕灑亂交頤。", "四瀆樓船泛，中原鼓角悲。賊壕連白翟，戰瓦落丹墀。", "先帝嚴靈寢，宗臣切受遺。恒山猶突騎，遼海競張旗。", "田父嗟膠漆，行人避蒺藜。總戎存大體，降將飾卑詞。", "楚貢何年絕，堯封舊俗疑。長籲翻北寇，一望卷西夷。", "不必陪玄圃，超然待具茨。凶兵鑄農器，講殿辟書帷。", "廟算高難測，天憂實在茲。形容真潦倒，答效莫支持。", "使者分王命，群公各典司。恐乖均賦斂，不似問瘡痍。", "萬里煩供給，孤城最怨思。綠林寧小患，雲夢欲難追。", "即事須嘗膽，蒼生可察眉。議堂猶集鳳，正觀是元龜。", "處處喧飛檄，家家急競錐。蕭車安不定，蜀使下何之。", "釣瀨疏墳籍，耕岩進弈棋。地蒸餘破扇，冬暖更纖絺。", "豺遘哀登楚，麟傷泣象尼。衣冠迷適越，藻繪憶游睢。", "賞月延秋桂，傾陽逐露葵。大庭終反樸，京觀且僵屍。", "高枕虛眠晝，哀歌欲和誰。南宮載勳業，凡百慎交綏。"]'),
('yuding-8','解悶十二首','杜甫','唐','御定全唐诗','yuding','','[]','草閣柴扉星散居，浪翻江黑雨飛初。',384,'御定全唐詩/json/230.json','["草閣柴扉星散居，浪翻江黑雨飛初。", "山禽引子哺紅果，溪友得錢留白魚。", "商胡離別下揚州，憶上西陵故驛樓。", "為問淮南米貴賤，老夫乘興欲東流。", "一辭故國十經秋，每見秋瓜憶故丘。", "今日南湖采薇蕨，何人為覓鄭瓜州。", "沈范早知何水部，曹劉不待薛郎中。", "獨當省署開文苑，兼泛滄浪學釣翁。", "李陵蘇武是吾師，孟子論文更不疑。", "一飯未曾留俗客，數篇今見古人詩。", "複憶襄陽孟浩然，清詩句句盡堪傳。", "即今耆舊無新語，漫釣槎頭縮頸鯿。", "陶冶性靈在底物，新詩改罷自長吟。", "孰知二謝將能事，頗學陰何苦用心。", "不見高人王右丞，藍田丘壑漫寒藤。", "最傳秀句寰區滿，未絕風流相國能。", "先帝貴妃今寂寞，荔枝還複入長安。", "炎方每續朱櫻獻，玉座應悲白露團。", "憶過瀘戎摘荔枝，青峰隱映石逶迤。", "京中舊見無顏色，紅顆酸甜只自知。", "翠瓜碧李沈玉甃，赤梨葡萄寒露成。", "可憐先不異枝蔓，此物娟娟長遠生。", "側生野岸及江蒲，不熟丹宮滿玉壺。", "雲壑布衣駘背死，勞生重馬翠眉須。"]'),
('yuding-9','複愁十二首','杜甫','唐','御定全唐诗','yuding','','[]','人煙生處僻，虎跡過新蹄。野鶻翻窺草，村船逆上溪。',288,'御定全唐詩/json/230.json','["人煙生處僻，虎跡過新蹄。野鶻翻窺草，村船逆上溪。", "釣艇收緡盡，昏鴉接翅歸。月生初學扇，雲細不成衣。", "萬國尚防寇，故園今若何。昔歸相識少，早已戰場多。", "身覺省郎在，家須農事歸。年深荒草徑，老恐失柴扉。", "金絲鏤箭鏃，皂尾制旗竿。一自風塵起，猶嗟行路難。", "胡虜何曾盛，干戈不肯休。閭閻聽小子，談話覓封侯。", "貞觀銅牙弩，開元錦獸張。花門小前好，此物棄沙場。", "今日翔麟馬，先宜駕鼓車。無勞問河北，諸將覺榮華。", "任轉江淮粟，休添苑囿兵。由來貔虎士，不滿鳳凰城。", "江上亦秋色，火雲終不移。巫山猶錦樹，南國且黃鸝。", "每恨陶彭澤，無錢對菊花。如今九日至，自覺酒須賒。", "病減詩仍拙，吟多意有餘。莫看江總老，猶被賞時魚。"]'),
('yuding-10','承聞河北諸道節度入朝歡喜口號絕句十二首','杜甫','唐','御定全唐诗','yuding','','[]','祿山作逆降天誅，更有思明亦已無。',384,'御定全唐詩/json/230.json','["祿山作逆降天誅，更有思明亦已無。", "洶洶人寰猶不定，時時鬥戰欲何須。", "社稷蒼生計必安，蠻夷雜種錯相干。", "周宣漢武今王是，孝子忠臣後代看。", "喧喧道路多歌謠，河北將軍盡入朝。", "始是乾坤王室正，卻交江漢客魂銷。", "不道諸公無表來，茫然庶事遣人猜。", "擁兵相學干戈銳，使者徒勞百萬回。", "鳴玉鏘金盡正臣，修文偃武不無人。", "興王會靜妖氛氣，聖壽宜過一萬春。", "英雄見事若通神，聖哲為心小一身。", "燕趙休矜出佳麗，宮闈不擬選才人。", "抱病江天白首郎，空山樓閣暮春光。", "衣冠是日朝天子，草奏何時入帝鄉。", "澶漫山東一百州，削成如桉抱青丘。", "苞茅重入歸關內，王祭還供盡海頭。", "東逾遼水北滹沱，星象風雲喜共和。", "紫氣關臨天地闊，黃金台貯俊賢多。", "漁陽突騎邯鄲兒，酒酣並轡金鞭垂。", "意氣即歸雙闕舞，雄豪複遣五陵知。", "李相將軍擁薊門，白頭雖老赤心存。", "竟能盡說諸侯入，知有從來天子尊。", "十二年來多戰場，天威已息陣堂堂。", "神靈漢代中興主，功業汾陽異姓王。"]'),
('yuding-11','喜聞盜賊蕃寇總退口號五首','杜甫','唐','御定全唐诗','yuding','','[]','蕭關隴水入官軍，青海黃河卷塞雲。',160,'御定全唐詩/json/230.json','["蕭關隴水入官軍，青海黃河卷塞雲。", "北極轉愁龍虎氣，西戎休縱犬羊群。", "贊普多教使入秦，數通和好止煙塵。", "朝廷忽用哥舒將，殺伐虛悲公主親。", "崆峒西極過昆侖，駝馬由來擁國門。", "逆氣數年吹路斷，蕃人聞道漸星奔。", "勃律天西采玉河，堅昆碧碗最來多。", "舊隨漢使千堆寶，少答胡王萬匹羅。", "今春喜氣滿乾坤，南北東西拱至尊。", "大曆二年調玉燭，玄元皇帝聖雲孫。"]'),
('yuding-12','洞房','杜甫','唐','御定全唐诗','yuding','','[]','洞房環佩冷，玉殿起秋風。秦地應新月，龍池滿舊宮。',48,'御定全唐詩/json/230.json','["洞房環佩冷，玉殿起秋風。秦地應新月，龍池滿舊宮。", "系舟今夜遠，清漏往時同。萬里黃山北，園陵白露中。"]'),
('yuding-13','宿昔','杜甫','唐','御定全唐诗','yuding','','[]','宿昔青門裏，蓬萊仗數移。花嬌迎雜樹，龍喜出平池。',48,'御定全唐詩/json/230.json','["宿昔青門裏，蓬萊仗數移。花嬌迎雜樹，龍喜出平池。", "落日留王母，微風倚少兒。宮中行樂秘，少有外人知。"]'),
('yuding-14','能畫','杜甫','唐','御定全唐诗','yuding','','[]','能畫毛延壽，投壺郭舍人。每蒙天一笑，複似物皆春。',48,'御定全唐詩/json/230.json','["能畫毛延壽，投壺郭舍人。每蒙天一笑，複似物皆春。", "政化平如水，皇恩斷若神。時時用抵戲，亦未雜風塵。"]'),
('yuding-15','鬥雞','杜甫','唐','御定全唐诗','yuding','','[]','鬥雞初賜錦，舞馬既登床。簾下宮人出，樓前禦柳長。',48,'御定全唐詩/json/230.json','["鬥雞初賜錦，舞馬既登床。簾下宮人出，樓前禦柳長。", "仙遊終一閟，女樂久無香。寂寞驪山道，清秋草木黃。"]'),
('yuding-16','鸚鵡','杜甫','唐','御定全唐诗','yuding','','[]','鸚鵡含愁思，聰明憶別離。翠衿渾短盡，紅觜漫多知。',48,'御定全唐詩/json/230.json','["鸚鵡含愁思，聰明憶別離。翠衿渾短盡，紅觜漫多知。", "未有開籠日，空殘舊宿枝。世人憐複損，何用羽毛奇。"]'),
('yuding-17','歷歷','杜甫','唐','御定全唐诗','yuding','','[]','歷歷開元事，分明在眼前。無端盜賊起，忽已歲時遷。',48,'御定全唐詩/json/230.json','["歷歷開元事，分明在眼前。無端盜賊起，忽已歲時遷。", "巫峽西江外，秦城北斗邊。為郎從白首，臥病數秋天。"]'),
('yuding-18','洛陽','杜甫','唐','御定全唐诗','yuding','','[]','洛陽昔陷沒，胡馬犯潼關。天子初愁思，都人慘別顏。',48,'御定全唐詩/json/230.json','["洛陽昔陷沒，胡馬犯潼關。天子初愁思，都人慘別顏。", "清笳去宮闕，翠蓋出關山。故老仍流涕，龍髯幸再攀。"]'),
('yuding-19','驪山','杜甫','唐','御定全唐诗','yuding','','[]','驪山絕望幸，花萼罷登臨。地下無朝燭，人間有賜金。',48,'御定全唐詩/json/230.json','["驪山絕望幸，花萼罷登臨。地下無朝燭，人間有賜金。", "鼎湖龍去遠，銀海雁飛深。萬歲蓬萊日，長懸舊羽林。"]'),
('yuding-20','提封','杜甫','唐','御定全唐诗','yuding','','[]','提封漢天下，萬國尚同心。借問懸車守，何如儉德臨。',48,'御定全唐詩/json/230.json','["提封漢天下，萬國尚同心。借問懸車守，何如儉德臨。", "時征俊乂入，草竊犬羊侵。願戒兵猶火，恩加四海深。"]'),
('yuding-21','覆舟二首','杜甫','唐','御定全唐诗','yuding','','[]','巫峽盤渦曉，黔陽貢物秋。丹砂同隕石，翠羽共沉舟。',96,'御定全唐詩/json/230.json','["巫峽盤渦曉，黔陽貢物秋。丹砂同隕石，翠羽共沉舟。", "羈使空斜影，龍居閟積流。篙工幸不溺，俄頃逐輕鷗。", "竹宮時望拜，桂館或求仙。姹女臨波日，神光照夜年。", "徒聞斬蛟劍，無複爨犀船。使者隨秋色，迢迢獨上天。"]'),
('yuding-22','垂白','杜甫','唐','御定全唐诗','yuding','','[]','垂白馮唐老，清秋宋玉悲。江喧長少睡，樓迥獨移時。',48,'御定全唐詩/json/230.json','["垂白馮唐老，清秋宋玉悲。江喧長少睡，樓迥獨移時。", "多難身何補，無家病不辭。甘從千日醉，未許七哀詩。"]'),
('yuding-23','草閣','杜甫','唐','御定全唐诗','yuding','','[]','草閣臨無地，柴扉永不關。魚龍回夜水，星月動秋山。',48,'御定全唐詩/json/230.json','["草閣臨無地，柴扉永不關。魚龍回夜水，星月動秋山。", "久露清初濕，高雲薄未還。泛舟慚小婦，飄泊損紅顏。"]'),
('yuding-24','江月','杜甫','唐','御定全唐诗','yuding','','[]','江月光于水，高樓思殺人。天邊長作客，老去一沾巾。',48,'御定全唐詩/json/230.json','["江月光于水，高樓思殺人。天邊長作客，老去一沾巾。", "玉露團清影，銀河沒半輪。誰家挑錦字，滅燭翠眉顰。"]'),
('yuding-25','江上','杜甫','唐','御定全唐诗','yuding','','[]','江上日多雨，蕭蕭荊楚秋。高風下木葉，永夜攬貂裘。',48,'御定全唐詩/json/230.json','["江上日多雨，蕭蕭荊楚秋。高風下木葉，永夜攬貂裘。", "勳業頻看鏡，行藏獨倚樓。時危思報主，衰謝不能休。"]'),
('yuding-26','中夜','杜甫','唐','御定全唐诗','yuding','','[]','中夜江山靜，危樓望北辰。長為萬里客，有愧百年身。',48,'御定全唐詩/json/230.json','["中夜江山靜，危樓望北辰。長為萬里客，有愧百年身。", "故國風雲氣，高堂戰伐塵。胡雛負恩澤，嗟爾太平人。"]'),
('yuding-27','江漢','杜甫','唐','御定全唐诗','yuding','','[]','江漢思歸客，乾坤一腐儒。片雲天共遠，永夜月同孤。',48,'御定全唐詩/json/230.json','["江漢思歸客，乾坤一腐儒。片雲天共遠，永夜月同孤。", "落日心猶壯，秋風病欲疏。古來存老馬，不必取長途。"]'),
('yuding-28','白露','杜甫','唐','御定全唐诗','yuding','','[]','白露團甘子，清晨散馬蹄。圃開連石樹，船渡入江溪。',48,'御定全唐詩/json/230.json','["白露團甘子，清晨散馬蹄。圃開連石樹，船渡入江溪。", "憑幾看魚樂，回鞭急鳥棲。漸知秋實美，幽徑恐多蹊。"]'),
('yuding-29','孟氏','杜甫','唐','御定全唐诗','yuding','','[]','孟氏好兄弟，養親唯小園。承顏胝手足，坐客強盤飧。',48,'御定全唐詩/json/230.json','["孟氏好兄弟，養親唯小園。承顏胝手足，坐客強盤飧。", "負米力葵外，讀書秋樹根。卜鄰慚近舍，訓子學誰門。"]'),
('yuding-30','吾宗','杜甫','唐','御定全唐诗','yuding','','[]','吾宗老孫子，質樸古人風。耕鑿安時論，衣冠與世同。',48,'御定全唐詩/json/230.json','["吾宗老孫子，質樸古人風。耕鑿安時論，衣冠與世同。", "在家常早起，憂國願年豐。語及君臣際，經書滿腹中。"]'),
('yuding-31','有歎','杜甫','唐','御定全唐诗','yuding','','[]','壯心久零落，白首寄人間。天下兵常鬥，江東客未還。',48,'御定全唐詩/json/230.json','["壯心久零落，白首寄人間。天下兵常鬥，江東客未還。", "窮猿號雨雪，老馬怯關山。武德開元際，蒼生豈重攀。"]'),
('yuding-32','冬深','杜甫','唐','御定全唐诗','yuding','','[]','花葉隨天意，江溪共石根。早霞隨類影，寒水各依痕。',48,'御定全唐詩/json/230.json','["花葉隨天意，江溪共石根。早霞隨類影，寒水各依痕。", "易下楊朱淚，難招楚客魂。風濤暮不穩，舍棹宿誰門。"]'),
('yuding-33','不寐','杜甫','唐','御定全唐诗','yuding','','[]','瞿塘夜水黑，城內改更籌。翳翳月沉霧，輝輝星近樓。',48,'御定全唐詩/json/230.json','["瞿塘夜水黑，城內改更籌。翳翳月沉霧，輝輝星近樓。", "氣衰甘少寐，心弱恨和愁。多壘滿山谷，桃源無處求。"]'),
('yuding-34','月圓','杜甫','唐','御定全唐诗','yuding','','[]','孤月當樓滿，寒江動夜扉。委波金不定，照席綺逾依。',48,'御定全唐詩/json/230.json','["孤月當樓滿，寒江動夜扉。委波金不定，照席綺逾依。", "未缺空山靜，高懸列宿稀。故園松桂發，萬里共清輝。"]'),
('yuding-35','中宵','杜甫','唐','御定全唐诗','yuding','','[]','西閣百尋餘，中宵步綺疏。飛星過水白，落月動沙虛。',48,'御定全唐詩/json/230.json','["西閣百尋餘，中宵步綺疏。飛星過水白，落月動沙虛。", "擇木知幽鳥，潛波想巨魚。親朋滿天地，兵甲少來書。"]'),
('yuding-36','遣愁','杜甫','唐','御定全唐诗','yuding','','[]','養拙蓬為戶，茫茫何所開。江通神女館，地隔望鄉台。',48,'御定全唐詩/json/230.json','["養拙蓬為戶，茫茫何所開。江通神女館，地隔望鄉台。", "漸惜容顏老，無由弟妹來。兵戈與人事，回首一悲哀。"]'),
('yuding-37','秋清','杜甫','唐','御定全唐诗','yuding','','[]','高秋蘇病氣，白髮自能梳。藥餌憎加減，門庭悶掃除。',48,'御定全唐詩/json/230.json','["高秋蘇病氣，白髮自能梳。藥餌憎加減，門庭悶掃除。", "杖藜還客拜，愛竹遣兒書。十月江平穩，輕舟進所如。"]'),
('yuding-38','傷秋','杜甫','唐','御定全唐诗','yuding','','[]','林僻來人少，山長去鳥微。高秋收畫扇，久客掩荊扉。',72,'御定全唐詩/json/230.json','["林僻來人少，山長去鳥微。高秋收畫扇，久客掩荊扉。", "懶慢頭時櫛，艱難帶減圍。將軍猶汗馬，天子尚戎衣。", "白蔣風飆脆，殷檉曉夜稀。何年減豺虎，似有故園歸。"]'),
('yuding-39','秋峽','杜甫','唐','御定全唐诗','yuding','','[]','江濤萬古峽，肺氣久衰翁。不寐防巴虎，全生狎楚童。',48,'御定全唐詩/json/230.json','["江濤萬古峽，肺氣久衰翁。不寐防巴虎，全生狎楚童。", "衣裳垂素發，門巷落丹楓。常怪商山老，兼存翊贊功。"]'),
('yuding-40','南極','杜甫','唐','御定全唐诗','yuding','','[]','南極青山眾，西江白穀分。古城疏落木，荒戍密寒雲。',72,'御定全唐詩/json/230.json','["南極青山眾，西江白穀分。古城疏落木，荒戍密寒雲。", "歲月蛇常見，風飆虎或聞。近身皆鳥道，殊俗自人群。", "睥睨登哀柝，矛弧照夕曛。亂離多醉尉，愁殺李將軍。"]'),
('yuding-41','搖落','杜甫','唐','御定全唐诗','yuding','','[]','搖落巫山暮，寒江東北流。煙塵多戰鼓，風浪少行舟。',48,'御定全唐詩/json/230.json','["搖落巫山暮，寒江東北流。煙塵多戰鼓，風浪少行舟。", "鵝費羲之墨，貂餘季子裘。長懷報明主，臥病複高秋。"]'),
('yuding-42','耳聾','杜甫','唐','御定全唐诗','yuding','','[]','生年鶡冠子，歎世鹿皮翁。眼複幾時暗，耳從前月聾。',48,'御定全唐詩/json/230.json','["生年鶡冠子，歎世鹿皮翁。眼複幾時暗，耳從前月聾。", "猿鳴秋淚缺，雀噪晚愁空。黃落驚山樹，呼兒問朔風。"]'),
('yuding-43','獨坐二首','杜甫','唐','御定全唐诗','yuding','','[]','竟日雨冥冥，雙崖洗更青。水花寒落岸，山鳥暮過庭。',96,'御定全唐詩/json/230.json','["竟日雨冥冥，雙崖洗更青。水花寒落岸，山鳥暮過庭。", "暖老須燕玉，充饑憶楚萍。胡笳在樓上，哀怨不堪聽。", "白狗斜臨北，黃牛更在東。峽雲常照夜，江月會兼風。", "曬藥安垂老，應門試小童。亦知行不逮，苦恨耳多聾。"]'),
('yuding-44','遠遊','杜甫','唐','御定全唐诗','yuding','','[]','江闊浮高棟，雲長出斷山。塵沙連越巂，風雨暗荊蠻。',48,'御定全唐詩/json/230.json','["江闊浮高棟，雲長出斷山。塵沙連越巂，風雨暗荊蠻。", "雁矯銜蘆內，猿啼失木間。弊裘蘇季子，曆國未知還。"]'),
('yuding-45','夜','杜甫','唐','御定全唐诗','yuding','','[]','露下天高秋水清，空山獨夜旅魂驚。疏燈自照孤帆宿，',40,'御定全唐詩/json/230.json','["露下天高秋水清，空山獨夜旅魂驚。疏燈自照孤帆宿，", "步蟾倚杖看牛鬥，銀漢遙應接鳳城。"]'),
('yuding-46','暮春','杜甫','唐','御定全唐诗','yuding','','[]','臥病擁塞在峽中，瀟湘洞庭虛映空。楚天不斷四時雨，',40,'御定全唐詩/json/230.json','["臥病擁塞在峽中，瀟湘洞庭虛映空。楚天不斷四時雨，", "暮春鴛鷺立洲渚，挾子翻飛還一叢。"]'),
('yuding-47','晴二首','杜甫','唐','御定全唐诗','yuding','','[]','久雨巫山暗，新晴錦繡文。碧知湖外草，紅見海東雲。',96,'御定全唐詩/json/230.json','["久雨巫山暗，新晴錦繡文。碧知湖外草，紅見海東雲。", "竟日鶯相和，摩霄鶴數群。野花幹更落，風處急紛紛。", "啼烏爭引子，鳴鶴不歸林。下食遭泥去，高飛恨久陰。", "雨聲沖塞盡，日氣射江深。回首周南客，驅馳魏闕心。"]'),
('yuding-48','雨','杜甫','唐','御定全唐诗','yuding','','[]','始賀天休雨，還嗟地出雷。驟看浮峽過，密作渡江來。',48,'御定全唐詩/json/230.json','["始賀天休雨，還嗟地出雷。驟看浮峽過，密作渡江來。", "牛馬行無色，蛟龍鬥不開。干戈盛陰氣，未必自陽臺。"]'),
('yuding-49','月三首','杜甫','唐','御定全唐诗','yuding','','[]','斷續巫山雨，天河此夜新。若無青嶂月，愁殺白頭人。',144,'御定全唐詩/json/230.json','["斷續巫山雨，天河此夜新。若無青嶂月，愁殺白頭人。", "魍魎移深樹，蝦蟆動半輪。故園當北斗，直指照西秦。", "並照巫山出，新窺楚水清。羈棲愁裏見，二十四回明。", "必驗升沉體，如知進退情。不違銀漢落，亦伴玉繩橫。", "萬里瞿塘峽，春來六上弦。時時開暗室，故故滿青天。", "爽合風襟靜，高當淚臉懸。南飛有烏鵲，夜久落江邊。"]'),
('yuding-50','雨','杜甫','唐','御定全唐诗','yuding','','[]','萬木雲深隱，連山雨未開。風扉掩不定，水鳥過仍回。',48,'御定全唐詩/json/230.json','["萬木雲深隱，連山雨未開。風扉掩不定，水鳥過仍回。", "鮫館如鳴杼，樵舟豈伐枚。清涼破炎毒，衰意欲登臺。"]'),
('yuding-51','晚晴','杜甫','唐','御定全唐诗','yuding','','[]','返照斜初徹，浮雲薄未歸。江虹明遠飲，峽雨落餘飛。',48,'御定全唐詩/json/230.json','["返照斜初徹，浮雲薄未歸。江虹明遠飲，峽雨落餘飛。", "鳧雁終高去，熊羆覺自肥。秋分客尚在，竹露夕微微。"]'),
('yuding-52','夜雨','杜甫','唐','御定全唐诗','yuding','','[]','小雨夜複密，回風吹早秋。野涼侵閉戶，江滿帶維舟。',48,'御定全唐詩/json/230.json','["小雨夜複密，回風吹早秋。野涼侵閉戶，江滿帶維舟。", "通籍恨多病，為郎忝薄遊。天寒出巫峽，醉別仲宣樓。"]'),
('yuding-53','更題','杜甫','唐','御定全唐诗','yuding','','[]','只應踏初雪，騎馬發荊州。直怕巫山雨，真傷白帝秋。',48,'御定全唐詩/json/230.json','["只應踏初雪，騎馬發荊州。直怕巫山雨，真傷白帝秋。", "群公蒼玉佩，天子翠雲裘。同舍晨趨侍，胡為淹此留。"]'),
('yuding-54','歸','杜甫','唐','御定全唐诗','yuding','','[]','束帶還騎馬，東西卻渡船。林中才有地，峽外絕無天。',48,'御定全唐詩/json/230.json','["束帶還騎馬，東西卻渡船。林中才有地，峽外絕無天。", "虛白高人靜，喧卑俗累牽。他鄉悅遲暮，不敢廢詩篇。"]'),
('yuding-55','返照','杜甫','唐','御定全唐诗','yuding','','[]','楚王宮北正黃昏，白帝城西過雨痕。返照入江翻石壁，',40,'御定全唐詩/json/230.json','["楚王宮北正黃昏，白帝城西過雨痕。返照入江翻石壁，", "不可久留豺虎亂，南方實有未招魂。"]'),
('yuding-56','熱三首','杜甫','唐','御定全唐诗','yuding','','[]','雷霆空霹靂，雲雨竟虛無。炎赫衣流汗，低垂氣不蘇。',144,'御定全唐詩/json/230.json','["雷霆空霹靂，雲雨竟虛無。炎赫衣流汗，低垂氣不蘇。", "乞為寒水玉，願作冷秋菰。何似兒童歲，風涼出舞雩。", "瘴雲終不滅，瀘水複西來。閉戶人高臥，歸林鳥卻回。", "峽中都似火，江上只空雷。想見陰宮雪，風門颯踏開。", "朱李沈不冷，雕胡炊屢新。將衰骨盡痛，被褐味空頻。", "欻翕炎蒸景，飄搖征戍人。十年可解甲，為爾一沾巾。"]'),
('yuding-57','日暮','杜甫','唐','御定全唐诗','yuding','','[]','牛羊下來久，各已閉柴門。風月自清夜，江山非故園。',48,'御定全唐詩/json/230.json','["牛羊下來久，各已閉柴門。風月自清夜，江山非故園。", "石泉流暗壁，草露滴秋根。頭白燈明裏，何須花燼繁。"]'),
('yuding-58','八月十五夜月二首','杜甫','唐','御定全唐诗','yuding','','[]','滿目飛明鏡，歸心折大刀。轉蓬行地遠，攀桂仰天高。',96,'御定全唐詩/json/230.json','["滿目飛明鏡，歸心折大刀。轉蓬行地遠，攀桂仰天高。", "水路疑霜雪，林棲見羽毛。此時瞻白兔，直欲數秋毫。", "稍下巫山峽，猶銜白帝城。氣沈全浦暗，輪仄半樓明。", "刁鬥皆催曉，蟾蜍且自傾。張弓倚殘魄，不獨漢家營。"]'),
('yuding-59','十六夜玩月','杜甫','唐','御定全唐诗','yuding','','[]','舊挹金波爽，皆傳玉露秋。關山隨地闊，河漢近人流。',48,'御定全唐詩/json/230.json','["舊挹金波爽，皆傳玉露秋。關山隨地闊，河漢近人流。", "穀口樵歸唱，孤城笛起愁。巴童渾不寢，半夜有行舟。"]'),
('yuding-60','十七夜對月','杜甫','唐','御定全唐诗','yuding','','[]','秋月仍圓夜，江村獨老身。捲簾還照客，倚杖更隨人。',48,'御定全唐詩/json/230.json','["秋月仍圓夜，江村獨老身。捲簾還照客，倚杖更隨人。", "光射潛虯動，明翻宿鳥頻。茅齋依橘柚，清切露華新。"]'),
('yuding-61','村雨','杜甫','唐','御定全唐诗','yuding','','[]','雨聲傳兩夜，寒事颯高秋。挈帶看朱紱，開箱睹黑裘。',48,'御定全唐詩/json/230.json','["雨聲傳兩夜，寒事颯高秋。挈帶看朱紱，開箱睹黑裘。", "世情只益睡，盜賊敢忘憂。松菊新沾洗，茅齋慰遠遊。"]'),
('yuding-62','雨晴','杜甫','唐','御定全唐诗','yuding','','[]','雨時山不改，晴罷峽如新。天路看殊俗，秋江思殺人。',48,'御定全唐詩/json/230.json','["雨時山不改，晴罷峽如新。天路看殊俗，秋江思殺人。", "有猿揮淚盡，無犬附書頻。故國愁眉外，長歌欲損神。"]'),
('yuding-63','晚晴吳郎見過北舍','杜甫','唐','御定全唐诗','yuding','','[]','圃畦新雨潤，愧子廢鋤來。竹杖交頭拄，柴扉隔徑開。',48,'御定全唐詩/json/230.json','["圃畦新雨潤，愧子廢鋤來。竹杖交頭拄，柴扉隔徑開。", "欲棲群鳥亂，未去小童催。明日重陽酒，相迎自醱醅。"]'),
('yuding-64','暝','杜甫','唐','御定全唐诗','yuding','','[]','日下四山陰，山庭嵐氣侵。牛羊歸徑險，鳥雀聚枝深。',48,'御定全唐詩/json/230.json','["日下四山陰，山庭嵐氣侵。牛羊歸徑險，鳥雀聚枝深。", "正枕當星劍，收書動玉琴。半扉開燭影，欲掩見清砧。"]'),
('yuding-65','雲','杜甫','唐','御定全唐诗','yuding','','[]','龍似瞿唐會，江依白帝深。終年常起峽，每夜必通林。',48,'御定全唐詩/json/230.json','["龍似瞿唐會，江依白帝深。終年常起峽，每夜必通林。", "收穫辭霜渚，分明在夕岑。高齋非一處，秀氣豁煩襟。"]'),
('yuding-66','月','杜甫','唐','御定全唐诗','yuding','','[]','四更山吐月，殘夜水明樓。塵匣元開鏡，風簾自上鉤。',48,'御定全唐詩/json/230.json','["四更山吐月，殘夜水明樓。塵匣元開鏡，風簾自上鉤。", "兔應疑鶴發，蟾亦戀貂裘。斟酌姮娥寡，天寒耐九秋。"]'),
('yuding-67','雨四首','杜甫','唐','御定全唐诗','yuding','','[]','微雨不滑道，斷雲疏複行。紫崖奔處黑，白鳥去邊明。',192,'御定全唐詩/json/230.json','["微雨不滑道，斷雲疏複行。紫崖奔處黑，白鳥去邊明。", "秋日新沾影，寒江舊落聲。柴扉臨野碓，半得搗香粳。", "江雨舊無時，天晴忽散絲。暮秋沾物冷，今日過雲遲。", "上馬迥休出，看鷗坐不辭。高軒當灩澦，潤色靜書帷。", "物色歲將晏，天隅人未歸。朔風鳴淅淅，寒雨下霏霏。", "多病久加飯，衰容新授衣。時危覺凋喪，故舊短書稀。", "楚雨石苔滋，京華消息遲。山寒青兕叫，江晚白鷗饑。", "神女花鈿落，鮫人織杼悲。繁憂不自整，終日灑如絲。"]'),
('yuding-68','夜','杜甫','唐','御定全唐诗','yuding','','[]','絕岸風威動，寒房燭影微。嶺猿霜外宿，江鳥夜深飛。',48,'御定全唐詩/json/230.json','["絕岸風威動，寒房燭影微。嶺猿霜外宿，江鳥夜深飛。", "獨坐親雄劍，哀歌歎短衣。煙塵繞閶闔，白首壯心違。"]'),
('yuding-69','晨雨','杜甫','唐','御定全唐诗','yuding','','[]','小雨晨光內，初來葉上聞。霧交才灑地，風逆旋隨雲。',48,'御定全唐詩/json/230.json','["小雨晨光內，初來葉上聞。霧交才灑地，風逆旋隨雲。", "暫起柴荊色，輕沾鳥獸群。麝香山一半，亭午未全分。"]'),
('yuding-70','返照','杜甫','唐','御定全唐诗','yuding','','[]','返照開巫峽，寒空半有無。已低魚複暗，不盡白鹽孤。',48,'御定全唐詩/json/230.json','["返照開巫峽，寒空半有無。已低魚複暗，不盡白鹽孤。", "荻岸如秋水，松門似畫圖。牛羊識僮僕，既夕應傳呼。"]'),
('yuding-71','向夕','杜甫','唐','御定全唐诗','yuding','','[]','畎畝孤城外，江村亂水中。深山催短景，喬木易高風。',48,'御定全唐詩/json/230.json','["畎畝孤城外，江村亂水中。深山催短景，喬木易高風。", "鶴下雲汀近，雞棲草屋同。琴書散明燭，長夜始堪終。"]'),
('yuding-72','曉望','杜甫','唐','御定全唐诗','yuding','','[]','白帝更聲盡，陽臺曙色分。高峰寒上日，疊嶺宿霾雲。',48,'御定全唐詩/json/230.json','["白帝更聲盡，陽臺曙色分。高峰寒上日，疊嶺宿霾雲。", "地坼江帆隱，天清木葉聞。荊扉對麋鹿，應共爾為群。"]'),
('yuding-73','雷','杜甫','唐','御定全唐诗','yuding','','[]','巫峽中宵動，滄江十月雷。龍蛇不成蟄，天地劃爭回。',48,'御定全唐詩/json/230.json','["巫峽中宵動，滄江十月雷。龍蛇不成蟄，天地劃爭回。", "卻碾空山過，深蟠絕壁來。何須妒雲雨，霹靂楚王台。"]'),
('yuding-74','雨','杜甫','唐','御定全唐诗','yuding','','[]','冥冥甲子雨，已度立春時。輕箑煩相向，纖絺恐自疑。',48,'御定全唐詩/json/230.json','["冥冥甲子雨，已度立春時。輕箑煩相向，纖絺恐自疑。", "煙添才有色，風引更如絲。直覺巫山暮，兼催宋玉悲。"]'),
('yuding-75','朝二首','杜甫','唐','御定全唐诗','yuding','','[]','清旭楚宮南，霜空萬嶺含。野人時獨往，雲木曉相參。',96,'御定全唐詩/json/230.json','["清旭楚宮南，霜空萬嶺含。野人時獨往，雲木曉相參。", "俊鶻無聲過，饑烏下食貪。病身終不動，搖落任江潭。", "浦帆晨初發，郊扉冷未開。村疏黃葉墜，野靜白鷗來。", "礎潤休全濕，雲晴欲半回。巫山冬可怪，昨夜有奔雷。"]'),
('yuding-76','晚','杜甫','唐','御定全唐诗','yuding','','[]','杖藜尋晚巷，炙背近牆暄。人見幽居僻，吾知拙養尊。',48,'御定全唐詩/json/230.json','["杖藜尋晚巷，炙背近牆暄。人見幽居僻，吾知拙養尊。", "朝廷問府主，耕稼學山村。歸翼飛棲定，寒燈亦閉門。"]'),
('yuding-77','夜二首','杜甫','唐','御定全唐诗','yuding','','[]','白夜月休弦，燈花半委眠。號山無定鹿，落樹有驚蟬。',96,'御定全唐詩/json/230.json','["白夜月休弦，燈花半委眠。號山無定鹿，落樹有驚蟬。", "暫憶江東鱠，兼懷雪下船。蠻歌犯星起，空覺在天邊。", "城郭悲笳暮，村墟過翼稀。甲兵年數久，賦斂夜深歸。", "暗樹依岩落，明河繞塞微。鬥斜人更望，月細鵲休飛。"]'),
('yuding-0','宗武生日','杜甫','唐','御定全唐诗','yuding','','[]','小子何時見，高秋此日生。自從都邑語，已伴老夫名。',72,'御定全唐詩/json/231.json','["小子何時見，高秋此日生。自從都邑語，已伴老夫名。", "詩是吾家事，人傳世上情。熟精文選理，休覓彩衣輕。", "凋瘵筵初秩，欹斜坐不成。流霞分片片，涓滴就徐傾。"]'),
('yuding-1','又示宗武','杜甫','唐','御定全唐诗','yuding','','[]','覓句新知律，攤書解滿床。試吟青玉案，莫羨紫羅囊。',72,'御定全唐詩/json/231.json','["覓句新知律，攤書解滿床。試吟青玉案，莫羨紫羅囊。", "假日從時飲，明年共我長。應須飽經術，已似愛文章。", "十五男兒志，三千弟子行。曾參與游夏，達者得升堂。"]'),
('yuding-2','熟食日示宗文、宗武','杜甫','唐','御定全唐诗','yuding','','[]','消渴游江漢，羈棲尚甲兵。幾年逢熟食，萬里逼清明。',48,'御定全唐詩/json/231.json','["消渴游江漢，羈棲尚甲兵。幾年逢熟食，萬里逼清明。", "松柏邛山路，風花白帝城。汝曹催我老，回首淚縱橫。"]'),
('yuding-3','又示兩兒','杜甫','唐','御定全唐诗','yuding','','[]','令節成吾老，他時見汝心。浮生看物變，為恨與年深。',48,'御定全唐詩/json/231.json','["令節成吾老，他時見汝心。浮生看物變，為恨與年深。", "長葛書難得，江州涕不禁。團圓思弟妹，行坐白頭吟。"]'),
('yuding-4','社日兩篇','杜甫','唐','御定全唐诗','yuding','','[]','九農成德業，百祀發光輝。報效神如在，馨香舊不違。',96,'御定全唐詩/json/231.json','["九農成德業，百祀發光輝。報效神如在，馨香舊不違。", "南翁巴曲醉，北雁塞聲微。尚想東方朔，詼諧割肉歸。", "陳平亦分肉，太史竟論功。今日江南老，他時渭北童。", "歡娛看絕塞，涕淚落秋風。鴛鷺回金闕，誰憐病峽中。"]'),
('yuding-5','九日五首','杜甫','唐','御定全唐诗','yuding','','[]','重陽獨酌杯中酒，抱病起登江上臺。竹葉於人既無分，',208,'御定全唐詩/json/231.json','["重陽獨酌杯中酒，抱病起登江上臺。竹葉於人既無分，", "弟妹蕭條各何往，干戈衰謝兩相催。", "舊日重陽日，傳杯不放杯。即今蓬鬢改，但愧菊花開。", "北闕心長戀，西江首獨回。茱萸賜朝士，難得一枝來。", "舊與蘇司業，兼隨鄭廣文。采花香泛泛，坐客醉紛紛。", "野樹歌還倚，秋砧醒卻聞。歡娛兩冥漠，西北有孤雲。", "故里樊川菊，登高素滻源。他時一笑後，今日幾人存。", "巫峽蟠江路，終南對國門。系舟身萬里，伏枕淚雙痕。", "為客裁烏帽，從兒具綠尊。佳辰對群盜，愁絕更誰論。"]'),
('yuding-6','九日諸人集于林','杜甫','唐','御定全唐诗','yuding','','[]','九日明朝是，相要舊俗非。老翁難早出，賢客幸知歸。',48,'御定全唐詩/json/231.json','["九日明朝是，相要舊俗非。老翁難早出，賢客幸知歸。", "舊采黃花剩，新梳白髮微。漫看年少樂，忍淚已沾衣。"]'),
('yuding-7','大曆二年九月三十日','杜甫','唐','御定全唐诗','yuding','','[]','為客無時了，悲秋向夕終。瘴餘夔子國，霜薄楚王宮。',48,'御定全唐詩/json/231.json','["為客無時了，悲秋向夕終。瘴餘夔子國，霜薄楚王宮。", "草敵虛嵐翠，花禁冷葉紅。年年小搖落，不與故園同。"]'),
('yuding-8','十月一日','杜甫','唐','御定全唐诗','yuding','','[]','有瘴非全歇，為冬亦不難。夜郎溪日暖，白帝峽風寒。',48,'御定全唐詩/json/231.json','["有瘴非全歇，為冬亦不難。夜郎溪日暖，白帝峽風寒。", "蒸裹如千室，焦糟幸一柈。茲辰南國重，舊俗自相歡。"]'),
('yuding-9','孟冬','杜甫','唐','御定全唐诗','yuding','','[]','殊俗還多事，方冬變所為。破甘霜落爪，嘗稻雪翻匙。',48,'御定全唐詩/json/231.json','["殊俗還多事，方冬變所為。破甘霜落爪，嘗稻雪翻匙。", "巫峽寒都薄，烏蠻瘴遠隨。終然減灘瀨，暫喜息蛟螭。"]'),
('yuding-10','冬至','杜甫','唐','御定全唐诗','yuding','','[]','年年至日長為客，忽忽窮愁泥殺人。江上形容吾獨老，',40,'御定全唐詩/json/231.json','["年年至日長為客，忽忽窮愁泥殺人。江上形容吾獨老，", "心折此時無一寸，路迷何處見三秦。"]'),
('yuding-11','小至','杜甫','唐','御定全唐诗','yuding','','[]','天時人事日相催，冬至陽生春又來。刺繡五紋添弱線，',40,'御定全唐詩/json/231.json','["天時人事日相催，冬至陽生春又來。刺繡五紋添弱線，", "雲物不殊鄉國異，教兒且覆掌中杯。"]'),
('yuding-12','覽物','杜甫','唐','御定全唐诗','yuding','','[]','曾為掾吏趨三輔，憶在潼關詩興多。巫峽忽如瞻華嶽，',40,'御定全唐詩/json/231.json','["曾為掾吏趨三輔，憶在潼關詩興多。巫峽忽如瞻華嶽，", "形勝有餘風土惡，幾時回首一高歌。"]'),
('yuding-13','憶鄭南玭','杜甫','唐','御定全唐诗','yuding','','[]','鄭南伏毒寺，瀟灑到江心。石影銜珠閣，泉聲帶玉琴。',48,'御定全唐詩/json/231.json','["鄭南伏毒寺，瀟灑到江心。石影銜珠閣，泉聲帶玉琴。", "風杉曾曙倚，雲嶠憶春臨。萬里滄浪外，龍蛇只自深。"]'),
('yuding-14','懷灞上游','杜甫','唐','御定全唐诗','yuding','','[]','悵望東陵道，平生灞上游。春濃停野騎，夜宿敞雲樓。',48,'御定全唐詩/json/231.json','["悵望東陵道，平生灞上游。春濃停野騎，夜宿敞雲樓。", "離別人誰在，經過老自休。眼前今古意，江漢一歸舟。"]'),
('yuding-15','愁','杜甫','唐','御定全唐诗','yuding','','[]','江草日日喚愁生，巫峽泠泠非世情。盤渦鷺浴底心性，',40,'御定全唐詩/json/231.json','["江草日日喚愁生，巫峽泠泠非世情。盤渦鷺浴底心性，", "渭水秦山得見否，人經罷病虎縱橫。"]'),
('yuding-16','晝夢','杜甫','唐','御定全唐诗','yuding','','[]','二月饒睡昏昏然，不獨夜短晝分眠。桃花氣暖眼自醉，',40,'御定全唐詩/json/231.json','["二月饒睡昏昏然，不獨夜短晝分眠。桃花氣暖眼自醉，", "安得務農息戰鬥，普天無吏橫索錢。"]'),
('yuding-17','覽鏡呈柏中丞','杜甫','唐','御定全唐诗','yuding','','[]','渭水流關內，終南在日邊。膽銷豺虎窟，淚入犬羊天。',48,'御定全唐詩/json/231.json','["渭水流關內，終南在日邊。膽銷豺虎窟，淚入犬羊天。", "起晚堪從事，行遲更學仙。鏡中衰謝色，萬一故人憐。"]'),
('yuding-18','即事','杜甫','唐','御定全唐诗','yuding','','[]','暮春三月巫峽長，皛皛行雲浮日光。雷聲忽送千峰雨，',40,'御定全唐詩/json/231.json','["暮春三月巫峽長，皛皛行雲浮日光。雷聲忽送千峰雨，", "飛閣捲簾圖畫裏，虛無只少對瀟湘。"]'),
('yuding-19','即事','杜甫','唐','御定全唐诗','yuding','','[]','天畔群山孤草亭，江中風浪雨冥冥。一雙白魚不受釣，',40,'御定全唐詩/json/231.json','["天畔群山孤草亭，江中風浪雨冥冥。一雙白魚不受釣，", "未聞細柳散金甲，腸斷秦川流濁涇。"]'),
('yuding-20','悶','杜甫','唐','御定全唐诗','yuding','','[]','瘴癘浮三蜀，風雲暗百蠻。捲簾唯白水，隱幾亦青山。',48,'御定全唐詩/json/231.json','["瘴癘浮三蜀，風雲暗百蠻。捲簾唯白水，隱幾亦青山。", "猿捷長難見，鷗輕故不還。無錢從滯客，有鏡巧催顏。"]'),
('yuding-21','戲作俳諧體遣悶二首','杜甫','唐','御定全唐诗','yuding','','[]','異俗籲可怪，斯人難並居。家家養烏鬼，頓頓食黃魚。',96,'御定全唐詩/json/231.json','["異俗籲可怪，斯人難並居。家家養烏鬼，頓頓食黃魚。", "舊識能為態，新知已暗疏。治生且耕鑿，只有不關渠。", "西曆青羌板，南留白帝城。於菟侵客恨，粔籹作人情。", "瓦蔔傳神語，畬田費火聲。是非何處定，高枕笑浮生。"]'),
('yuding-22','得舍弟觀書自中都已達江陵今茲暮春月末行李合到夔州悲喜相兼團圓可待賦詩即事情見乎詞','杜甫','唐','御定全唐诗','yuding','','[]','爾到江陵府，何時到峽州。亂難生有別，聚集病應瘳。',48,'御定全唐詩/json/231.json','["爾到江陵府，何時到峽州。亂難生有別，聚集病應瘳。", "颯颯開啼眼，朝朝上水樓。老身須付託，白骨更何憂。"]'),
('yuding-23','喜觀即到，複題短篇二首','杜甫','唐','御定全唐诗','yuding','','[]','巫峽千山暗，終南萬里春。病中吾見弟，書到汝為人。',96,'御定全唐詩/json/231.json','["巫峽千山暗，終南萬里春。病中吾見弟，書到汝為人。", "意答兒童問，來經戰伐新。泊船悲喜後，款款話歸秦。", "待爾嗔烏鵲，拋書示鶺鴒。枝間喜不去，原上急曾經。", "江閣嫌津柳，風帆數驛亭。應論十年事，愁絕始星星。"]'),
('yuding-24','舍弟觀歸藍田迎新婦，送示兩篇','杜甫','唐','御定全唐诗','yuding','','[]','汝去迎妻子，高秋念卻回。即今螢已亂，好與雁同來。',96,'御定全唐詩/json/231.json','["汝去迎妻子，高秋念卻回。即今螢已亂，好與雁同來。", "東望西江水，南遊北戶開。卜居期靜處，會有故人杯。", "楚塞難為路，藍田莫滯留。衣裳判白露，鞍馬信清秋。", "滿峽重江水，開帆八月舟。此時同一醉，應在仲宣樓。"]'),
('yuding-25','第五弟豐獨在江左，近三四載寂無消息，覓使寄此二首','杜甫','唐','御定全唐诗','yuding','','[]','亂後嗟吾在，羈棲見汝難。草黃騏驥病，沙晚鶺鴒寒。',96,'御定全唐詩/json/231.json','["亂後嗟吾在，羈棲見汝難。草黃騏驥病，沙晚鶺鴒寒。", "楚設關城險，吳吞水府寬。十年朝夕淚，衣袖不曾幹。", "聞汝依山寺，杭州定越州。風塵淹別日，江漢失清秋。", "影蓋啼猿樹，魂飄結蜃樓。明年下春水，東盡白雲求。"]'),
('yuding-26','舍弟觀赴藍田取妻子到江陵，喜寄三首','杜甫','唐','御定全唐诗','yuding','','[]','汝迎妻子達荊州，消息真傳解我憂。鴻雁影來連峽內，',120,'御定全唐詩/json/231.json','["汝迎妻子達荊州，消息真傳解我憂。鴻雁影來連峽內，", "朱紱即當隨彩鷁，青春不假報黃牛。", "馬度秦關雪正深，北來肌骨苦寒侵。他鄉就我生春色，", "巡簷索共梅花笑，冷蕊疏枝半不禁。", "庾信羅含俱有宅，春來秋去作誰家。短牆若在從殘草，", "比年病酒開涓滴，弟勸兄酬何怨嗟。"]'),
('yuding-27','江雨有懷鄭典設','杜甫','唐','御定全唐诗','yuding','','[]','春雨暗暗塞峽中，早晚來自楚王宮。亂波分披已打岸，',40,'御定全唐詩/json/231.json','["春雨暗暗塞峽中，早晚來自楚王宮。亂波分披已打岸，", "穀口子真正憶汝，岸高瀼滑限西東。"]'),
('yuding-28','王十五前閣會','杜甫','唐','御定全唐诗','yuding','','[]','楚岸收新雨，春台引細風。情人來石上，鮮膾出江中。',48,'御定全唐詩/json/231.json','["楚岸收新雨，春台引細風。情人來石上，鮮膾出江中。", "鄰舍煩書劄，肩輿強老翁。病身虛俊味，何幸飫兒童。"]'),
('yuding-29','寄韋有夏郎中','杜甫','唐','御定全唐诗','yuding','','[]','省郎憂病士，書信有柴胡。飲子頻通汗，懷君想報珠。',72,'御定全唐詩/json/231.json','["省郎憂病士，書信有柴胡。飲子頻通汗，懷君想報珠。", "親知天畔少，藥味峽中無。歸楫生衣臥，春鷗洗翅呼。", "猶聞上急水，早作取平途。萬里皇華使，為僚記腐儒。"]'),
('yuding-30','陪柏中丞觀宴將士二首','杜甫','唐','御定全唐诗','yuding','','[]','極樂三軍士，誰知百戰場。無私齊綺饌，久坐密金章。',96,'御定全唐詩/json/231.json','["極樂三軍士，誰知百戰場。無私齊綺饌，久坐密金章。", "醉客沾鸚鵡，佳人指鳳凰。幾時來翠節，特地引紅妝。", "繡段裝簷額，金花帖鼓腰。一夫先舞劍，百戲後歌樵。", "江樹城孤遠，雲台使寂寥。漢朝頻選將，應拜霍嫖姚。"]'),
('yuding-31','七月一日題終明府水樓二首','杜甫','唐','御定全唐诗','yuding','','[]','高棟曾軒已自涼，秋風此日灑衣裳。翛然欲下陰山雪，',80,'御定全唐詩/json/231.json','["高棟曾軒已自涼，秋風此日灑衣裳。翛然欲下陰山雪，", "看君宜著王喬履，真賜還疑出尚方。", "宓子彈琴邑宰日，終軍棄繻英妙時。承家節操尚不泯，", "楚江巫峽半雲雨，清簟疏簾看弈棋。"]'),
('yuding-32','季秋蘇五弟纓江樓夜宴崔十三評事、韋少府侄三首','杜甫','唐','御定全唐诗','yuding','','[]','峽險江驚急，樓高月迥明。一時今夕會，萬里故鄉情。',144,'御定全唐詩/json/231.json','["峽險江驚急，樓高月迥明。一時今夕會，萬里故鄉情。", "星落黃姑渚，秋辭白帝城。老人因酒病，堅坐看君傾。", "明月生長好，浮雲薄漸遮。悠悠照邊塞，悄悄憶京華。", "清動杯中物，高隨海上查。不眠瞻白兔，百過落烏紗。", "對月那無酒，登樓況有江。聽歌驚白鬢，笑舞拓秋窗。", "尊蟻添相續，沙鷗並一雙。盡憐君醉倒，更覺片心降。"]'),
('yuding-33','九月一日過孟十二倉曹、十四主簿兄弟','杜甫','唐','御定全唐诗','yuding','','[]','藜杖侵寒露，蓬門啟曙煙。力稀經樹歇，老困撥書眠。',48,'御定全唐詩/json/231.json','["藜杖侵寒露，蓬門啟曙煙。力稀經樹歇，老困撥書眠。", "秋覺追隨盡，來因孝友偏。清談見滋味，爾輩可忘年。"]'),
('yuding-34','過客相尋','杜甫','唐','御定全唐诗','yuding','','[]','窮老真無事，江山已定居。地幽忘盥櫛，客至罷琴書。',48,'御定全唐詩/json/231.json','["窮老真無事，江山已定居。地幽忘盥櫛，客至罷琴書。", "掛壁移筐果，呼兒問煮魚。時聞系舟楫，及此問吾廬。"]'),
('yuding-35','孟倉曹步趾領新酒醬二物滿器見遺老夫','杜甫','唐','御定全唐诗','yuding','','[]','楚岸通秋屐，胡床面夕畦。藉糟分汁滓，甕醬落提攜。',48,'御定全唐詩/json/231.json','["楚岸通秋屐，胡床面夕畦。藉糟分汁滓，甕醬落提攜。", "飯糲添香味，朋來有醉泥。理生那免俗，方法報山妻。"]'),
('yuding-36','柳司馬至','杜甫','唐','御定全唐诗','yuding','','[]','有使歸三峽，相過問兩京。函關猶出將，渭水更屯兵。',72,'御定全唐詩/json/231.json','["有使歸三峽，相過問兩京。函關猶出將，渭水更屯兵。", "設備邯鄲道，和親邏些城。幽燕唯鳥去，商洛少人行。", "衰謝身何補，蕭條病轉嬰。霜天到宮闕，戀主寸心明。"]'),
('yuding-37','簡吳郎司法','杜甫','唐','御定全唐诗','yuding','','[]','有客乘舸自忠州，遣騎安置瀼西頭。古堂本買藉疏豁，',40,'御定全唐詩/json/231.json','["有客乘舸自忠州，遣騎安置瀼西頭。古堂本買藉疏豁，", "卻為姻婭過逢地，許坐曾軒數散愁。"]'),
('yuding-38','又呈吳郎','杜甫','唐','御定全唐诗','yuding','','[]','堂前撲棗任西鄰，無食無兒一婦人。不為困窮寧有此，',40,'御定全唐詩/json/231.json','["堂前撲棗任西鄰，無食無兒一婦人。不為困窮寧有此，", "已訴徵求貧到骨，正思戎馬淚盈巾。"]'),
('yuding-39','覃山人隱居','杜甫','唐','御定全唐诗','yuding','','[]','南極老人自有星，北山移文誰勒銘。征君已去獨松菊，',40,'御定全唐詩/json/231.json','["南極老人自有星，北山移文誰勒銘。征君已去獨松菊，", "高車駟馬帶傾覆，悵望秋天虛翠屏。"]'),
('yuding-40','柏學士茅屋','杜甫','唐','御定全唐诗','yuding','','[]','碧山學士焚銀魚，白馬卻走身岩居。古人已用三冬足，',40,'御定全唐詩/json/231.json','["碧山學士焚銀魚，白馬卻走身岩居。古人已用三冬足，", "富貴必從勤苦得，男兒須讀五車書。"]'),
('yuding-41','題柏大兄弟山居屋壁二首','杜甫','唐','御定全唐诗','yuding','','[]','叔父朱門貴，郎君玉樹高。山居精典籍，文雅涉風騷。',96,'御定全唐詩/json/231.json','["叔父朱門貴，郎君玉樹高。山居精典籍，文雅涉風騷。", "江漢終吾老，雲林得爾曹。哀弦繞白雪，未與俗人操。", "野屋流寒水，山籬帶薄雲。靜應連虎穴，喧已去人群。", "筆架沾窗雨，書簽映隙曛。蕭蕭千里足，個個五花文。"]'),
('yuding-42','戲寄崔評事表侄、蘇五表弟、韋大少府諸侄','杜甫','唐','御定全唐诗','yuding','','[]','隱豹深愁雨，潛龍故起雲。泥多仍徑曲，心醉阻賢群。',48,'御定全唐詩/json/231.json','["隱豹深愁雨，潛龍故起雲。泥多仍徑曲，心醉阻賢群。", "忍待江山麗，還披鮑謝文。高樓憶疏豁，秋興坐氛氳。"]'),
('yuding-43','秋日寄題鄭監湖上亭三首','杜甫','唐','御定全唐诗','yuding','','[]','碧草逢春意，沅湘萬里秋。池要山簡馬，月淨庾公樓。',144,'御定全唐詩/json/231.json','["碧草逢春意，沅湘萬里秋。池要山簡馬，月淨庾公樓。", "磨滅餘篇翰，平生一釣舟。高唐寒浪減，仿佛識昭丘。", "新作湖邊宅，遠聞賓客過。自須開竹徑，誰道避雲蘿。", "官序潘生拙，才名賈傅多。舍舟應轉地，鄰接意如何。", "暫阻蓬萊閣，終為江海人。揮金應物理，拖玉豈吾身。", "羹煮秋蓴滑，杯迎露菊新。賦詩分氣象，佳句莫頻頻。"]'),
('yuding-44','謁真諦寺禪師','杜甫','唐','御定全唐诗','yuding','','[]','蘭若山高處，煙霞嶂幾重。凍泉依細石，晴雪落長松。',48,'御定全唐詩/json/231.json','["蘭若山高處，煙霞嶂幾重。凍泉依細石，晴雪落長松。", "問法看詩忘，觀身向酒慵。未能割妻子，卜宅近前峰。"]'),
('yuding-45','別崔潩因寄薛據、孟雲卿','杜甫','唐','御定全唐诗','yuding','','[]','志士惜妄動，知深難固辭。如何久磨礪，但取不磷緇。',48,'御定全唐詩/json/231.json','["志士惜妄動，知深難固辭。如何久磨礪，但取不磷緇。", "夙夜聽憂主，飛騰急濟時。荊州過薛孟，為報欲論詩。"]'),
('yuding-46','送李八秘書赴杜相公幕','杜甫','唐','御定全唐诗','yuding','','[]','青簾白舫益州來，巫峽秋濤天地回。石出倒聽楓葉下，',40,'御定全唐詩/json/231.json','["青簾白舫益州來，巫峽秋濤天地回。石出倒聽楓葉下，", "南極一星朝北斗，五雲多處是三台。"]'),
('yuding-47','巫峽敝廬奉贈侍禦四舅別之澧朗','杜甫','唐','御定全唐诗','yuding','','[]','江城秋日落，山鬼閉門中。行李淹吾舅，誅茅問老翁。',48,'御定全唐詩/json/231.json','["江城秋日落，山鬼閉門中。行李淹吾舅，誅茅問老翁。", "赤眉猶世亂，青眼只途窮。傳語桃源客，人今出處同。"]'),
('yuding-48','奉送十七舅下邵桂','杜甫','唐','御定全唐诗','yuding','','[]','絕域三冬暮，浮生一病身。感深辭舅氏，別後見何人。',48,'御定全唐詩/json/231.json','["絕域三冬暮，浮生一病身。感深辭舅氏，別後見何人。", "縹緲蒼梧帝，推遷孟母鄰。昏昏阻雲水，側望苦傷神。"]'),
('yuding-49','送覃二判官','杜甫','唐','御定全唐诗','yuding','','[]','先帝弓劍遠，小臣餘此生。蹉跎病江漢，不復謁承明。',72,'御定全唐詩/json/231.json','["先帝弓劍遠，小臣餘此生。蹉跎病江漢，不復謁承明。", "餞爾白頭日，永懷丹鳳城。遲遲戀屈宋，渺渺臥荊衡。", "魂斷航舸失，天寒沙水清。肺肝若稍愈，亦上赤霄行。"]'),
('yuding-50','季夏送鄉弟韶陪黃門從叔朝謁','杜甫','唐','御定全唐诗','yuding','','[]','令弟尚為蒼水使，名家莫出杜陵人。比來相國兼安蜀，',40,'御定全唐詩/json/231.json','["令弟尚為蒼水使，名家莫出杜陵人。比來相國兼安蜀，", "莫度清秋吟蟋蟀，早聞黃閣畫麒麟。"]'),
('yuding-51','送十五弟侍禦使蜀','杜甫','唐','御定全唐诗','yuding','','[]','喜弟文章進，添餘別興牽。數杯巫峽酒，百丈內江船。',48,'御定全唐詩/json/231.json','["喜弟文章進，添餘別興牽。數杯巫峽酒，百丈內江船。", "未息豺狼鬥，空催犬馬年。歸朝多便道，搏擊望秋天。"]'),
('yuding-52','送田四弟將軍將夔州柏中丞命起居江陵節度陽城郡王衛公幕','杜甫','唐','御定全唐诗','yuding','','[]','離筵罷多酒，起地發寒塘。回首中丞座，馳箋異姓王。',48,'御定全唐詩/json/231.json','["離筵罷多酒，起地發寒塘。回首中丞座，馳箋異姓王。", "燕辭楓樹日，雁度麥城霜。空醉山翁酒，遙憐似葛強。"]'),
('yuding-53','送王十六判官','杜甫','唐','御定全唐诗','yuding','','[]','客下荊南盡，君今複入舟。買薪猶白帝，鳴櫓少沙頭。',48,'御定全唐詩/json/231.json','["客下荊南盡，君今複入舟。買薪猶白帝，鳴櫓少沙頭。", "衡霍生春早，瀟湘共海浮。荒林庾信宅，為仗主人留。"]'),
('yuding-54','奉送卿二翁統節度鎮軍還江陵','杜甫','唐','御定全唐诗','yuding','','[]','火旗還錦纜，白馬出江城。嘹唳吟笳發，蕭條別浦清。',48,'御定全唐詩/json/231.json','["火旗還錦纜，白馬出江城。嘹唳吟笳發，蕭條別浦清。", "寒空巫峽曙，落日渭陽明。留滯嗟衰疾，何時見息兵。"]'),
('yuding-55','送鮮于萬州遷巴州','杜甫','唐','御定全唐诗','yuding','','[]','京兆先時傑，琳琅照一門。朝廷偏注意，接近與名藩。',48,'御定全唐詩/json/231.json','["京兆先時傑，琳琅照一門。朝廷偏注意，接近與名藩。", "祖帳排舟數，寒江觸石喧。看君妙為政，他日有殊恩。"]'),
('yuding-56','寄杜位','杜甫','唐','御定全唐诗','yuding','','[]','寒日經簷短，窮猿失木悲。峽中為客恨，江上憶君時。',48,'御定全唐詩/json/231.json','["寒日經簷短，窮猿失木悲。峽中為客恨，江上憶君時。", "天地身何在，風塵病敢辭。封書兩行淚，沾灑裛新詩。"]'),
('yuding-57','奉寄李十五秘書二首','杜甫','唐','御定全唐诗','yuding','','[]','避暑雲安縣，秋風早下來。暫留魚複浦，同過楚王台。',96,'御定全唐詩/json/231.json','["避暑雲安縣，秋風早下來。暫留魚複浦，同過楚王台。", "猿鳥千崖窄，江湖萬里開。竹枝歌未好，畫舸莫遲回。", "行李千金贈，衣冠八尺身。飛騰知有策，意度不無神。", "班秩兼通貴，公侯出異人。玄成負文彩，世業豈沉淪。"]'),
('yuding-58','奉送韋中丞之晉赴湖南','杜甫','唐','御定全唐诗','yuding','','[]','寵渥征黃漸，權宜借寇頻。湖南安背水，峽內憶行春。',48,'御定全唐詩/json/231.json','["寵渥征黃漸，權宜借寇頻。湖南安背水，峽內憶行春。", "王室仍多故，蒼生倚大臣。還將徐孺子，處處待高人。"]'),
('yuding-59','送李功曹之荊州充鄭侍禦判官重贈','杜甫','唐','御定全唐诗','yuding','','[]','曾聞宋玉宅，每欲到荊州。此地生涯晚，遙悲水國秋。',48,'御定全唐詩/json/231.json','["曾聞宋玉宅，每欲到荊州。此地生涯晚，遙悲水國秋。", "孤城一柱觀，落日九江流。使者雖光彩，青楓遠自愁。"]'),
('yuding-60','送孟十二倉曹赴東京選','杜甫','唐','御定全唐诗','yuding','','[]','君行別老親，此去苦家貧。藻鏡留連客，江山憔悴人。',48,'御定全唐詩/json/231.json','["君行別老親，此去苦家貧。藻鏡留連客，江山憔悴人。", "秋風楚竹冷，夜雪鞏梅春。朝夕高堂念，應宜彩服新。"]'),
('yuding-61','憑孟倉曹將書覓土婁舊莊','杜甫','唐','御定全唐诗','yuding','','[]','平居喪亂後，不到洛陽岑。為曆雲山問，無辭荊棘深。',48,'御定全唐詩/json/231.json','["平居喪亂後，不到洛陽岑。為曆雲山問，無辭荊棘深。", "北風黃葉下，南浦白頭吟。十載江湖客，茫茫遲暮心。"]'),
('yuding-62','別蘇徯','杜甫','唐','御定全唐诗','yuding','','[]','故人有遊子，棄擲傍天隅。他日憐才命，居然屈壯圖。',120,'御定全唐詩/json/231.json','["故人有遊子，棄擲傍天隅。他日憐才命，居然屈壯圖。", "十年猶塌翼，絕倒為驚籲。消渴今如在，提攜愧老夫。", "豈知台閣舊，先拂鳳凰雛。得實翻蒼竹，棲枝把翠梧。", "北辰當宇宙，南嶽據江湖。國帶風塵色，兵張虎豹符。", "數論封內事，揮發府中趨。贈爾秦人策，莫鞭轅下駒。"]'),
('yuding-63','存歿口號二首','杜甫','唐','御定全唐诗','yuding','','[]','席謙不見近彈棋，畢曜仍傳舊小詩。',64,'御定全唐詩/json/231.json','["席謙不見近彈棋，畢曜仍傳舊小詩。", "玉局他年無限笑，白楊今日幾人悲。", "鄭公粉繪隨長夜，曹霸丹青已白頭。", "天下何曾有山水，人間不解重驊騮。"]'),
('yuding-64','奉漢中王手劄報韋侍禦、蕭尊師亡','杜甫','唐','御定全唐诗','yuding','','[]','秋日蕭韋逝，淮王報峽中。少年疑柱史，多術怪仙公。',72,'御定全唐詩/json/231.json','["秋日蕭韋逝，淮王報峽中。少年疑柱史，多術怪仙公。", "不但時人惜，只應吾道窮。一哀侵疾病，相識自兒童。", "處處鄰家笛，飄飄客子蓬。強吟懷舊賦，已作白頭翁。"]'),
('yuding-65','哭王彭州掄','杜甫','唐','御定全唐诗','yuding','','[]','執友驚淪沒，斯人已寂寥。新文生沈謝，異骨降松喬。',240,'御定全唐詩/json/231.json','["執友驚淪沒，斯人已寂寥。新文生沈謝，異骨降松喬。", "北部初高選，東堂早見招。蛟龍纏倚劍，鸞鳳夾吹簫。", "曆職漢庭久，中年胡馬驕。兵戈闇兩觀，寵辱事三朝。", "蜀路江幹窄，彭門地裏遙。解龜生碧草，諫獵阻清霄。", "頃壯戎麾出，叨陪幕府要。將軍臨氣候，猛士塞風飆。", "井漏泉誰汲，烽疏火不燒。前籌自多暇，隱幾接終朝。", "翠石俄雙表，寒松竟後凋。贈詩焉敢墜，染翰欲無聊。", "再哭經過罷，離魂去住銷。之官方玉折，寄葬與萍漂。", "曠望渥窪道，霏微河漢橋。夫人先即世，令子各清標。", "巫峽長雲雨，秦城近鬥杓。馮唐毛髮白，歸興日蕭蕭。"]'),
('yuding-66','見螢火','杜甫','唐','御定全唐诗','yuding','','[]','巫山秋夜螢火飛，簾疏巧入坐人衣。忽驚屋裏琴書冷，',40,'御定全唐詩/json/231.json','["巫山秋夜螢火飛，簾疏巧入坐人衣。忽驚屋裏琴書冷，", "滄江白發愁看汝，來歲如今歸未歸。"]'),
('yuding-67','吹笛','杜甫','唐','御定全唐诗','yuding','','[]','吹笛秋山風月清，誰家巧作斷腸聲。風飄律呂相和切，',40,'御定全唐詩/json/231.json','["吹笛秋山風月清，誰家巧作斷腸聲。風飄律呂相和切，", "故園楊柳今搖落，何得愁中曲盡生。"]'),
('yuding-68','孤雁','杜甫','唐','御定全唐诗','yuding','','[]','孤雁不飲啄，飛鳴聲念群。誰憐一片影，相失萬重雲。',48,'御定全唐詩/json/231.json','["孤雁不飲啄，飛鳴聲念群。誰憐一片影，相失萬重雲。", "望盡似猶見，哀多如更聞。野鴉無意緒，鳴噪自紛紛。"]'),
('yuding-69','鷗','杜甫','唐','御定全唐诗','yuding','','[]','江浦寒鷗戲，無他亦自饒。卻思翻玉羽，隨意點春苗。',48,'御定全唐詩/json/231.json','["江浦寒鷗戲，無他亦自饒。卻思翻玉羽，隨意點春苗。", "雪暗還須浴，風生一任飄。幾群滄海上，清影日蕭蕭。"]'),
('yuding-70','猿','杜甫','唐','御定全唐诗','yuding','','[]','嫋嫋啼虛壁，蕭蕭掛冷枝。艱難人不見，隱見爾如知。',48,'御定全唐詩/json/231.json','["嫋嫋啼虛壁，蕭蕭掛冷枝。艱難人不見，隱見爾如知。", "慣習元從眾，全生或用奇。前林騰每及，父子莫相離。"]'),
('yuding-71','黃魚','杜甫','唐','御定全唐诗','yuding','','[]','日見巴東峽，黃魚出浪新。脂膏兼飼犬，長大不容身。',48,'御定全唐詩/json/231.json','["日見巴東峽，黃魚出浪新。脂膏兼飼犬，長大不容身。", "筒桶相沿久，風雷肯為神。泥沙卷涎沫，回首怪龍鱗。"]'),
('yuding-72','白小','杜甫','唐','御定全唐诗','yuding','','[]','白小群分命，天然二寸魚。細微沾水族，風俗當園蔬。',48,'御定全唐詩/json/231.json','["白小群分命，天然二寸魚。細微沾水族，風俗當園蔬。", "入肆銀花亂，傾箱雪片虛。生成猶拾卵，盡取義何如。"]'),
('yuding-73','麂','杜甫','唐','御定全唐诗','yuding','','[]','永與清溪別，蒙將玉饌俱。無才逐仙隱，不敢恨庖廚。',48,'御定全唐詩/json/231.json','["永與清溪別，蒙將玉饌俱。無才逐仙隱，不敢恨庖廚。", "亂世輕全物，微聲及禍樞。衣冠兼盜賊，饕餮用斯須。"]'),
('yuding-74','雞','杜甫','唐','御定全唐诗','yuding','','[]','紀德名標五，初鳴度必三。殊方聽有異，失次曉無慚。',48,'御定全唐詩/json/231.json','["紀德名標五，初鳴度必三。殊方聽有異，失次曉無慚。", "問俗人情似，充庖爾輩堪。氣交亭育際，巫峽漏司南。"]'),
('yuding-75','玉腕騮','杜甫','唐','御定全唐诗','yuding','','[]','聞說荊南馬，尚書玉腕騮。頓驂飄赤汗，局蹐顧長楸。',48,'御定全唐詩/json/231.json','["聞說荊南馬，尚書玉腕騮。頓驂飄赤汗，局蹐顧長楸。", "胡虜三年入，乾坤一戰收。舉鞭如有問，欲伴習池遊。"]'),
('yuding-76','見王監兵馬使說近山有白黑二鷹羅者久取竟未能得王以為毛骨有異他鷹恐臘後春生鶱飛避暖勁翮思秋之甚眇不可見請余賦詩','杜甫','唐','御定全唐诗','yuding','','[]','雪飛玉立盡清秋，不惜奇毛恣遠遊。在野只教心力破，',80,'御定全唐詩/json/231.json','["雪飛玉立盡清秋，不惜奇毛恣遠遊。在野只教心力破，", "鵬礙九天須卻避，兔藏三穴莫深憂。", "黑鷹不省人間有，度海疑從北極來。正翮摶風超紫塞，", "萬里寒空只一日，金眸玉爪不凡材。"]'),
('yuding-0','太歲日','杜甫','唐','御定全唐诗','yuding','','[]','楚岸行將老，巫山坐複春。病多猶是客，謀拙竟何人。',96,'御定全唐詩/json/232.json','["楚岸行將老，巫山坐複春。病多猶是客，謀拙竟何人。", "閶闔開黃道，衣冠拜紫宸。榮光懸日月，賜與出金銀。", "愁寂鴛行斷，參差虎穴鄰。西江元下蜀，北斗故臨秦。", "散地逾高枕，生涯脫要津。天邊梅柳樹，相見幾回新。"]'),
('yuding-1','元日示宗武','杜甫','唐','御定全唐诗','yuding','','[]','汝啼吾手戰，吾笑汝身長。處處逢正月，迢迢滯遠方。',72,'御定全唐詩/json/232.json','["汝啼吾手戰，吾笑汝身長。處處逢正月，迢迢滯遠方。", "飄零還柏酒，衰病只藜床。訓喻青衿子，名慚白首郎。", "賦詩猶落筆，獻壽更稱觴。不見江東弟，高歌淚數行。"]'),
('yuding-2','遠懷舍弟穎、觀等','杜甫','唐','御定全唐诗','yuding','','[]','陽翟空知處，荊南近得書。積年仍遠別，多難不安居。',72,'御定全唐詩/json/232.json','["陽翟空知處，荊南近得書。積年仍遠別，多難不安居。", "江漢春風起，冰霜昨夜除。雲天猶錯莫，花萼尚蕭疏。", "對酒都疑夢，吟詩正憶渠。舊時元日會，鄉黨羨吾廬。"]'),
('yuding-3','續得觀書，迎就當陽居止，正月中旬定出三峽','杜甫','唐','御定全唐诗','yuding','','[]','自汝到荊府，書來數喚吾。頌椒添諷詠，禁火蔔歡娛。',96,'御定全唐詩/json/232.json','["自汝到荊府，書來數喚吾。頌椒添諷詠，禁火蔔歡娛。", "舟楫因人動，形骸用杖扶。天旋夔子國，春近岳陽湖。", "發日排南喜，傷神散北籲。飛鳴還接翅，行序密銜蘆。", "俗薄江山好，時危草木蘇。馮唐雖晚達，終覬在皇都。"]'),
('yuding-4','將別巫峽，贈南卿兄瀼西果園四十畝','杜甫','唐','御定全唐诗','yuding','','[]','苔竹素所好，萍蓬無定居。遠遊長兒子，幾地別林廬。',96,'御定全唐詩/json/232.json','["苔竹素所好，萍蓬無定居。遠遊長兒子，幾地別林廬。", "雜蕊紅相對，他時錦不如。具舟將出峽，巡圃念攜鋤。", "正月喧鶯末，茲辰放鷁初。雪籬梅可折，風榭柳微舒。", "托贈卿家有，因歌野興疏。殘生逗江漢，何處狎樵漁。"]'),
('yuding-5','送大理封主簿五郎親事不合卻赴通州主簿前閬州賢子余與主簿平章鄭氏女子垂欲納鄭氏伯父京書至女子已許他族親事遂停','杜甫','唐','御定全唐诗','yuding','','[]','禁臠去東床，趨庭赴北堂。風波空遠涉，琴瑟幾虛張。',96,'御定全唐詩/json/232.json','["禁臠去東床，趨庭赴北堂。風波空遠涉，琴瑟幾虛張。", "渥水出騏驥，昆山生鳳凰。兩家誠款款，中道許蒼蒼。", "頗謂秦晉匹，從來王謝郎。青春動才調，白首缺輝光。", "玉潤終孤立，珠明得暗藏。餘寒折花卉，恨別滿江鄉。"]'),
('yuding-6','人日兩篇','杜甫','唐','御定全唐诗','yuding','','[]','元日到人日，未有不陰時。冰雪鶯難至，春寒花較遲。',88,'御定全唐詩/json/232.json','["元日到人日，未有不陰時。冰雪鶯難至，春寒花較遲。", "雲隨白水落，風振紫山悲。蓬鬢稀疏久，無勞比素絲。", "此日此時人共得，一談一笑俗相看。尊前柏葉休隨酒，", "早春重引江湖興，直道無憂行路難。"]'),
('yuding-7','江梅','杜甫','唐','御定全唐诗','yuding','','[]','梅蕊臘前破，梅花年後多。絕知春意好，最奈客愁何。',48,'御定全唐詩/json/232.json','["梅蕊臘前破，梅花年後多。絕知春意好，最奈客愁何。", "雪樹元同色，江風亦自波。故園不可見，巫岫鬱嵯峨。"]'),
('yuding-8','庭草','杜甫','唐','御定全唐诗','yuding','','[]','楚草經寒碧，逢春入眼濃。舊低收葉舉，新掩卷牙重。',48,'御定全唐詩/json/232.json','["楚草經寒碧，逢春入眼濃。舊低收葉舉，新掩卷牙重。", "步履宜輕過，開筵得屢供。看花隨節序，不敢強為容。"]'),
('yuding-9','大曆三年春白帝城放船出瞿塘峽久居夔府將適江陵漂泊有詩凡四十韻','杜甫','唐','御定全唐诗','yuding','','[]','老向巴人裏，今辭楚塞隅。入舟翻不樂，解纜獨長籲。',504,'御定全唐詩/json/232.json','["老向巴人裏，今辭楚塞隅。入舟翻不樂，解纜獨長籲。", "窄轉深啼狖，虛隨亂浴鳧。石苔淩几杖，空翠撲肌膚。", "疊壁排霜劍，奔泉濺水珠。杳冥藤上下，濃澹樹榮枯。", "神女峰娟妙，昭君宅有無。曲留明怨惜，夢盡失歡娛。", "擺闔盤渦沸，欹斜激浪輸。風雷纏地脈，冰雪耀天衢。", "鹿角真走險，狼頭如跋胡。惡灘甯變色，高臥負微軀。", "書史全傾撓，裝囊半壓濡。生涯臨臬兀，死地脫斯須。", "不有平川決，焉知眾壑趨。乾坤霾漲海，雨露洗春蕪。", "鷗鳥牽絲颺，驪龍濯錦紆。落霞沉綠綺，殘月壞金樞。", "泥筍苞初荻，沙茸出小蒲。雁兒爭水馬，燕子逐檣烏。", "絕島容煙霧，環洲納曉晡。前聞辨陶牧，轉眄拂宜都。", "縣郭南畿好，津亭北望孤。勞心依憩息，朗詠劃昭蘇。", "意遣樂還笑，衰迷賢與愚。飄蕭將素發，汩沒聽洪爐。", "丘壑曾忘返，文章敢自誣。此生遭聖代，誰分哭窮途。", "臥疾淹為客，蒙恩早廁儒。廷爭酬造化，樸直乞江湖。", "灩澦險相迫，滄浪深可逾。浮名尋已已，懶計卻區區。", "喜近天皇寺，先披古畫圖。應經帝子渚，同泣舜蒼梧。", "朝士兼戎服，君王按湛盧。旄頭初俶擾，鶉首麗泥塗。", "甲卒身雖貴，書生道固殊。出塵皆野鶴，曆塊匪轅駒。", "伊呂終難降，韓彭不易呼。五雲高太甲，六月曠摶扶。", "回首黎元病，爭權將帥誅。山林托疲苶，未必免崎嶇。"]'),
('yuding-10','巫山縣汾州唐使君十八弟宴別兼諸公攜酒樂相送率題小詩留於屋壁','杜甫','唐','御定全唐诗','yuding','','[]','臥病巴東久，今年強作歸。故人猶遠謫，茲日倍多違。',48,'御定全唐詩/json/232.json','["臥病巴東久，今年強作歸。故人猶遠謫，茲日倍多違。", "接宴身兼杖，聽歌淚滿衣。諸公不相棄，擁別惜光輝。"]'),
('yuding-11','春夜峽州田侍禦長史津亭留宴','杜甫','唐','御定全唐诗','yuding','','[]','北斗三更席，西江萬里船。杖藜登水榭，揮翰宿春天。',48,'御定全唐詩/json/232.json','["北斗三更席，西江萬里船。杖藜登水榭，揮翰宿春天。", "白髮煩多酒，明星惜此筵。始知雲雨峽，忽盡下牢邊。"]'),
('yuding-12','泊松滋江亭','杜甫','唐','御定全唐诗','yuding','','[]','沙帽隨鷗鳥，扁舟系此亭。江湖深更白，松竹遠微青。',48,'御定全唐詩/json/232.json','["沙帽隨鷗鳥，扁舟系此亭。江湖深更白，松竹遠微青。", "一柱全應近，高唐莫再經。今宵南極外，甘作老人星。"]'),
('yuding-13','行次古城店泛江作，不揆鄙拙，奉呈江陵幕府諸公','杜甫','唐','御定全唐诗','yuding','','[]','老年常道路，遲日複山川。白屋花開裏，孤城麥秀邊。',72,'御定全唐詩/json/232.json','["老年常道路，遲日複山川。白屋花開裏，孤城麥秀邊。", "濟江元自闊，下水不勞牽。風蝶勤依槳，春鷗懶避船。", "王門高德業，幕府盛才賢。行色兼多病，蒼茫泛愛前。"]'),
('yuding-14','乘雨入行軍六弟宅','杜甫','唐','御定全唐诗','yuding','','[]','曙角淩雲罷，春城帶雨長。水花分塹弱，巢燕得泥忙。',48,'御定全唐詩/json/232.json','["曙角淩雲罷，春城帶雨長。水花分塹弱，巢燕得泥忙。", "令弟雄軍佐，凡才汙省郎。萍漂忍流涕，衰颯近中堂。"]'),
('yuding-15','宴胡侍禦書堂','杜甫','唐','御定全唐诗','yuding','','[]','江湖春欲暮，牆宇日猶微。暗暗春籍滿，輕輕花絮飛。',48,'御定全唐詩/json/232.json','["江湖春欲暮，牆宇日猶微。暗暗春籍滿，輕輕花絮飛。", "翰林名有素，墨客興無違。今夜文星動，吾儕醉不歸。"]'),
('yuding-16','書堂飲既，夜複邀李尚書下馬，月下賦絕句','杜甫','唐','御定全唐诗','yuding','','[]','湖水林風相與清，殘尊下馬複同傾。',32,'御定全唐詩/json/232.json','["湖水林風相與清，殘尊下馬複同傾。", "久判野鶴如霜鬢，遮莫鄰雞下五更。"]'),
('yuding-17','上巳日徐司錄林園宴集','杜甫','唐','御定全唐诗','yuding','','[]','鬢毛垂領白，花蕊亞枝紅。欹倒衰年廢，招尋令節同。',48,'御定全唐詩/json/232.json','["鬢毛垂領白，花蕊亞枝紅。欹倒衰年廢，招尋令節同。", "薄衣臨積水，吹面受和風。有喜留攀桂，無勞問轉蓬。"]'),
('yuding-18','奉送蘇州李二十五長史丈之任','杜甫','唐','御定全唐诗','yuding','','[]','星坼台衡地，曾為人所憐。公侯終必複，經術昔相傳。',72,'御定全唐詩/json/232.json','["星坼台衡地，曾為人所憐。公侯終必複，經術昔相傳。", "食德見從事，克家何妙年。一毛生鳳穴，三尺獻龍泉。", "赤壁浮春暮，姑蘇落海邊。客間頭最白，惆悵此離筵。"]'),
('yuding-19','暮春江陵送馬大卿公，恩命追赴闕下','杜甫','唐','御定全唐诗','yuding','','[]','自古求忠孝，名家信有之。吾賢富才術，此道未磷緇。',120,'御定全唐詩/json/232.json','["自古求忠孝，名家信有之。吾賢富才術，此道未磷緇。", "玉府標孤映，霜蹄去不疑。激揚音韻徹，籍甚眾多推。", "潘陸應同調，孫吳亦異時。北辰征事業，南紀赴恩私。", "卿月升金掌，王春度玉墀。熏風行應律，湛露即歌詩。", "天意高難問，人情老易悲。尊前江漢闊，後會且深期。"]'),
('yuding-20','暮春陪李尚書、李中丞過鄭監湖亭泛舟','杜甫','唐','御定全唐诗','yuding','','[]','海內文章伯，湖邊意緒多。玉尊移晚興，桂楫帶酣歌。',48,'御定全唐詩/json/232.json','["海內文章伯，湖邊意緒多。玉尊移晚興，桂楫帶酣歌。", "春日繁魚鳥，江天足芰荷。鄭莊賓客地，衰白遠來過。"]'),
('yuding-21','奉送蜀州柏二別駕將中丞命赴江陵起居衛尚書太夫人因示從弟行軍司馬佐','杜甫','唐','御定全唐诗','yuding','','[]','中丞問俗畫熊頻，愛弟傳書彩鷁新。遷轉五州防禦使，',40,'御定全唐詩/json/232.json','["中丞問俗畫熊頻，愛弟傳書彩鷁新。遷轉五州防禦使，", "報與惠連詩不惜，知吾斑鬢總如銀。"]'),
('yuding-22','夏日楊長寧宅送崔侍禦、常正字入京','杜甫','唐','御定全唐诗','yuding','','[]','醉酒揚雄宅，升堂子賤琴。不堪垂老鬢，還對欲分襟。',48,'御定全唐詩/json/232.json','["醉酒揚雄宅，升堂子賤琴。不堪垂老鬢，還對欲分襟。", "天地西江遠，星辰北斗深。烏台俯麟閣，長夏白頭吟。"]'),
('yuding-23','和江陵宋大少府暮春雨後同諸公及舍弟宴書齋','杜甫','唐','御定全唐诗','yuding','','[]','渥窪汗血種，天上麒麟兒。才士得神秀，書齋聞爾為。',48,'御定全唐詩/json/232.json','["渥窪汗血種，天上麒麟兒。才士得神秀，書齋聞爾為。", "棣華晴雨好，彩服暮春宜。朋酒日歡會，老夫今始知。"]'),
('yuding-24','宇文晁尚書之甥崔彧司業之孫尚書之子重泛鄭監前湖','杜甫','唐','御定全唐诗','yuding','','[]','郊扉俗遠長幽寂，野水春來更接連。錦席淹留還出浦，',40,'御定全唐詩/json/232.json','["郊扉俗遠長幽寂，野水春來更接連。錦席淹留還出浦，", "不但習池歸酩酊，君看鄭穀去夤緣。"]'),
('yuding-25','多病執熱奉懷李尚書','杜甫','唐','御定全唐诗','yuding','','[]','衰年正苦病侵淩，首夏何須氣鬱蒸。大水淼茫炎海接，',40,'御定全唐詩/json/232.json','["衰年正苦病侵淩，首夏何須氣鬱蒸。大水淼茫炎海接，", "不是尚書期不顧，山陰野雪興難乘。"]'),
('yuding-26','水宿遣興奉呈群公','杜甫','唐','御定全唐诗','yuding','','[]','魯鈍乃多病，逢迎遠複迷。耳聾須畫字，發短不勝篦。',240,'御定全唐詩/json/232.json','["魯鈍乃多病，逢迎遠複迷。耳聾須畫字，發短不勝篦。", "澤國雖勤雨，炎天竟淺泥。小江還積浪，弱纜且長堤。", "歸路非關北，行舟卻向西。暮年漂泊恨，今夕亂離啼。", "童稚頻書劄，盤餐詎糝藜。我行何到此，物理直難齊。", "高枕翻星月，嚴城疊鼓鼙。風號聞虎豹，水宿伴鳧鷖。", "異縣驚虛往，同人惜解攜。蹉跎長泛鷁，輾轉屢鳴雞。", "嶷嶷瑚璉器，陰陰桃李蹊。餘波期救涸，費日苦輕齎。", "支策門闌邃，肩輿羽翮低。自傷甘賤役，誰湣強幽棲。", "巨海能無釣，浮雲亦有梯。勳庸思樹立，語默可端倪。", "贈粟囷應指，登橋柱必題。丹心老未折，時訪武陵溪。"]'),
('yuding-27','奉賀陽城郡王太夫人恩命加鄧國太夫人','杜甫','唐','御定全唐诗','yuding','','[]','衛幕銜恩重，潘輿送喜頻。濟時瞻上將，錫號戴慈親。',120,'御定全唐詩/json/232.json','["衛幕銜恩重，潘輿送喜頻。濟時瞻上將，錫號戴慈親。", "富貴當如此，尊榮邁等倫。郡依封土舊，國與大名新。", "紫誥鸞回紙，清朝燕賀人。遠傳冬筍味，更覺彩衣春。", "奕葉班姑史，芬芳孟母鄰。義方兼有訓，詞翰兩如神。", "委曲承顏體，鶱飛報主身。可憐忠與孝，雙美畫騏驎。"]'),
('yuding-28','江陵望幸','杜甫','唐','御定全唐诗','yuding','','[]','雄都元壯麗，望幸欻威神。地利西通蜀，天文北照秦。',72,'御定全唐詩/json/232.json','["雄都元壯麗，望幸欻威神。地利西通蜀，天文北照秦。", "風煙含越鳥，舟楫控吳人。未枉周王駕，終期漢武巡。", "甲兵分聖旨，居守付宗臣。早發雲台仗，恩波起涸鱗。"]'),
('yuding-29','江邊星月二首','杜甫','唐','御定全唐诗','yuding','','[]','驟雨清秋夜，金波耿玉繩。天河元自白，江浦向來澄。',96,'御定全唐詩/json/232.json','["驟雨清秋夜，金波耿玉繩。天河元自白，江浦向來澄。", "映物連珠斷，緣空一鏡升。餘光隱更漏，況乃露華凝。", "江月辭風纜，江星別霧船。雞鳴還曙色，鷺浴自清川。", "歷歷竟誰種，悠悠何處圓。客愁殊未已，他夕始相鮮。"]'),
('yuding-30','舟月對驛近寺','杜甫','唐','御定全唐诗','yuding','','[]','更深不假燭，月朗自明船。金刹青楓外，朱樓白水邊。',48,'御定全唐詩/json/232.json','["更深不假燭，月朗自明船。金刹青楓外，朱樓白水邊。", "城烏啼眇眇，野鷺宿娟娟。皓首江湖客，鉤簾獨未眠。"]'),
('yuding-31','舟中','杜甫','唐','御定全唐诗','yuding','','[]','風餐江柳下，雨臥驛樓邊。結纜排魚網，連檣並米船。',48,'御定全唐詩/json/232.json','["風餐江柳下，雨臥驛樓邊。結纜排魚網，連檣並米船。", "今朝雲細薄，昨夜月清圓。飄泊南庭老，只應學水仙。"]'),
('yuding-32','遣悶','杜甫','唐','御定全唐诗','yuding','','[]','地闊平沙岸，舟虛小洞房。使塵來驛道，城日避烏檣。',144,'御定全唐詩/json/232.json','["地闊平沙岸，舟虛小洞房。使塵來驛道，城日避烏檣。", "暑雨留蒸濕，江風借夕涼。行雲星隱見，疊浪月光芒。", "螢鑒緣帷徹，蛛絲罥鬢長。哀箏猶憑幾，鳴笛竟沾裳。", "倚著如秦贅，過逢類楚狂。氣沖看劍匣，穎脫撫錐囊。", "妖孽關東臭，兵戈隴右創。時清疑武略，世亂局文場。", "餘力浮於海，端憂問彼蒼。百年從萬事，故國耿難忘。"]'),
('yuding-33','江陵節度陽城郡王新樓成王請嚴侍禦判官賦七字句同作','杜甫','唐','御定全唐诗','yuding','','[]','樓上炎天冰雪生，高盡燕雀賀新成。碧窗宿霧濛濛濕，',40,'御定全唐詩/json/232.json','["樓上炎天冰雪生，高盡燕雀賀新成。碧窗宿霧濛濛濕，", "自公多暇延參佐，江漢風流萬古情。"]'),
('yuding-34','又作此奉衛王','杜甫','唐','御定全唐诗','yuding','','[]','西北樓成雄楚都，遠開山嶽散江湖。二儀清濁還高下，',40,'御定全唐詩/json/232.json','["西北樓成雄楚都，遠開山嶽散江湖。二儀清濁還高下，", "白頭授簡焉能賦，愧似相如為大夫。"]'),
('yuding-35','舟出江陵南浦，奉寄鄭少尹','杜甫','唐','御定全唐诗','yuding','','[]','更欲投何處，飄然去此都。形骸元土木，舟楫複江湖。',144,'御定全唐詩/json/232.json','["更欲投何處，飄然去此都。形骸元土木，舟楫複江湖。", "社稷纏妖氣，干戈送老儒。百年同棄物，萬國盡窮途。", "雨洗平沙靜，天銜闊岸紆。鳴螿隨泛梗，別燕赴秋菰。", "棲托難高臥，饑寒迫向隅。寂寥相喣沫，浩蕩報恩珠。", "溟漲鯨波動，衡陽雁影徂。南征問懸榻，東逝想乘桴。", "濫竊商歌聽，時憂卞泣誅。經過憶鄭驛，斟酌旅情孤。"]'),
('yuding-36','江南逢李龜年','杜甫','唐','御定全唐诗','yuding','','[]','岐王宅裏尋常見，崔九堂前幾度聞。',32,'御定全唐詩/json/232.json','["岐王宅裏尋常見，崔九堂前幾度聞。", "正是江南好風景，落花時節又逢君。"]'),
('yuding-37','官亭夕坐戲簡顏十少府','杜甫','唐','御定全唐诗','yuding','','[]','南國調寒杵，西江浸日車。客愁連蟋蟀，亭古帶蒹葭。',48,'御定全唐詩/json/232.json','["南國調寒杵，西江浸日車。客愁連蟋蟀，亭古帶蒹葭。", "不返青絲鞚，虛燒夜燭花。老翁須地主，細細酌流霞。"]'),
('yuding-38','秋日荊南述懷三十韻','杜甫','唐','御定全唐诗','yuding','','[]','昔承推獎分，愧匪挺生材。遲暮宮臣忝，艱危袞職陪。',360,'御定全唐詩/json/232.json','["昔承推獎分，愧匪挺生材。遲暮宮臣忝，艱危袞職陪。", "揚鑣隨日馭，折檻出雲台。罪戾寬猶活，干戈塞未開。", "星霜玄鳥變，身世白駒催。伏枕因超忽，扁舟任往來。", "九鑽巴噀火，三蟄楚祠雷。望帝傳應實，昭王問不回。", "蛟螭深作橫，豺虎亂雄猜。素業行已矣，浮名安在哉。", "琴烏曲怨憤，庭鶴舞摧頹。秋雨漫湘水，陰風過嶺梅。", "苦搖求食尾，常曝報恩腮。結舌防讒柄，探腸有禍胎。", "蒼茫步兵哭，輾轉仲宣哀。饑籍家家米，愁征處處杯。", "休為貧士歎，任受眾人咍。得喪初難識，榮枯劃易該。", "差池分組冕，合遝起蒿萊。不必伊周地，皆知屈宋才。", "漢庭和異域，晉史坼中台。霸業尋常體，忠臣忌諱災。", "群公紛戮力，聖慮窅裴回。數見銘鐘鼎，真宜法鬥魁。", "願聞鋒鏑鑄，莫使棟樑摧。磐石圭多翦，凶門轂少推。", "垂旒資穆穆，祝網但恢恢。赤雀翻然至，黃龍詎假媒。", "賢非夢傅野，隱類鑿顏坯。自古江湖客，冥心若死灰。"]'),
('yuding-39','秋日荊南送石首薛明府辭滿告別奉寄薛尚書頌德敘懷斐然之作三十韻','杜甫','唐','御定全唐诗','yuding','','[]','南征為客久，西候別君初。歲滿歸鳧舄，秋來把雁書。',360,'御定全唐詩/json/232.json','["南征為客久，西候別君初。歲滿歸鳧舄，秋來把雁書。", "荊門留美化，薑被就離居。聞道和親入，垂名報國餘。", "連枝不日並，八座幾時除。往者胡星孛，恭惟漢網疏。", "風塵相澒洞，天地一丘墟。殿瓦鴛鴦坼，宮簾翡翠虛。", "鉤陳摧徼道，槍櫐失儲胥。文物陪巡守，親賢病拮据。", "公時呵猰貐，首唱卻鯨魚。勢愜宗蕭相，材非一范睢。", "屍填太行道，血走浚儀渠。滏口師仍會，函關憤已攄。", "紫微臨大角，皇極正乘輿。賞從頻峨冕，殊私再直廬。", "豈惟高衛霍，曾是接應徐。降集翻翔鳳，追攀絕眾狙。", "侍臣雙宋玉，戰策兩穰苴。鑒澈勞懸鏡，荒蕪已荷鋤。", "向來披述作，重此憶吹噓。白髮甘凋喪，青雲亦卷舒。", "經綸功不朽，跋涉體何如。應訝耽湖橘，常餐占野蔬。", "十年嬰藥餌，萬里狎樵漁。揚子淹投閣，鄒生惜曳裾。", "但驚飛熠耀，不記改蟾蜍。煙雨封巫峽，江淮略孟諸。", "湯池雖險固，遼海尚填淤。努力輸肝膽，休煩獨起予。"]'),
('yuding-40','哭李尚書','杜甫','唐','御定全唐诗','yuding','','[]','漳濱與蒿裏，逝水竟同年。欲掛留徐劍，猶回憶戴船。',120,'御定全唐詩/json/232.json','["漳濱與蒿裏，逝水竟同年。欲掛留徐劍，猶回憶戴船。", "相知成白首，此別間黃泉。風雨嗟何及，江湖涕泫然。", "修文將管輅，奉使失張騫。史閣行人在，詩家秀句傳。", "客亭鞍馬絕，旅櫬網蟲懸。複魄昭丘遠，歸魂素滻偏。", "樵蘇封葬地，喉舌罷朝天。秋色凋春草，王孫若個邊。"]'),
('yuding-41','重題','杜甫','唐','御定全唐诗','yuding','','[]','涕泗不能收，哭君餘白頭。兒童相識盡，宇宙此生浮。',48,'御定全唐詩/json/232.json','["涕泗不能收，哭君餘白頭。兒童相識盡，宇宙此生浮。", "江雨銘旌濕，湖風井徑秋。還瞻魏太子，賓客減應劉。"]'),
('yuding-42','獨坐','杜甫','唐','御定全唐诗','yuding','','[]','悲愁回白首，倚杖背孤城。江斂洲渚出，天虛風物清。',48,'御定全唐詩/json/232.json','["悲愁回白首，倚杖背孤城。江斂洲渚出，天虛風物清。", "滄溟服衰謝，朱紱負平生。仰羨黃昏鳥，投林羽翮輕。"]'),
('yuding-43','暮歸','杜甫','唐','御定全唐诗','yuding','','[]','霜黃碧梧白鶴棲，城上擊柝複烏啼。客子入門月皎皎，',40,'御定全唐詩/json/232.json','["霜黃碧梧白鶴棲，城上擊柝複烏啼。客子入門月皎皎，", "年過半百不稱意，明日看雲還杖藜。"]'),
('yuding-44','移居公安敬贈衛大郎鈞','杜甫','唐','御定全唐诗','yuding','','[]','衛侯不易得，餘病汝知之。雅量涵高遠，清襟照等夷。',120,'御定全唐詩/json/232.json','["衛侯不易得，餘病汝知之。雅量涵高遠，清襟照等夷。", "平生感意氣，少小愛文辭。河海由來合，風雲若有期。", "形容勞宇宙，質樸謝軒墀。自古幽人泣，流年壯士悲。", "水煙通徑草，秋露接園葵。入邑豺狼鬥，傷弓鳥雀饑。", "白頭供宴語，烏幾伴棲遲。交態遭輕薄，今朝豁所思。"]'),
('yuding-45','公安送韋二少府匡贊','杜甫','唐','御定全唐诗','yuding','','[]','逍遙公後世多賢，送爾維舟惜此筵。念我能書數字至，',40,'御定全唐詩/json/232.json','["逍遙公後世多賢，送爾維舟惜此筵。念我能書數字至，", "古往今來皆涕淚，斷腸分手各風煙。"]'),
('yuding-46','贈虞十五司馬','杜甫','唐','御定全唐诗','yuding','','[]','遠師虞秘監，今喜識玄孫。形像丹青逼，家聲器宇存。',120,'御定全唐詩/json/232.json','["遠師虞秘監，今喜識玄孫。形像丹青逼，家聲器宇存。", "淒涼憐筆勢，浩蕩問詞源。爽氣金天豁，清談玉露繁。", "佇鳴南嶽鳳，欲化北溟鯤。交態知浮俗，儒流不異門。", "過逢聯客位，日夜倒芳尊。沙岸風吹葉，雲江月上軒。", "百年嗟已半，四座敢辭喧。書籍終相與，青山隔故園。"]'),
('yuding-47','公安縣懷古','杜甫','唐','御定全唐诗','yuding','','[]','野曠呂蒙營，江深劉備城。寒天催日短，風浪與雲平。',48,'御定全唐詩/json/232.json','["野曠呂蒙營，江深劉備城。寒天催日短，風浪與雲平。", "灑落君臣契，飛騰戰伐名。維舟倚前浦，長嘯一含情。"]'),
('yuding-48','公安送李二十九弟晉肅入蜀，餘下沔鄂','杜甫','唐','御定全唐诗','yuding','','[]','正解柴桑纜，仍看蜀道行。檣烏相背發，塞雁一行鳴。',48,'御定全唐詩/json/232.json','["正解柴桑纜，仍看蜀道行。檣烏相背發，塞雁一行鳴。", "南紀連銅柱，西江接錦城。憑將百錢蔔，飄泊問君平。"]'),
('yuding-49','宴王使君宅題二首','杜甫','唐','御定全唐诗','yuding','','[]','漢主追韓信，蒼生起謝安。吾徒自漂泊，世事各艱難。',96,'御定全唐詩/json/232.json','["漢主追韓信，蒼生起謝安。吾徒自漂泊，世事各艱難。", "逆旅招邀近，他鄉思緒寬。不材甘朽質，高臥豈泥蟠。", "泛愛容霜發，留歡蔔夜閑。自吟詩送老，相勸酒開顏。", "戎馬今何地，鄉園獨舊山。江湖墮清月，酩酊任扶還。"]'),
('yuding-50','留別公安太易沙門','杜甫','唐','御定全唐诗','yuding','','[]','隱居欲就廬山遠，麗藻初逢休上人。數問舟航留製作，',40,'御定全唐詩/json/232.json','["隱居欲就廬山遠，麗藻初逢休上人。數問舟航留製作，", "先蹋爐峰置蘭若，徐飛錫杖出風塵。"]'),
('yuding-0','曉發公安','杜甫','唐','御定全唐诗','yuding','','[]','北城擊柝複欲罷，東方明星亦不遲。鄰雞野哭如昨日，',40,'御定全唐詩/json/233.json','["北城擊柝複欲罷，東方明星亦不遲。鄰雞野哭如昨日，", "出門轉眄已陳跡，藥餌扶吾隨所之。"]'),
('yuding-1','泊岳陽城下','杜甫','唐','御定全唐诗','yuding','','[]','江國逾千里，山城僅百層。岸風翻夕浪，舟雪灑寒燈。',48,'御定全唐詩/json/233.json','["江國逾千里，山城僅百層。岸風翻夕浪，舟雪灑寒燈。", "留滯才難盡，艱危氣益增。圖南未可料，變化有鯤鵬。"]'),
('yuding-2','纜船苦風，戲題四韻，奉簡鄭十三判官','杜甫','唐','御定全唐诗','yuding','','[]','楚岸朔風疾，天寒鶬鴰呼。漲沙霾草樹，舞雪渡江湖。',48,'御定全唐詩/json/233.json','["楚岸朔風疾，天寒鶬鴰呼。漲沙霾草樹，舞雪渡江湖。", "吹帽時時落，維舟日日孤。因聲置驛外，為覓酒家壚。"]'),
('yuding-3','登岳陽樓','杜甫','唐','御定全唐诗','yuding','','[]','昔聞洞庭水，今上岳陽樓。吳楚東南坼，乾坤日夜浮。',48,'御定全唐詩/json/233.json','["昔聞洞庭水，今上岳陽樓。吳楚東南坼，乾坤日夜浮。", "親朋無一字，老病有孤舟。戎馬關山北，憑軒涕泗流。"]'),
('yuding-4','陪裴使君登岳陽樓','杜甫','唐','御定全唐诗','yuding','','[]','湖闊兼雲霧，樓孤屬晚晴。禮加徐孺子，詩接謝宣城。',48,'御定全唐詩/json/233.json','["湖闊兼雲霧，樓孤屬晚晴。禮加徐孺子，詩接謝宣城。", "雪岸叢梅發，春泥百草生。敢違漁父問，從此更南征。"]'),
('yuding-5','過南嶽入洞庭湖','杜甫','唐','御定全唐诗','yuding','','[]','洪波忽爭道，岸轉異江湖。鄂渚分雲樹，衡山引舳艫。',144,'御定全唐詩/json/233.json','["洪波忽爭道，岸轉異江湖。鄂渚分雲樹，衡山引舳艫。", "翠牙穿裛槳，碧節上寒蒲。病渴身何去，春生力更無。", "壤童犁雨雪，漁屋架泥塗。欹側風帆滿，微冥水驛孤。", "悠悠回赤壁，浩浩略蒼梧。帝子留遺恨，曹公屈壯圖。", "聖朝光禦極，殘孽駐艱虞。才淑隨廝養，名賢隱鍛爐。", "邵平元入漢，張翰後歸吳。莫怪啼痕數，危檣逐夜烏。"]'),
('yuding-6','宿青草湖','杜甫','唐','御定全唐诗','yuding','','[]','洞庭猶在目，青草續為名。宿槳依農事，郵簽報水程。',48,'御定全唐詩/json/233.json','["洞庭猶在目，青草續為名。宿槳依農事，郵簽報水程。", "寒冰爭倚薄，雲月遞微明。湖雁雙雙起，人來故北征。"]'),
('yuding-7','宿白沙驛','杜甫','唐','御定全唐诗','yuding','','[]','水宿仍餘照，人煙複此亭。驛邊沙舊白，湖外草新青。',48,'御定全唐詩/json/233.json','["水宿仍餘照，人煙複此亭。驛邊沙舊白，湖外草新青。", "萬象皆春氣，孤槎自客星。隨波無限月，的的近南溟。"]'),
('yuding-8','湘夫人祠','杜甫','唐','御定全唐诗','yuding','','[]','肅肅湘妃廟，空牆碧水春。蟲書玉佩蘚，燕舞翠帷塵。',48,'御定全唐詩/json/233.json','["肅肅湘妃廟，空牆碧水春。蟲書玉佩蘚，燕舞翠帷塵。", "晚泊登汀樹，微馨借渚蘋。蒼梧恨不盡，染淚在叢筠。"]'),
('yuding-9','祠南夕望','杜甫','唐','御定全唐诗','yuding','','[]','百丈牽江色，孤舟泛日斜。興來猶杖屨，目斷更雲沙。',48,'御定全唐詩/json/233.json','["百丈牽江色，孤舟泛日斜。興來猶杖屨，目斷更雲沙。", "山鬼迷春竹，湘娥倚暮花。湖南清絕地，萬古一長嗟。"]'),
('yuding-10','登白馬潭','杜甫','唐','御定全唐诗','yuding','','[]','水生春纜沒，日出野船開。宿鳥行猶去，叢花笑不來。',48,'御定全唐詩/json/233.json','["水生春纜沒，日出野船開。宿鳥行猶去，叢花笑不來。", "人人傷白首，處處接金杯。莫道新知要，南征且未回。"]'),
('yuding-11','歸雁','杜甫','唐','御定全唐诗','yuding','','[]','聞道今春雁，南歸自廣州。見花辭漲海，避雪到羅浮。',48,'御定全唐詩/json/233.json','["聞道今春雁，南歸自廣州。見花辭漲海，避雪到羅浮。", "是物關兵氣，何時免客愁。年年霜露隔，不過五湖秋。"]'),
('yuding-12','野望','杜甫','唐','御定全唐诗','yuding','','[]','納納乾坤大，行行郡國遙。雲山兼五嶺，風壤帶三苗。',48,'御定全唐詩/json/233.json','["納納乾坤大，行行郡國遙。雲山兼五嶺，風壤帶三苗。", "野樹侵江闊，春蒲長雪消。扁舟空老去，無補聖明朝。"]'),
('yuding-13','入喬口','杜甫','唐','御定全唐诗','yuding','','[]','漠漠舊京遠，遲遲歸路賒。殘年傍水國，落日對春華。',48,'御定全唐詩/json/233.json','["漠漠舊京遠，遲遲歸路賒。殘年傍水國，落日對春華。", "樹蜜早蜂亂，江泥輕燕斜。賈生骨已朽，淒惻近長沙。"]'),
('yuding-14','銅官渚守風','杜甫','唐','御定全唐诗','yuding','','[]','不夜楚帆落，避風湘渚間。水耕先浸草，春火更燒山。',48,'御定全唐詩/json/233.json','["不夜楚帆落，避風湘渚間。水耕先浸草，春火更燒山。", "早泊雲物晦，逆行波浪慳。飛來雙白鶴，過去杳難攀。"]'),
('yuding-15','北風','杜甫','唐','御定全唐诗','yuding','','[]','春生南國瘴，氣待北風蘇。向晚霾殘日，初宵鼓大爐。',120,'御定全唐詩/json/233.json','["春生南國瘴，氣待北風蘇。向晚霾殘日，初宵鼓大爐。", "爽攜卑濕地，聲拔洞庭湖。萬里魚龍伏，三更鳥獸呼。", "滌除貪破浪，愁絕付摧枯。執熱沉沉在，淩寒往往須。", "且知寬疾肺，不敢恨危途。再宿煩舟子，衰容問僕夫。", "今晨非盛怒，便道即長驅。隱幾看帆席，雲州湧坐隅。"]'),
('yuding-16','雙楓浦','杜甫','唐','御定全唐诗','yuding','','[]','輟棹青楓浦，雙楓舊已摧。自驚衰謝力，不道棟樑材。',48,'御定全唐詩/json/233.json','["輟棹青楓浦，雙楓舊已摧。自驚衰謝力，不道棟樑材。", "浪足浮紗帽，皮須截錦苔。江邊地有主，暫借上天回。"]'),
('yuding-17','奉送王信州崟北歸','杜甫','唐','御定全唐诗','yuding','','[]','朝廷防盜賊，供給湣誅求。下詔選郎署，傳聲能典州。',216,'御定全唐詩/json/233.json','["朝廷防盜賊，供給湣誅求。下詔選郎署，傳聲能典州。", "蒼生今日困，天子向時憂。井屋有煙起，瘡痍無血流。", "壤歌唯海甸，畫角自山樓。白髮寐常早，荒榛農複秋。", "解龜逾臥轍，遣騎覓扁舟。徐榻不知倦，潁川何以酬。", "塵生彤管筆，寒膩黑貂裘。高義終焉在，斯文去矣休。", "別離同雨散，行止各雲浮。林熱鳥開口，江渾魚掉頭。", "尉佗雖北拜，太史尚南留。軍旅應都息，寰區要盡收。", "九重思諫諍，八極念懷柔。徙倚瞻王室，從容仰廟謀。", "故人持雅論，絕塞豁窮愁。複見陶唐理，甘為汗漫遊。"]'),
('yuding-18','江閣臥病走筆寄呈崔、盧兩侍禦','杜甫','唐','御定全唐诗','yuding','','[]','客子庖廚薄，江樓枕席清。衰年病只瘦，長夏想為情。',48,'御定全唐詩/json/233.json','["客子庖廚薄，江樓枕席清。衰年病只瘦，長夏想為情。", "滑憶雕胡飯，香聞錦帶羹。溜匙兼暖腹，誰欲致杯罌。"]'),
('yuding-19','潭州送韋員外牧韶州','杜甫','唐','御定全唐诗','yuding','','[]','炎海韶州牧，風流漢署郎。分符先令望，同舍有輝光。',48,'御定全唐詩/json/233.json','["炎海韶州牧，風流漢署郎。分符先令望，同舍有輝光。", "白首多年疾，秋天昨夜涼。洞庭無過雁，書疏莫相忘。"]'),
('yuding-20','江閣對雨有懷行營裴二端公','杜甫','唐','御定全唐诗','yuding','','[]','南紀風濤壯，陰晴屢不分。野流行地日，江入度山雲。',48,'御定全唐詩/json/233.json','["南紀風濤壯，陰晴屢不分。野流行地日，江入度山雲。", "層閣憑雷殷，長空水面文。雨來銅柱北，應洗伏波軍。"]'),
('yuding-21','酬韋韶州見寄','杜甫','唐','御定全唐诗','yuding','','[]','養拙江湖外，朝廷記憶疏。深慚長者轍，重得故人書。',48,'御定全唐詩/json/233.json','["養拙江湖外，朝廷記憶疏。深慚長者轍，重得故人書。", "白髮絲難理，新詩錦不如。雖無南去雁，看取北來魚。"]'),
('yuding-22','千秋節有感二首','杜甫','唐','御定全唐诗','yuding','','[]','自罷千秋節，頻傷八月來。先朝常宴會，壯觀已塵埃。',144,'御定全唐詩/json/233.json','["自罷千秋節，頻傷八月來。先朝常宴會，壯觀已塵埃。", "鳳紀編生日，龍池塹劫灰。湘川新涕淚，秦樹遠樓臺。", "寶鏡群臣得，金吾萬國回。衢尊不重飲，白首獨餘哀。", "禦氣雲樓敞，含風彩仗高。仙人張內樂，王母獻宮桃。", "羅襪紅蕖豔，金羈白雪毛。舞階銜壽酒，走索背秋毫。", "聖主他年貴，邊心此日勞。桂江流向北，滿眼送波濤。"]'),
('yuding-23','晚秋長沙蔡五侍禦飲筵，送殷六參軍歸澧州覲省','杜甫','唐','御定全唐诗','yuding','','[]','佳士欣相識，慈顏望遠遊。甘從投轄飲，肯作置書郵。',48,'御定全唐詩/json/233.json','["佳士欣相識，慈顏望遠遊。甘從投轄飲，肯作置書郵。", "高鳥黃雲暮，寒蟬碧樹秋。湖南冬不雪，吾病得淹留。"]'),
('yuding-24','湖中送敬十使君適廣陵','杜甫','唐','御定全唐诗','yuding','','[]','相見各頭白，其如離別何。幾年一會面，今日複悲歌。',96,'御定全唐詩/json/233.json','["相見各頭白，其如離別何。幾年一會面，今日複悲歌。", "少壯樂難得，歲寒心匪他。氣纏霜匣滿，冰置玉壺多。", "遭亂實漂泊，濟時曾琢磨。形容吾校老，膽力爾誰過。", "秋晚嶽增翠，風高湖湧波。鶱騰訪知己，淮海莫蹉跎。"]'),
('yuding-25','長沙送李十一','杜甫','唐','御定全唐诗','yuding','','[]','與子避地西康州，洞庭相逢十二秋。遠愧尚方曾賜履，',40,'御定全唐詩/json/233.json','["與子避地西康州，洞庭相逢十二秋。遠愧尚方曾賜履，", "李杜齊名真忝竊，朔雲寒菊倍離憂。"]'),
('yuding-26','重送劉十弟判官','杜甫','唐','御定全唐诗','yuding','','[]','分源豕韋派，別浦雁賓秋。年事推兄忝，人才覺弟優。',72,'御定全唐詩/json/233.json','["分源豕韋派，別浦雁賓秋。年事推兄忝，人才覺弟優。", "經過辨豐劍，意氣逐吳鉤。垂翅徒衰老，先鞭不滯留。", "本枝淩歲晚，高義豁窮愁。他日臨江待，長沙舊驛樓。"]'),
('yuding-27','奉贈盧五丈參謀','杜甫','唐','御定全唐诗','yuding','','[]','恭惟同自出，妙選異高標。入幕知孫楚，披襟得鄭僑。',192,'御定全唐詩/json/233.json','["恭惟同自出，妙選異高標。入幕知孫楚，披襟得鄭僑。", "丈人藉才地，門閥冠雲霄。老矣逢迎拙，相于契托饒。", "賜錢傾府待，爭米駐船遙。鄰好艱難薄，氓心杼軸焦。", "客星空伴使，寒水不成潮。素發幹垂領，銀章破在腰。", "說詩能累夜，醉酒或連朝。藻翰惟牽率，湖山合動搖。", "時清非造次，興盡卻蕭條。天子多恩澤，蒼生轉寂寥。", "休傳鹿是馬，莫信鵩如鴞。未解依依袂，還斟泛泛瓢。", "流年疲蟋蟀，體物幸鷦鷯。辜負滄洲願，誰雲晚見招。"]'),
('yuding-28','登舟將適漢陽','杜甫','唐','御定全唐诗','yuding','','[]','春宅棄汝去，秋帆催客歸。庭蔬尚在眼，浦浪已吹衣。',72,'御定全唐詩/json/233.json','["春宅棄汝去，秋帆催客歸。庭蔬尚在眼，浦浪已吹衣。", "生理飄蕩拙，有心遲暮違。中原戎馬盛，遠道素書稀。", "塞雁與時集，檣烏終歲飛。鹿門自此往，永息漢陰機。"]'),
('yuding-29','暮秋將歸秦，留別湖南幕府親友','杜甫','唐','御定全唐诗','yuding','','[]','水闊蒼梧野，天高白帝秋。途窮那免哭，身老不禁愁。',48,'御定全唐詩/json/233.json','["水闊蒼梧野，天高白帝秋。途窮那免哭，身老不禁愁。", "大府才能會，諸公德業優。北歸沖雨雪，誰憫敝貂裘。"]'),
('yuding-30','送盧十四弟侍禦護韋尚書靈櫬歸上都二十韻','杜甫','唐','御定全唐诗','yuding','','[]','素幕渡江遠，朱幡登陸微。悲鳴駟馬顧，失涕萬人揮。',240,'御定全唐詩/json/233.json','["素幕渡江遠，朱幡登陸微。悲鳴駟馬顧，失涕萬人揮。", "參佐哭辭畢，門闌誰送歸。從公伏事久，之子俊才稀。", "長路更執紼，此心猶倒衣。感恩義不小，懷舊禮無違。", "墓待龍驤詔，台迎獬豸威。深衷見士則，雅論在兵機。", "戎狄乘妖氣，塵沙落禁闈。往年朝謁斷，他日掃除非。", "但促銅壺箭，休添玉帳旗。動詢黃閣老，肯慮白登圍。", "萬姓瘡痍合，群凶嗜欲肥。刺規多諫諍，端拱自光輝。", "儉約前王體，風流後代希。對揚期特達，衰朽再芳菲。", "空裏愁書字，山中疾采薇。撥杯要忽罷，抱被宿何依。", "眼冷看征蓋，兒扶立釣磯。清霜洞庭葉，故就別時飛。"]'),
('yuding-31','哭李常侍嶧二首','杜甫','唐','御定全唐诗','yuding','','[]','一代風流盡，修文地下深。斯人不重見，將老失知音。',96,'御定全唐詩/json/233.json','["一代風流盡，修文地下深。斯人不重見，將老失知音。", "短日行梅嶺，寒山落桂林。長安若個畔，猶想映貂金。", "青瑣陪雙入，銅梁阻一辭。風塵逢我地，江漢哭君時。", "次第尋書劄，呼兒檢贈詩。發揮王子表，不愧史臣詞。"]'),
('yuding-32','哭韋大夫之晉','杜甫','唐','御定全唐诗','yuding','','[]','悽愴郇瑕色，差池弱冠年。丈人叨禮數，文律早周旋。',216,'御定全唐詩/json/233.json','["悽愴郇瑕色，差池弱冠年。丈人叨禮數，文律早周旋。", "台閣黃圖裏，簪裾紫蓋邊。尊榮真不忝，端雅獨翛然。", "貢喜音容間，馮招病疾纏。南過駭倉卒，北思悄聯綿。", "鵩鳥長沙諱，犀牛蜀郡憐。素車猶慟哭，寶劍谷高懸。", "漢道中興盛，韋經亞相傳。沖融標世業，磊落映時賢。", "城府深朱夏，江湖眇霽天。綺樓關樹頂，飛旐泛堂前。", "帟幕疑風燕，笳簫急暮蟬。興殘虛白室，跡斷孝廉船。", "童孺交遊盡，喧卑俗事牽。老來多涕淚，情在強詩篇。", "誰寄方隅理，朝難將帥權。春秋褒貶例，名器重雙全。"]'),
('yuding-33','舟中夜雪，有懷盧十四侍禦弟','杜甫','唐','御定全唐诗','yuding','','[]','朔風吹桂水，朔雪夜紛紛。暗度南樓月，寒深北渚雲。',48,'御定全唐詩/json/233.json','["朔風吹桂水，朔雪夜紛紛。暗度南樓月，寒深北渚雲。", "燭斜初近見，舟重竟無聞。不識山陰道，聽雞更憶君。"]'),
('yuding-34','對雪','杜甫','唐','御定全唐诗','yuding','','[]','北雪犯長沙，胡雲冷萬家。隨風且間葉，帶雨不成花。',48,'御定全唐詩/json/233.json','["北雪犯長沙，胡雲冷萬家。隨風且間葉，帶雨不成花。", "金錯囊從罄，銀壺酒易賒。無人竭浮蟻，有待至昏鴉。"]'),
('yuding-35','樓上','杜甫','唐','御定全唐诗','yuding','','[]','天地空搔首，頻抽白玉簪。皇輿三極北，身事五湖南。',48,'御定全唐詩/json/233.json','["天地空搔首，頻抽白玉簪。皇輿三極北，身事五湖南。", "戀闕勞肝肺，論材愧杞楠。亂離難自救，終是老湘潭。"]'),
('yuding-36','冬晚送長孫漸舍人歸州','杜甫','唐','御定全唐诗','yuding','','[]','參卿休坐幄，蕩子不還鄉。南客瀟湘外，西戎鄠杜旁。',72,'御定全唐詩/json/233.json','["參卿休坐幄，蕩子不還鄉。南客瀟湘外，西戎鄠杜旁。", "衰年傾蓋晚，費日系舟長。會面思來劄，銷魂逐去檣。", "雲晴鷗更舞，風逆雁無行。匣裏雌雄劍，吹毛任選將。"]'),
('yuding-37','暮冬送蘇四郎徯兵曹適桂州','杜甫','唐','御定全唐诗','yuding','','[]','飄飄蘇季子，六印佩何遲。早作諸侯客，兼工古體詩。',72,'御定全唐詩/json/233.json','["飄飄蘇季子，六印佩何遲。早作諸侯客，兼工古體詩。", "爾賢埋照久，余病長年悲。盧綰須征日，樓蘭要斬時。", "歲陽初盛動，王化久磷緇。為入蒼梧廟，看雲哭九疑。"]'),
('yuding-38','風疾舟中伏枕書懷三十六韻，奉呈湖南親友','杜甫','唐','御定全唐诗','yuding','','[]','軒轅休制律，虞舜罷彈琴。尚錯雄鳴管，猶傷半死心。',432,'御定全唐詩/json/233.json','["軒轅休制律，虞舜罷彈琴。尚錯雄鳴管，猶傷半死心。", "聖賢名古邈，羈旅病年侵。舟泊常依震，湖平早見參。", "如聞馬融笛，若倚仲宣襟。故國悲寒望，群雲慘歲陰。", "水鄉霾白屋，楓岸疊青岑。鬱鬱冬炎瘴，濛濛雨滯淫。", "鼓迎非祭鬼，彈落似鴞禽。興盡才無悶，愁來遽不禁。", "生涯相汩沒，時物自蕭森。疑惑尊中弩，淹留冠上簪。", "牽裾驚魏帝，投閣為劉歆。狂走終奚適，微才謝所欽。", "吾安藜不糝，汝貴玉為琛。烏幾重重縛，鶉衣寸寸針。", "哀傷同庾信，述作異陳琳。十暑岷山葛，三霜楚戶砧。", "叨陪錦帳座，久放白頭吟。反朴時難遇，忘機陸易沈。", "應過數粒食，得近四知金。春草封歸恨，源花費獨尋。", "轉蓬憂悄悄，行藥病涔涔。瘞夭追潘岳，持危覓鄧林。", "蹉跎翻學步，感激在知音。卻假蘇張舌，高誇周宋鐔。", "納流迷浩汗，峻址得嶔崟。城府開清旭，松筠起碧潯。", "披顏爭倩倩，逸足競駸駸。朗鑒存愚直，皇天實照臨。", "公孫仍恃險，侯景未生擒。書信中原闊，干戈北斗深。", "畏人千里井，問俗九州箴。戰血流依舊，軍聲動至今。", "葛洪屍定解，許靖力還任。家事丹砂訣，無成涕作霖。"]'),
('yuding-39','奉贈蕭二十使君','杜甫','唐','御定全唐诗','yuding','','[]','昔在嚴公幕，俱為蜀使臣。艱危參大府，前後間清塵。',216,'御定全唐詩/json/233.json','["昔在嚴公幕，俱為蜀使臣。艱危參大府，前後間清塵。", "起草鳴先路，乘槎動要津。王鳧聊暫出，蕭雉只相馴。", "終始任安義，荒蕪孟母鄰。聯翩匍匐禮，意氣死生親。", "張老存家事，嵇康有故人。食恩慚鹵莽，鏤骨抱酸辛。", "巢許山林志，夔龍廊廟珍。鵬圖仍矯翼，熊軾且移輪。", "磊落衣冠地，蒼茫土木身。塤篪鳴自合，金石瑩逾新。", "重憶羅江外，同游錦水濱。結歡隨過隙，懷舊益沾巾。", "曠絕含香舍，稽留伏枕辰。停驂雙闕早，回雁五湖春。", "不達長卿病，從來原憲貧。監河受貸粟，一起轍中鱗。"]'),
('yuding-40','奉送二十三舅錄事之攝郴州','杜甫','唐','御定全唐诗','yuding','','[]','賢良歸盛族，吾舅盡知名。徐庶高交友，劉牢出外甥。',120,'御定全唐詩/json/233.json','["賢良歸盛族，吾舅盡知名。徐庶高交友，劉牢出外甥。", "泥塗豈珠玉，環堵但柴荊。衰老悲人世，驅馳厭甲兵。", "氣春江上別，淚血渭陽情。舟鷁排風影，林烏反哺聲。", "永嘉多北至，句漏且南征。必見公侯複，終聞盜賊平。", "郴州頗涼冷，橘井尚淒清。從役何蠻貊，居官志在行。"]'),
('yuding-41','送魏二十四司直充嶺南掌選崔郎中判官兼寄韋韶州','杜甫','唐','御定全唐诗','yuding','','[]','選曹分五嶺，使者曆三湘。才美膺推薦，君行佐紀綱。',72,'御定全唐詩/json/233.json','["選曹分五嶺，使者曆三湘。才美膺推薦，君行佐紀綱。", "佳聲斯共遠，雅節在周防。明白山濤鑒，嫌疑陸賈裝。", "故人湖外少，春日嶺南長。憑報韶州牧，新詩昨寄將。"]'),
('yuding-42','送趙十七明府之縣','杜甫','唐','御定全唐诗','yuding','','[]','連城為寶重，茂宰得才新。山雉迎舟楫，江花報邑人。',48,'御定全唐詩/json/233.json','["連城為寶重，茂宰得才新。山雉迎舟楫，江花報邑人。", "論交翻恨晚，臥病卻愁春。惠愛南翁悅，餘波及老身。"]'),
('yuding-43','燕子來舟中作','杜甫','唐','御定全唐诗','yuding','','[]','湖南為客動經春，燕子銜泥兩度新。舊入故園常識主，',40,'御定全唐詩/json/233.json','["湖南為客動經春，燕子銜泥兩度新。舊入故園常識主，", "暫語船檣還起去，穿花落水益沾巾。"]'),
('yuding-44','同豆盧峰知字韻','杜甫','唐','御定全唐诗','yuding','','[]','煉金歐冶子，噴玉大宛兒。符彩高無敵，聰明達所為。',72,'御定全唐詩/json/233.json','["煉金歐冶子，噴玉大宛兒。符彩高無敵，聰明達所為。", "夢蘭他日應，折桂早年知。爛漫通經術，光芒刷羽儀。", "謝庭瞻不遠，潘省會於斯。倡和將雛曲，田翁號鹿皮。"]'),
('yuding-45','歸雁二首','杜甫','唐','御定全唐诗','yuding','','[]','萬里衡陽雁，今年又北歸。雙雙瞻客上，一一背人飛。',96,'御定全唐詩/json/233.json','["萬里衡陽雁，今年又北歸。雙雙瞻客上，一一背人飛。", "雲裏相呼疾，沙邊自宿稀。系書元浪語，愁寂故山薇。", "欲雪違胡地，先花別楚雲。卻過清渭影，高起洞庭群。", "塞北春陰暮，江南日色曛。傷弓流落羽，行斷不堪聞。"]'),
('yuding-46','小寒食舟中作','杜甫','唐','御定全唐诗','yuding','','[]','佳辰強飯食猶寒，隱幾蕭條帶鶡冠。春水船如天上坐，',40,'御定全唐詩/json/233.json','["佳辰強飯食猶寒，隱幾蕭條帶鶡冠。春水船如天上坐，", "雲白山青萬餘裏，愁看直北是長安。"]'),
('yuding-47','清明二首','杜甫','唐','御定全唐诗','yuding','','[]','朝來新火起新煙，湖色春光淨客船。繡羽銜花他自得，',96,'御定全唐詩/json/233.json','["朝來新火起新煙，湖色春光淨客船。繡羽銜花他自得，", "不見定王城舊處，長懷賈傅井依然。虛沾焦舉為寒食，", "此身飄泊苦西東，右臂偏枯半耳聾。寂寂系舟雙下淚，", "旅雁上雲歸紫塞，家人鑽火用青楓。秦城樓閣煙花裏，"]'),
('yuding-48','發潭州','杜甫','唐','御定全唐诗','yuding','','[]','夜醉長沙酒，曉行湘水春。岸花飛送客，檣燕語留人。',48,'御定全唐詩/json/233.json','["夜醉長沙酒，曉行湘水春。岸花飛送客，檣燕語留人。", "賈傅才未有，褚公書絕倫。高名前後事，回首一傷神。"]'),
('yuding-49','回棹','杜甫','唐','御定全唐诗','yuding','','[]','宿昔試安命，自私猶畏天。勞生系一物，為客費多年。',168,'御定全唐詩/json/233.json','["宿昔試安命，自私猶畏天。勞生系一物，為客費多年。", "衡嶽江湖大，蒸池疫癘偏。散才嬰薄俗，有跡負前賢。", "巾拂那關眼，瓶罍易滿船。火雲滋垢膩，凍雨裛沉綿。", "強飯蓴添滑，端居茗續煎。清思漢水上，涼憶峴山巔。", "順浪翻堪倚，回帆又省牽。吾家碑不昧，王氏井依然。", "几杖將衰齒，茅茨寄短椽。灌園曾取適，遊寺可終焉。", "遂性同漁父，成名異魯連。篙師煩爾送，朱夏及寒泉。"]'),
('yuding-50','贈韋七贊善','杜甫','唐','御定全唐诗','yuding','','[]','鄉里衣冠不乏賢，杜陵韋曲未央前。爾家最近魁三象，',40,'御定全唐詩/json/233.json','["鄉里衣冠不乏賢，杜陵韋曲未央前。爾家最近魁三象，", "洞庭春色悲公子，鰕菜忘歸範蠡船。"]'),
('yuding-51','奉酬寇十侍禦錫見寄四韻，複寄寇','杜甫','唐','御定全唐诗','yuding','','[]','往別郇瑕地，於今四十年。來簪禦府筆，故泊洞庭船。',48,'御定全唐詩/json/233.json','["往別郇瑕地，於今四十年。來簪禦府筆，故泊洞庭船。", "詩憶傷心處，春深把臂前。南瞻按百越，黃帽待君偏。"]'),
('yuding-52','酬郭十五受判官','杜甫','唐','御定全唐诗','yuding','','[]','才微歲老尚虛名，臥病江湖春複生。藥裹關心詩總廢，',40,'御定全唐詩/json/233.json','["才微歲老尚虛名，臥病江湖春複生。藥裹關心詩總廢，", "喬口橘洲風浪促，系帆何惜片時程。"]'),
('yuding-53','衡州送李大夫七丈勉赴廣州','杜甫','唐','御定全唐诗','yuding','','[]','斧鉞下青冥，樓船過洞庭。北風隨爽氣，南斗避文星。',48,'御定全唐詩/json/233.json','["斧鉞下青冥，樓船過洞庭。北風隨爽氣，南斗避文星。", "日月籠中鳥，乾坤水上萍。王孫丈人行，垂老見飄零。"]'),
('yuding-0','哭長孫侍禦','杜甫','唐','御定全唐诗','yuding','','[]','道為謀書重，名因賦頌雄。禮闈曾擢桂，憲府舊乘驄。',48,'御定全唐詩/json/234.json','["道為謀書重，名因賦頌雄。禮闈曾擢桂，憲府舊乘驄。", "流水生涯盡，浮雲世事空。唯餘舊台柏，蕭瑟九原中。"]'),
('yuding-1','虢國夫人','杜甫','唐','御定全唐诗','yuding','','[]','虢國夫人承主恩，平明上馬入宮門。',32,'御定全唐詩/json/234.json','["虢國夫人承主恩，平明上馬入宮門。", "卻嫌脂粉涴顏色，澹掃蛾眉朝至尊。"]'),
('yuding-2','軍中醉飲寄沈八、劉叟','杜甫','唐','御定全唐诗','yuding','','[]','酒渴愛江清，餘甘漱晚汀。軟沙欹坐穩，冷石醉眠醒。',48,'御定全唐詩/json/234.json','["酒渴愛江清，餘甘漱晚汀。軟沙欹坐穩，冷石醉眠醒。", "野膳隨行帳，華音發從伶。數杯君不見，醉已遣沉冥。"]'),
('yuding-3','杜鵑行','杜甫','唐','御定全唐诗','yuding','','[]','古時杜宇稱望帝，魂作杜鵑何微細。跳枝竄葉樹木中，',72,'御定全唐詩/json/234.json','["古時杜宇稱望帝，魂作杜鵑何微細。跳枝竄葉樹木中，", "隳形不敢棲華屋，短翮唯願巢深叢。穿皮啄朽觜欲禿，", "聲音咽咽如有謂，號啼略與嬰兒同。口幹垂血轉迫促，"]'),
('yuding-4','聞惠二過東溪特一送','杜甫','唐','御定全唐诗','yuding','','[]','惠子白駒瘦，歸溪唯病身。皇天無老眼，空穀滯斯人。',48,'御定全唐詩/json/234.json','["惠子白駒瘦，歸溪唯病身。皇天無老眼，空穀滯斯人。", "崖蜜松花熟，山杯竹葉新。柴門了無事，黃綺未稱臣。"]'),
('yuding-5','舟泛洞庭','杜甫','唐','御定全唐诗','yuding','','[]','蛟室圍青草，龍堆擁白沙。護江盤古木，迎棹舞神鴉。',48,'御定全唐詩/json/234.json','["蛟室圍青草，龍堆擁白沙。護江盤古木，迎棹舞神鴉。", "破浪南風正，收帆畏日斜。雲山千萬疊，底處上仙槎。"]'),
('yuding-6','李鹽鐵二首','杜甫','唐','御定全唐诗','yuding','','[]','落葉春風起，高城煙霧開。雜花分戶映，嬌燕入簷回。',48,'御定全唐詩/json/234.json','["落葉春風起，高城煙霧開。雜花分戶映，嬌燕入簷回。", "一見能傾產，虛懷只愛才。鹽官雖絆驥，名是漢庭來。"]'),
('yuding-7','長吟','杜甫','唐','御定全唐诗','yuding','','[]','江渚翻鷗戲，官橋帶柳陰。江飛競渡日，草見蹋春心。',48,'御定全唐詩/json/234.json','["江渚翻鷗戲，官橋帶柳陰。江飛競渡日，草見蹋春心。", "已撥形骸累，真為爛漫深。賦詩歌句穩，不免自長吟。"]'),
('yuding-8','絕句九首','杜甫','唐','御定全唐诗','yuding','','[]','聞道巴山裏，春船正好行。都將百年興，一望九江城。',72,'御定全唐詩/json/234.json','["聞道巴山裏，春船正好行。都將百年興，一望九江城。", "水檻溫江口，茅堂石筍西。移船先主廟，洗藥浣沙溪。", "設道春來好，狂風大放顛。吹花隨水去，翻卻釣魚船。"]'),
('yuding-9','瞿唐懷古','杜甫','唐','御定全唐诗','yuding','','[]','西南萬壑注，勍敵兩崖開。地與山根裂，江從月窟來。',48,'御定全唐詩/json/234.json','["西南萬壑注，勍敵兩崖開。地與山根裂，江從月窟來。", "削成當白帝，空曲隱陽臺。疏鑿功雖美，陶鈞力大哉。"]'),
('yuding-10','送司馬入京','杜甫','唐','御定全唐诗','yuding','','[]','群盜至今日，先朝忝從臣。歎君能戀主，久客羨歸秦。',48,'御定全唐詩/json/234.json','["群盜至今日，先朝忝從臣。歎君能戀主，久客羨歸秦。", "黃閣長司諫，丹墀有故人。向來論社稷，為話涕沾巾。"]'),
('yuding-11','惜別行送劉僕射判官','杜甫','唐','御定全唐诗','yuding','','[]','聞道南行市駿馬，不限匹數軍中須。襄陽幕府天下異，',137,'御定全唐詩/json/234.json','["聞道南行市駿馬，不限匹數軍中須。襄陽幕府天下異，", "而今西北自反胡，騏驎蕩盡一匹無。龍媒真種在帝都，", "江湖凡馬多憔悴，衣冠往往乘蹇驢。梁公富貴於身疏，", "以茲報主寸心赤，氣卻西戎回北狄。羅網群馬籍馬多，", "杜陵老翁秋系船，扶病相識長沙驛。強梳白髮提胡盧，", "當杯對客忍流涕，君不覺老夫神內傷。"]'),
('yuding-12','呀鶻行','杜甫','唐','御定全唐诗','yuding','','[]','病鶻孤飛俗眼醜，每夜江邊宿衰柳。清秋落日已側身，',48,'御定全唐詩/json/234.json','["病鶻孤飛俗眼醜，每夜江邊宿衰柳。清秋落日已側身，", "強神迷複皂雕前，俊才早在蒼鷹上。風濤颯颯寒山陰，"]'),
('yuding-13','狂歌行，贈四兄','杜甫','唐','御定全唐诗','yuding','','[]','與兄行年校一歲，賢者是兄愚者弟。兄將富貴等浮雲，',96,'御定全唐詩/json/234.json','["與兄行年校一歲，賢者是兄愚者弟。兄將富貴等浮雲，", "公卿朱門未開鎖，我曹已到肩相齊。吾兄睡穩方舒膝，", "今年思我來嘉州。嘉州酒重花繞樓。樓頭吃酒樓下臥，", "幅巾鞶帶不掛身，頭脂足垢何曾洗。吾兄吾兄巢許倫，"]'),
('yuding-14','逃難','杜甫','唐','御定全唐诗','yuding','','[]','五十頭白翁，南北逃世難。疏布纏枯骨，奔走苦不暖。',84,'御定全唐詩/json/234.json','["五十頭白翁，南北逃世難。疏布纏枯骨，奔走苦不暖。", "已衰病方入，四海一塗炭。乾坤萬里內，莫見容身畔。", "妻孥複隨我，回首共悲歎。故國莽丘墟，鄰里各分散。", "歸路從此迷，涕盡湘江岸。"]'),
('yuding-15','寄高適','杜甫','唐','御定全唐诗','yuding','','[]','楚隔乾坤遠，難招病客魂。詩名惟我共，世事與誰論。',48,'御定全唐詩/json/234.json','["楚隔乾坤遠，難招病客魂。詩名惟我共，世事與誰論。", "北闕更新主，南星落故園。定知相見日，爛漫倒芳尊。"]'),
('yuding-16','送靈州李判官','杜甫','唐','御定全唐诗','yuding','','[]','犬戎腥四海，回首一茫茫。血戰乾坤赤，氛迷日月黃。',48,'御定全唐詩/json/234.json','["犬戎腥四海，回首一茫茫。血戰乾坤赤，氛迷日月黃。", "將軍專策略，幕府盛材良。近賀中興主，神兵動朔方。"]'),
('yuding-17','與嚴二郎奉禮別','杜甫','唐','御定全唐诗','yuding','','[]','別君誰暖眼，將老病纏身。出涕同斜日，臨風看去塵。',72,'御定全唐詩/json/234.json','["別君誰暖眼，將老病纏身。出涕同斜日，臨風看去塵。", "商歌還入夜，巴俗自為鄰。尚愧微軀在，遙聞盛禮新。", "山東群盜散，闕下受降頻。諸將歸應盡，題書報旅人。"]'),
('yuding-18','巴西驛亭觀江漲，呈竇使君二首','杜甫','唐','御定全唐诗','yuding','','[]','轉驚波作怒，即恐岸隨流。賴有杯中物，還同海上鷗。',96,'御定全唐詩/json/234.json','["轉驚波作怒，即恐岸隨流。賴有杯中物，還同海上鷗。", "關心小剡縣，傍眼見揚州。為接情人飲，朝來減半愁。", "向晚波微綠，連空岸腳青。日兼春有暮，愁與醉無醒。", "漂泊猶杯酒，躊躇此驛亭。相看萬里外，同是一浮萍。"]'),
('yuding-19','遣憂','杜甫','唐','御定全唐诗','yuding','','[]','亂離知又甚，消息苦難真。受諫無今日，臨危憶古人。',48,'御定全唐詩/json/234.json','["亂離知又甚，消息苦難真。受諫無今日，臨危憶古人。", "紛紛乘白馬，攘攘著黃巾。隋氏留宮室，焚燒何太頻。"]'),
('yuding-20','早花','杜甫','唐','御定全唐诗','yuding','','[]','西京安穩未，不見一人來。臘日巴江曲，山花已自開。',48,'御定全唐詩/json/234.json','["西京安穩未，不見一人來。臘日巴江曲，山花已自開。", "盈盈當雪杏，豔豔待春梅。直苦風塵暗，誰憂容鬢催。"]'),
('yuding-21','巴山','杜甫','唐','御定全唐诗','yuding','','[]','巴山遇中使，雲自峽城來。盜賊還奔突，乘輿恐未回。',48,'御定全唐詩/json/234.json','["巴山遇中使，雲自峽城來。盜賊還奔突，乘輿恐未回。", "天寒邵伯樹，地闊望仙台。狼狽風塵裏，群臣安在哉。"]'),
('yuding-22','收京','杜甫','唐','御定全唐诗','yuding','','[]','複道收京邑，兼聞殺犬戎。衣冠卻扈從，車駕已還宮。',48,'御定全唐詩/json/234.json','["複道收京邑，兼聞殺犬戎。衣冠卻扈從，車駕已還宮。", "克復成如此，安危在數公。莫令回首地，慟哭起悲風。"]'),
('yuding-23','巴西聞收宮闕，送班司馬入京','杜甫','唐','御定全唐诗','yuding','','[]','聞道收宗廟，鳴鑾自陝歸。傾都看黃屋，正殿引朱衣。',48,'御定全唐詩/json/234.json','["聞道收宗廟，鳴鑾自陝歸。傾都看黃屋，正殿引朱衣。", "劍外春天遠，巴西敕使稀。念君經世亂，匹馬向王畿。"]'),
('yuding-24','花底','杜甫','唐','御定全唐诗','yuding','','[]','紫萼扶千蕊，黃須照萬花。忽疑行暮雨，何事入朝霞。',48,'御定全唐詩/json/234.json','["紫萼扶千蕊，黃須照萬花。忽疑行暮雨，何事入朝霞。", "恐是潘安縣，堪留衛玠車。深知好顏色，莫作委泥沙。"]'),
('yuding-25','柳邊','杜甫','唐','御定全唐诗','yuding','','[]','只道梅花發，那知柳亦新。枝枝總到地，葉葉自開春。',48,'御定全唐詩/json/234.json','["只道梅花發，那知柳亦新。枝枝總到地，葉葉自開春。", "紫燕時翻翼，黃鸝不露身。漢南應老盡，霸上遠愁人。"]'),
('yuding-26','送竇九歸成都','杜甫','唐','御定全唐诗','yuding','','[]','文章亦不盡，竇子才縱橫。非爾更苦節，何人符大名。',48,'御定全唐詩/json/234.json','["文章亦不盡，竇子才縱橫。非爾更苦節，何人符大名。", "讀書雲閣觀，問絹錦官城。我有浣花竹，題詩須一行。"]'),
('yuding-27','贈裴南部，聞袁判官自來欲有按問','杜甫','唐','御定全唐诗','yuding','','[]','塵滿萊蕪甑，堂橫單父琴。人皆知飲水，公輩不偷金。',72,'御定全唐詩/json/234.json','["塵滿萊蕪甑，堂橫單父琴。人皆知飲水，公輩不偷金。", "梁獄書因上，秦台鏡欲臨。獨醒時所嫉，群小謗能深。", "即出黃沙在，何須白髮侵。使君傳舊德，已見直繩心。"]'),
('yuding-28','奉使崔都水翁下峽','杜甫','唐','御定全唐诗','yuding','','[]','無數涪江筏，鳴橈總發時。別離終不久，宗族忍相遺。',48,'御定全唐詩/json/234.json','["無數涪江筏，鳴橈總發時。別離終不久，宗族忍相遺。", "白狗黃牛峽，朝雲暮雨祠。所過頻問訊，到日自題詩。"]'),
('yuding-29','題郪縣郭三十二明府茅屋壁','杜甫','唐','御定全唐诗','yuding','','[]','江頭且系船，為爾獨相憐。雲散灌壇雨，春青彭澤田。',48,'御定全唐詩/json/234.json','["江頭且系船，為爾獨相憐。雲散灌壇雨，春青彭澤田。", "頻驚適小國，一擬問高天。別後巴東路，逢人問幾賢。"]'),
('yuding-30','遣悶戲呈路十九曹長','杜甫','唐','御定全唐诗','yuding','','[]','江浦雷聲喧昨夜，春城雨色動微寒。黃鸝並坐交愁濕，',40,'御定全唐詩/json/234.json','["江浦雷聲喧昨夜，春城雨色動微寒。黃鸝並坐交愁濕，", "惟吾最愛清狂客，百遍相看意未闌。"]'),
('yuding-31','隨章留後新亭會送諸君','杜甫','唐','御定全唐诗','yuding','','[]','新亭有高會，行子得良時。日動映江幕，風鳴排檻旗。',48,'御定全唐詩/json/234.json','["新亭有高會，行子得良時。日動映江幕，風鳴排檻旗。", "絕葷終不改，勸酒欲無詞。已墮峴山淚，因題零雨詩。"]'),
('yuding-32','東津送韋諷攝閬州錄事','杜甫','唐','御定全唐诗','yuding','','[]','聞說江山好，憐君吏隱兼。寵行舟遠泛，怯別酒頻添。',48,'御定全唐詩/json/234.json','["聞說江山好，憐君吏隱兼。寵行舟遠泛，怯別酒頻添。", "推薦非承乏，操持必去嫌。他時如按縣，不得慢陶潛。"]'),
('yuding-33','客舊館','杜甫','唐','御定全唐诗','yuding','','[]','陳跡隨人事，初秋別此亭。重來梨葉赤，依舊竹林青。',48,'御定全唐詩/json/234.json','["陳跡隨人事，初秋別此亭。重來梨葉赤，依舊竹林青。", "風幔何時卷，寒砧昨夜聲。無由出江漢，愁緒月冥冥。"]'),
('yuding-34','閬州奉送二十四舅使自京赴任青城','杜甫','唐','御定全唐诗','yuding','','[]','聞道王喬舄，名因太史傳。如何碧雞使，把詔紫微天。',48,'御定全唐詩/json/234.json','["聞道王喬舄，名因太史傳。如何碧雞使，把詔紫微天。", "秦嶺愁回馬，涪江醉泛船。青城漫汙雜，吾舅意淒然。"]'),
('yuding-35','愁坐','杜甫','唐','御定全唐诗','yuding','','[]','高齋常見野，愁坐更臨門。十月山寒重，孤城月水昏。',48,'御定全唐詩/json/234.json','["高齋常見野，愁坐更臨門。十月山寒重，孤城月水昏。", "葭萌氐種迥，左擔犬戎存。終日憂奔走，歸期未敢論。"]'),
('yuding-36','陪鄭公秋晚北池臨眺','杜甫','唐','御定全唐诗','yuding','','[]','北池雲水闊，華館辟秋風。獨鶴元依渚，衰荷且映空。',120,'御定全唐詩/json/234.json','["北池雲水闊，華館辟秋風。獨鶴元依渚，衰荷且映空。", "采菱寒刺上，蹋藕野泥中。素楫分曹往，金盤小徑通。", "萋萋露草碧，片片晚旗紅。杯酒沾津吏，衣裳與釣翁。", "異方初豔菊，故里亦高桐。搖落關山思，淹留戰伐功。", "嚴城殊未掩，清宴已知終。何補參卿事，歡娛到薄躬。"]'),
('yuding-37','去蜀','杜甫','唐','御定全唐诗','yuding','','[]','五載客蜀郡，一年居梓州。如何關塞阻，轉作瀟湘遊。',48,'御定全唐詩/json/234.json','["五載客蜀郡，一年居梓州。如何關塞阻，轉作瀟湘遊。", "世事已黃發，殘生隨白鷗。安危大臣在，不必淚長流。"]'),
('yuding-38','放船','杜甫','唐','御定全唐诗','yuding','','[]','收帆下急水，卷幔逐回灘。江市戎戎暗，山雲淰淰寒。',48,'御定全唐詩/json/234.json','["收帆下急水，卷幔逐回灘。江市戎戎暗，山雲淰淰寒。", "村荒無徑入，獨鳥怪人看。已泊城樓底，何曾夜色闌。"]'),
('yuding-39','哭台州鄭司戶蘇少監','杜甫','唐','御定全唐诗','yuding','','[]','故舊誰憐我，平生鄭與蘇。存亡不重見，喪亂獨前途。',264,'御定全唐詩/json/234.json','["故舊誰憐我，平生鄭與蘇。存亡不重見，喪亂獨前途。", "豪俊何人在，文章掃地無。羈遊萬里闊，凶問一年俱。", "白首中原上，清秋大海隅。夜台當北斗，泉路著東吳。", "得罪台州去，時危棄碩儒。移官蓬閣後，穀貴沒潛夫。", "流慟嗟何及，銜冤有是夫。道消詩興廢，心息酒為徒。", "許與才雖薄，追隨跡未拘。班揚名甚盛，嵇阮逸相須。", "會取君臣合，寧銓品命殊。賢良不必展，廊廟偶然趨。", "勝決風塵際，功安造化爐。從容拘舊學，慘澹閟陰符。", "擺落嫌疑久，哀傷志力輸。俗依綿穀異，客對雪山孤。", "童稚思諸子，交朋列友于。情乖清酒送，望絕撫墳呼。", "瘧病餐巴水，瘡痍老蜀都。飄零迷哭處，天地日榛蕪。"]'),
('yuding-40','送王侍禦往東川，放生池祖席','杜甫','唐','御定全唐诗','yuding','','[]','東川詩友合，此贈怯輕為。況複傳宗近，空然惜別離。',48,'御定全唐詩/json/234.json','["東川詩友合，此贈怯輕為。況複傳宗近，空然惜別離。", "梅花交近野，草色向平池。倘憶江邊臥，歸期願早知。"]'),
('yuding-41','惠義寺送王少尹赴成都','杜甫','唐','御定全唐诗','yuding','','[]','苒苒穀中寺，娟娟林表峰。闌幹上處遠，結構坐來重。',48,'御定全唐詩/json/234.json','["苒苒穀中寺，娟娟林表峰。闌幹上處遠，結構坐來重。", "騎馬行春徑，衣冠起晚鐘。雲門青寂寂，此別惜相從。"]'),
('yuding-42','避地','杜甫','唐','御定全唐诗','yuding','','[]','避地歲時晚，竄身筋骨勞。詩書遂牆壁，奴僕且旌旄。',48,'御定全唐詩/json/234.json','["避地歲時晚，竄身筋骨勞。詩書遂牆壁，奴僕且旌旄。", "行在僅聞信，此生隨所遭。神堯舊天下，會見出腥臊。"]'),
('yuding-43','惠義寺園送辛員外','杜甫','唐','御定全唐诗','yuding','','[]','朱櫻此日垂朱實，郭外誰家負郭田。',32,'御定全唐詩/json/234.json','["朱櫻此日垂朱實，郭外誰家負郭田。", "萬里相逢貪握手，高才卻望足離筵。"]'),
('yuding-44','又送','杜甫','唐','御定全唐诗','yuding','','[]','雙峰寂寂對春台，萬竹青青照客杯。細草留連侵坐軟，',40,'御定全唐詩/json/234.json','["雙峰寂寂對春台，萬竹青青照客杯。細草留連侵坐軟，", "直到綿州始分首，江邊樹裏共誰來。"]'),
('yuding-45','九日登梓州城','杜甫','唐','御定全唐诗','yuding','','[]','客心驚暮序，賓雁下襄州。共賞重陽節，言尋戲馬遊。',48,'御定全唐詩/json/234.json','["客心驚暮序，賓雁下襄州。共賞重陽節，言尋戲馬遊。", "湖風秋戍柳，江雨暗山樓。且酌東籬菊，聊祛南國愁。"]'),
('yuding-46','闕題','杜甫','唐','御定全唐诗','yuding','','[]','三月雪連夜，未應傷物華。只緣春欲盡，留著伴梨花。',24,'御定全唐詩/json/234.json','["三月雪連夜，未應傷物華。只緣春欲盡，留著伴梨花。"]'),
('yuding-47','句','杜甫','唐','御定全唐诗','yuding','','[]','寒食少天氣，東風多柳花。',24,'御定全唐詩/json/234.json','["寒食少天氣，東風多柳花。", "小桃知客意，春盡始開花。"]'),
('yuding-0','自蜀奉冊命往朔方途中呈韋左相文部房尚書門下崔侍郎','賈至','唐','御定全唐诗','yuding','','[]','胡羯亂中夏，鑾輿忽南巡。衣冠陷戎寇，狼狽隨風塵。',360,'御定全唐詩/json/235.json','["胡羯亂中夏，鑾輿忽南巡。衣冠陷戎寇，狼狽隨風塵。", "豳公秉大節，臨難不顧身。激昂白刃前，濺血下沾巾。", "尚書抱忠義，歷險披荊榛。扈從出劍門，登翼岷江濱。", "時望挹侍郎，公才標縉紳。亭亭昆山玉，皎皎無緇磷。", "顧惟乏經濟，扞牧陪從臣。永願雪會稽，仗劍清咸秦。", "太皇時內禪，神器付嗣君。新命集舊邦，至德被遠人。", "捧冊自南服，奉詔趨北軍。覲謁心載馳，違離難重陳。", "策馬出蜀山，畏途上緣雲。飲啄叢箐間，棲息虎豹群。", "崎嶇淩危棧，惴栗驚心神。峭壁上嶔岑，大江下沄沄。", "皇風扇八極，異類懷深仁。元兇誘黠虜，肘腋生妖氛。", "明主信英武，威聲赫四鄰。誓師自朔方，旗幟何繽紛。", "鐵騎照白日，旄頭拂秋旻。將來蕩滄溟，寧止蹴昆侖。", "古來有屯難，否泰長相因。夏康纘禹績，代祖複漢勳。", "于役各勤王，驅馳拱紫宸。豈惟太公望，往昔逢周文。", "誰謂三傑才，功業獨殊倫。感此慰行邁，無為歌苦辛。"]'),
('yuding-1','贈裴九侍禦昌江草堂彈琴','賈至','唐','御定全唐诗','yuding','','[]','朔風吹疏林，積雪在崖巘。鳴琴草堂響，小澗清且淺。',48,'御定全唐詩/json/235.json','["朔風吹疏林，積雪在崖巘。鳴琴草堂響，小澗清且淺。", "沉吟東山意，欲去芳歲晚。悵望黃綺心，白雲若在眼。"]'),
('yuding-2','巴陵早秋，寄荊州崔司馬、吏部閻功曹舍人','賈至','唐','御定全唐诗','yuding','','[]','謫居瀟湘渚，再見洞庭秋。極目連江漢，西南浸鬥牛。',180,'御定全唐詩/json/235.json','["謫居瀟湘渚，再見洞庭秋。極目連江漢，西南浸鬥牛。", "滔滔蕩雲夢，澹澹搖巴丘。曠如臨渤澥，窅疑造瀛洲。", "君山麗中波，蒼翠長夜浮。帝子去永久，楚詞尚悲秋。", "我同長沙行，時事加百憂。登高望舊國，胡馬滿東周。", "宛葉遍蓬蒿，樊鄧無良疇。獨攀青楓樹，淚灑滄江流。", "故人西掖寮，同扈岐陽搜。差池盡三黜，蹭蹬各南州。", "相去雖地接，不得從之遊。耿耿雲陽臺，迢迢王粲樓。", "跂予暮霞裏，誰謂無輕舟。"]'),
('yuding-3','閒居秋懷，寄陽翟陸贊府、封丘高少府','賈至','唐','御定全唐诗','yuding','','[]','今日霖雨霽，颯然高館涼。秋風吹二毛，烈士加慨慷。',240,'御定全唐詩/json/235.json','["今日霖雨霽，颯然高館涼。秋風吹二毛，烈士加慨慷。", "憶昔皇運初，眾賓俱龍驤。解巾佐幕府，脫劍升明堂。", "鬱鬱被慶雲，昭昭翼太陽。鯨魚縱大壑，鸑鷟鳴高岡。", "信矣草創時，泰階速賢良。一言頓遭逢，片善蒙恩光。", "我生屬聖明，感激竊自強。崎嶇郡邑權，連騫翰墨場。", "天朝富英髦，多士如珪璋。盛才溢下位，蹇步徒倡狂。", "閉門對群書，幾案在我旁。枕席相遠遊，聊欲浮滄浪。", "八月白露降，玄蟬號枯桑。艤舟臨清川，迢遞愁思長。", "我有同懷友，各在天一方。離披不相見，浩蕩隔兩鄉。", "平生霞外期，宿昔共行藏。豈無蓬萊樹，歲晏空蒼蒼。"]'),
('yuding-4','送友人使河源','賈至','唐','御定全唐诗','yuding','','[]','送君魯郊外，下車上高丘。蕭條千里暮，日落黃雲秋。',48,'御定全唐詩/json/235.json','["送君魯郊外，下車上高丘。蕭條千里暮，日落黃雲秋。", "舉酒有餘恨，論邊無遠謀。河源望不見，旌旆去悠悠。"]'),
('yuding-5','送李侍禦','賈至','唐','御定全唐诗','yuding','','[]','我年四十餘，已歎前路短。羈離洞庭上，安得不引滿。',48,'御定全唐詩/json/235.json','["我年四十餘，已歎前路短。羈離洞庭上，安得不引滿。", "李侯忘情者，與我同疏懶。孤帆泣瀟湘，望遠心欲斷。"]'),
('yuding-6','送耿副使歸長沙','賈至','唐','御定全唐诗','yuding','','[]','畫舸欲南歸，江亭且留宴。日暮湖上雲，蕭蕭若流霰。',48,'御定全唐詩/json/235.json','["畫舸欲南歸，江亭且留宴。日暮湖上雲，蕭蕭若流霰。", "昨夜相知者，明發不可見。惆悵西北風，高帆為誰扇。"]'),
('yuding-7','送夏侯子之江夏','賈至','唐','御定全唐诗','yuding','','[]','扣楫洞庭上，清風千里來。留歡一杯酒，欲別複裴回。',48,'御定全唐詩/json/235.json','["扣楫洞庭上，清風千里來。留歡一杯酒，欲別複裴回。", "相見楚山下，漁舟憶釣台。羨君還舊裏，歸念獨悠哉。"]'),
('yuding-8','寓言二首','賈至','唐','御定全唐诗','yuding','','[]','春草紛碧色，佳人曠無期。悠哉千里心，欲采商山芝。',132,'御定全唐詩/json/235.json','["春草紛碧色，佳人曠無期。悠哉千里心，欲采商山芝。", "歎息良會晚，如何桃李時。懷君晴川上，佇立夏雲滋。", "凜凜秋閨夕，綺羅早知寒。玉砧調鳴杵，始搗機中紈。", "憶昨別離日，桐花覆井欄。今來思君時，白露盈階漙。", "聞有關河信，欲寄雙玉盤。玉以委貞心，盤以薦嘉餐。", "嗟君在萬里，使妾衣帶寬。"]'),
('yuding-9','燕歌行','賈至','唐','御定全唐诗','yuding','','[]','國之重鎮惟幽都，東威九夷北制胡。五軍精卒三十萬，',120,'御定全唐詩/json/235.json','["國之重鎮惟幽都，東威九夷北制胡。五軍精卒三十萬，", "昔時燕山重賢士，黃金築台從隗始。倏忽興王定薊丘，", "我唐區夏餘十紀，軍容武備赫萬祀。彤弓黃鉞授元帥，", "千營萬隊連旌旗，望之如火忽電馳。匈奴懾竄窮發北，", "六軍將士皆死盡，戰馬空鞍歸故營。時移道革天下平，"]'),
('yuding-10','巴陵寄李二戶部、張十四禮部','賈至','唐','御定全唐诗','yuding','','[]','江南春草初冪冪，愁殺江南獨愁客。秦中楊柳也應新，',24,'御定全唐詩/json/235.json','["江南春草初冪冪，愁殺江南獨愁客。秦中楊柳也應新，"]'),
('yuding-11','長門怨','賈至','唐','御定全唐诗','yuding','','[]','獨坐思千里，春庭曉景長。鶯喧翡翠幕，柳覆郁金堂。',48,'御定全唐詩/json/235.json','["獨坐思千里，春庭曉景長。鶯喧翡翠幕，柳覆郁金堂。", "舞蝶縈愁緒，繁花對靚妝。深情托瑤瑟，弦斷不成章。"]'),
('yuding-12','銅雀台','賈至','唐','御定全唐诗','yuding','','[]','日暮銅台靜，西陵鳥雀歸。撫弦心斷絕，聽管淚霏微。',48,'御定全唐詩/json/235.json','["日暮銅台靜，西陵鳥雀歸。撫弦心斷絕，聽管淚霏微。", "靈幾臨朝奠，空床卷夜衣。蒼蒼川上月，應照妾魂飛。"]'),
('yuding-13','侍宴曲','賈至','唐','御定全唐诗','yuding','','[]','雲陛褰珠扆，天墀覆綠楊。隔簾妝隱映，向席舞低昂。',48,'御定全唐詩/json/235.json','["雲陛褰珠扆，天墀覆綠楊。隔簾妝隱映，向席舞低昂。", "鳴佩長廊靜，開冰廣殿涼。歡餘劍履散，同輦入昭陽。"]'),
('yuding-14','對酒麴二首','賈至','唐','御定全唐诗','yuding','','[]','梅發柳依依，黃鸝曆亂飛。當歌憐景色，對酒惜芳菲。',96,'御定全唐詩/json/235.json','["梅發柳依依，黃鸝曆亂飛。當歌憐景色，對酒惜芳菲。", "曲水浮花氣，流風散舞衣。通宵留暮雨，上客莫言歸。", "春來酒味濃，舉酒對春叢。一酌千憂散，三杯萬事空。", "放歌乘美景，醉舞向東風。寄語尊前客，生涯任轉蓬。"]'),
('yuding-15','送陸協律赴端州','賈至','唐','御定全唐诗','yuding','','[]','越井人南去，湘川水北流。江邊數杯酒，海內一孤舟。',48,'御定全唐詩/json/235.json','["越井人南去，湘川水北流。江邊數杯酒，海內一孤舟。", "嶺嶠同仙客，京華即舊遊。春心將別恨，萬里共悠悠。"]'),
('yuding-16','送王員外赴長沙','賈至','唐','御定全唐诗','yuding','','[]','攜手登臨處，巴陵天一隅。春生雲夢澤，水溢洞庭湖。',48,'御定全唐詩/json/235.json','["攜手登臨處，巴陵天一隅。春生雲夢澤，水溢洞庭湖。", "共歎虞翻枉，同悲阮籍途。長沙舊卑濕，今古不應殊。"]'),
('yuding-17','送夏侯參軍赴廣州','賈至','唐','御定全唐诗','yuding','','[]','聞道衡陽外，由來雁不飛。送君從此去，書信定應稀。',48,'御定全唐詩/json/235.json','["聞道衡陽外，由來雁不飛。送君從此去，書信定應稀。", "雲海南溟遠，煙波北渚微。勉哉孫楚吏，彩服正光輝。"]'),
('yuding-18','長沙別李六侍禦','賈至','唐','御定全唐诗','yuding','','[]','月明湘水白，霜落洞庭幹。放逐長沙外，相逢路正難。',48,'御定全唐詩/json/235.json','["月明湘水白，霜落洞庭幹。放逐長沙外，相逢路正難。", "雲歸帝鄉遠，雁報朔方寒。此別盈襟淚，雍門不假彈。"]'),
('yuding-19','岳陽樓宴王員外貶長沙','賈至','唐','御定全唐诗','yuding','','[]','極浦三春草，高樓萬里心。楚山晴靄碧，湘水暮流深。',48,'御定全唐詩/json/235.json','["極浦三春草，高樓萬里心。楚山晴靄碧，湘水暮流深。", "忽與朝中舊，同為澤畔吟。停杯試北望，還欲淚沾襟。"]'),
('yuding-20','詠馮昭儀當熊','賈至','唐','御定全唐诗','yuding','','[]','白羽插雕弓，霓旌動朔風。平明出金屋，扈輦上林中。',48,'御定全唐詩/json/235.json','["白羽插雕弓，霓旌動朔風。平明出金屋，扈輦上林中。", "逐獸長廊靜，呼鷹御苑空。王孫莫諫獵，賤妾解當熊。"]'),
('yuding-21','早朝大明宮呈兩省僚友','賈至','唐','御定全唐诗','yuding','','[]','銀燭熏天紫陌長，禁城春色曉蒼蒼。千條弱柳垂青瑣，',40,'御定全唐詩/json/235.json','["銀燭熏天紫陌長，禁城春色曉蒼蒼。千條弱柳垂青瑣，", "共沐恩波鳳池上，朝朝染翰侍君王。"]'),
('yuding-22','白馬','賈至','唐','御定全唐诗','yuding','','[]','白馬紫連錢，嘶鳴丹闕前。聞珂自蹀躞，不要下金鞭。',24,'御定全唐詩/json/235.json','["白馬紫連錢，嘶鳴丹闕前。聞珂自蹀躞，不要下金鞭。"]'),
('yuding-23','贈薛瑤英','賈至','唐','御定全唐诗','yuding','','[]','舞怯銖衣重，笑疑桃臉開。方知漢成帝，虛築避風台。',24,'御定全唐詩/json/235.json','["舞怯銖衣重，笑疑桃臉開。方知漢成帝，虛築避風台。"]'),
('yuding-24','出塞曲','賈至','唐','御定全唐诗','yuding','','[]','萬里平沙一聚塵，南飛羽檄北來人。',32,'御定全唐詩/json/235.json','["萬里平沙一聚塵，南飛羽檄北來人。", "傳道五原烽火急，單于昨夜寇新秦。"]'),
('yuding-25','春思二首','賈至','唐','御定全唐诗','yuding','','[]','草色青青柳色黃，桃花曆亂李花香。',64,'御定全唐詩/json/235.json','["草色青青柳色黃，桃花曆亂李花香。", "東風不為吹愁去，春日偏能惹恨長。", "紅粉當壚弱柳垂，金花臘酒解酴醿。", "笙歌日暮能留客，醉殺長安輕薄兒。"]'),
('yuding-26','勤政樓觀樂','賈至','唐','御定全唐诗','yuding','','[]','銀河帝女下三清，紫禁笙歌出九城。',32,'御定全唐詩/json/235.json','["銀河帝女下三清，紫禁笙歌出九城。", "為報延州來聽樂，須知天下欲升平。"]'),
('yuding-27','贈陝掾梁宏','賈至','唐','御定全唐诗','yuding','','[]','梁子工文四十年，詩顛名過草書顛。',32,'御定全唐詩/json/235.json','["梁子工文四十年，詩顛名過草書顛。", "白頭仍作功曹掾，祿薄難供沽酒錢。"]'),
('yuding-28','答嚴大夫','賈至','唐','御定全唐诗','yuding','','[]','今夕秦天一雁來，梧桐墜葉擣衣催。',32,'御定全唐詩/json/235.json','["今夕秦天一雁來，梧桐墜葉擣衣催。", "思君獨步華亭月，舊館秋陰生綠苔。"]'),
('yuding-29','送李侍郎赴常州','賈至','唐','御定全唐诗','yuding','','[]','雪晴雲散北風寒，楚水吳山道路難。',32,'御定全唐詩/json/235.json','["雪晴雲散北風寒，楚水吳山道路難。", "今日送君須盡醉，明朝相憶路漫漫。"]'),
('yuding-30','初至巴陵與李十二白、裴九同泛洞庭湖三首','賈至','唐','御定全唐诗','yuding','','[]','江上相逢皆舊遊，湘山永望不堪愁。',96,'御定全唐詩/json/235.json','["江上相逢皆舊遊，湘山永望不堪愁。", "明月秋風洞庭水，孤鴻落葉一扁舟。", "楓岸紛紛落葉多，洞庭秋水晚來波。", "乘興輕舟無近遠，白雲明月吊湘娥。", "江畔楓葉初帶霜，渚邊菊花亦已黃。", "輕舟落日興不盡，三湘五湖意何長。"]'),
('yuding-31','西亭春望','賈至','唐','御定全唐诗','yuding','','[]','日長風暖柳青青，北雁歸飛入窅冥。',32,'御定全唐詩/json/235.json','["日長風暖柳青青，北雁歸飛入窅冥。", "岳陽城上聞吹笛，能使春心滿洞庭。"]'),
('yuding-32','君山','賈至','唐','御定全唐诗','yuding','','[]','湘中老人讀黃老，手援紫藟坐碧草。',32,'御定全唐詩/json/235.json','["湘中老人讀黃老，手援紫藟坐碧草。", "春至不知湖水深，日暮忘卻巴陵道。"]'),
('yuding-33','洞庭送李十二赴零陵','賈至','唐','御定全唐诗','yuding','','[]','今日相逢落葉前，洞庭秋水遠連天。',32,'御定全唐詩/json/235.json','["今日相逢落葉前，洞庭秋水遠連天。", "共說金華舊遊處，回看北斗欲潸然。"]'),
('yuding-34','江南送李卿','賈至','唐','御定全唐诗','yuding','','[]','雙鶴南飛度楚山，楚南相見憶秦關。',32,'御定全唐詩/json/235.json','["雙鶴南飛度楚山，楚南相見憶秦關。", "願值回風吹羽翼，早隨陽雁及春還。"]'),
('yuding-35','送王道士還京','賈至','唐','御定全唐诗','yuding','','[]','一片仙雲入帝鄉，數聲秋雁至衡陽。',32,'御定全唐詩/json/235.json','["一片仙雲入帝鄉，數聲秋雁至衡陽。", "借問清都舊花月，豈知遷客泣瀟湘。"]'),
('yuding-36','巴陵夜別王八員外','賈至','唐','御定全唐诗','yuding','','[]','柳絮飛時別洛陽，梅花發後到三湘。',32,'御定全唐詩/json/235.json','["柳絮飛時別洛陽，梅花發後到三湘。", "世情已逐浮雲散，離恨空隨江水長。"]'),
('yuding-37','別裴九弟','賈至','唐','御定全唐诗','yuding','','[]','西江萬里向東流，今夜江邊駐客舟。',32,'御定全唐詩/json/235.json','["西江萬里向東流，今夜江邊駐客舟。", "月色更添春色好，蘆風似勝竹風幽。"]'),
('yuding-38','送南給事貶崖州','賈至','唐','御定全唐诗','yuding','','[]','疇昔丹墀與鳳池，即今相見兩相悲。',32,'御定全唐詩/json/235.json','["疇昔丹墀與鳳池，即今相見兩相悲。", "朱崖雲夢三千里，欲別俱為慟哭時。"]'),
('yuding-39','重別南給事','賈至','唐','御定全唐诗','yuding','','[]','謫宦三年尚未回，故人今日又重來。',32,'御定全唐詩/json/235.json','["謫宦三年尚未回，故人今日又重來。", "聞道崖州一千里，今朝須盡數千杯。"]'),
('yuding-40','岳陽樓重宴別王八員外貶長沙','賈至','唐','御定全唐诗','yuding','','[]','江路東連千里潮，青雲北望紫微遙。',32,'御定全唐詩/json/235.json','["江路東連千里潮，青雲北望紫微遙。", "莫道巴陵湖水闊，長沙南畔更蕭條。"]'),
('yuding-0','紫參歌','錢起','唐','御定全唐诗','yuding','','[]','遠公林下滿青苔，春藥偏宜間石開。往往幽人尋水見，',64,'御定全唐詩/json/236.json','["遠公林下滿青苔，春藥偏宜間石開。往往幽人尋水見，", "春風宛轉虎溪傍，紫翼紅翹翻霽光。貝葉經前無住色，", "應知仙卉老雲霞，莫賞夭桃滿蹊徑。"]'),
('yuding-1','瑪瑙杯歌','錢起','唐','御定全唐诗','yuding','','[]','瑤溪碧岸生奇寶，剖質披心出文藻。良工雕飾明且鮮，',73,'御定全唐詩/json/236.json','["瑤溪碧岸生奇寶，剖質披心出文藻。良工雕飾明且鮮，", "繁弦急管催獻酬，倏若飛空生羽翼，fY々蘭英照豹斑，", "王孫彩筆題新詠，碎錦連珠複輝映。世情貴耳不貴奇，"]'),
('yuding-2','鋤藥詠','錢起','唐','御定全唐诗','yuding','','[]','蒔藥穿林複在巘，濃香秀色深能淺。雲氣垂來浥露偏，',72,'御定全唐詩/json/236.json','["蒔藥穿林複在巘，濃香秀色深能淺。雲氣垂來浥露偏，", "不隨飛鳥緣枝去，如笑幽人出穀來。對之不覺忘疏懶，", "但使芝蘭出蕭艾，不辭手足皆胼胝。甯學陶潛空嗜酒，"]'),
('yuding-3','病鶴篇','錢起','唐','御定全唐诗','yuding','','[]','獨鶴聲哀羽摧折，沙頭一點留殘雪。三山侶伴能遠翔，',64,'御定全唐詩/json/236.json','["獨鶴聲哀羽摧折，沙頭一點留殘雪。三山侶伴能遠翔，", "不及川鳧長比翼，隨波雙泛複雙歸。碧海滄江深且廣，", "何時白霧卷青天，接影追飛太液前。"]'),
('yuding-4','片玉篇','錢起','唐','御定全唐诗','yuding','','[]','至寶未為代所奇，韞靈示璞荊山陲。獨使虹光天子識，',72,'御定全唐詩/json/236.json','["至寶未為代所奇，韞靈示璞荊山陲。獨使虹光天子識，", "空山埋照凡幾年，古色蒼痕宛自然。重溪冪冪暗雲樹，", "試勞香袖拂莓苔，不覺清心皎冰雪。連城美價幸逢時，"]'),
('yuding-5','畫鶴篇','錢起','唐','御定全唐诗','yuding','','[]','點素凝姿任畫工，霜毛玉羽照簾櫳。借問飛鳴華表上，',48,'御定全唐詩/json/236.json','["點素凝姿任畫工，霜毛玉羽照簾櫳。借問飛鳴華表上，", "爐氣朝成緱嶺雲，銀燈夜作華亭月。日暖花明梁燕歸，"]'),
('yuding-6','秋霖曲','錢起','唐','御定全唐诗','yuding','','[]','君不見聖主旰食憂元元，秋風苦雨暗九門。',91,'御定全唐詩/json/236.json','["君不見聖主旰食憂元元，秋風苦雨暗九門。", "鳳凰池裏沸泉騰，蒼龍闕下生雲根。陰精離畢太淹度，", "公卿紅粒爨丹桂，黔首白骨封青苔。貂裘玉食張公子，", "鶴鳴蛙躍正及時，豹隱蘭凋亦可悲。焉得太阿決屏翳，"]'),
('yuding-7','白石枕','錢起','唐','御定全唐诗','yuding','','[]','琢瑉勝水碧，所貴素且貞。曾無白圭玷，不作浮磬鳴。',72,'御定全唐詩/json/236.json','["琢瑉勝水碧，所貴素且貞。曾無白圭玷，不作浮磬鳴。", "捧來太陽前，一片新冰清。沉沉風憲地，待爾秋已至。", "璞堅難為功，誰怨晚成器。比德無磷緇，論交亦如此。"]'),
('yuding-8','賦得青城山歌，送楊、杜二郎中赴蜀軍','錢起','唐','御定全唐诗','yuding','','[]','蜀山西南千萬重，仙經最說青城峰。青城嶔岑倚空碧，',48,'御定全唐詩/json/236.json','["蜀山西南千萬重，仙經最說青城峰。青城嶔岑倚空碧，", "星台二妙逐王師，阮瑀軍書王粲詩。日落猿聲連玉笛，"]'),
('yuding-9','送李大夫赴廣州','錢起','唐','御定全唐诗','yuding','','[]','一賢間氣生，麟趾鳳凰羽。何意人之望，未為王者輔。',192,'御定全唐詩/json/236.json','["一賢間氣生，麟趾鳳凰羽。何意人之望，未為王者輔。", "出鎮忽推才，盛哉文且武。南越寄維城，雄雄擁甲兵。", "鼓門通幕府，天井入軍營。厥俗多豪侈，古來難致禮。", "唯君飲冰心，可酌貪泉水。忠臣感聖君，徇義不邀勳。", "龍鏡逃山魅，霜風破嶂雪。征途凡幾轉，魏闕如在眼。", "向郡海潮迎，指鄉關樹遠。按節化甌閩，下車佳政新。", "應令尉陀俗，還作上皇人。支離交俊哲，弱冠至華髮。", "昔許霄漢期，今嗟鵬鷃別。圖南不可禦，惆悵守薄暮。"]'),
('yuding-10','送崔校書從軍','錢起','唐','御定全唐诗','yuding','','[]','雁門太守能愛賢，麟閣書生亦投筆。甯唯玉劍報知己，',48,'御定全唐詩/json/236.json','["雁門太守能愛賢，麟閣書生亦投筆。甯唯玉劍報知己，", "燕南春草傷心色，薊北黃雲滿眼愁。聞道輕生能擊虜，"]'),
('yuding-11','送張將軍征西','錢起','唐','御定全唐诗','yuding','','[]','長安少年唯好武，金殿承恩爭破虜。沙場烽火隔天山，',48,'御定全唐詩/json/236.json','["長安少年唯好武，金殿承恩爭破虜。沙場烽火隔天山，", "玉笛聲悲離酌晚，金方路極行人遠。計日霜戈盡敵歸，"]'),
('yuding-12','送修武元少府','錢起','唐','御定全唐诗','yuding','','[]','寸祿榮色養，此行寧嘆惜。自今黃綬采蘭時，',36,'御定全唐詩/json/236.json','["寸祿榮色養，此行寧嘆惜。自今黃綬采蘭時，", "黎氓久厭蓬飄苦，遲爾西南惠月傳。"]'),
('yuding-13','送崔十三東游','錢起','唐','御定全唐诗','yuding','','[]','千里有同心，十年一會面。當杯緩箏柱，倏忽催離宴。',48,'御定全唐詩/json/236.json','["千里有同心，十年一會面。當杯緩箏柱，倏忽催離宴。", "丹鳳城頭噪晚鴉，行人馬首夕陽斜。灞上春風留別袂，"]'),
('yuding-14','送鄔三落第還鄉','錢起','唐','御定全唐诗','yuding','','[]','郢客文章絕世稀，常嗟時命與心違。十年失路誰知己，',48,'御定全唐詩/json/236.json','["郢客文章絕世稀，常嗟時命與心違。十年失路誰知己，", "關中新月對離尊，江上殘花待歸客。名宦無媒自古遲，"]'),
('yuding-15','送馬明府赴江陵','錢起','唐','御定全唐诗','yuding','','[]','陶令南行心自永，江天極目澄秋景。萬室遙方犬不鳴，',40,'御定全唐詩/json/236.json','["陶令南行心自永，江天極目澄秋景。萬室遙方犬不鳴，", "黃花滿把應相憶，落日登樓北望還。"]'),
('yuding-16','送畢侍禦謫居','錢起','唐','御定全唐诗','yuding','','[]','崇蘭香死玉簪折，志士吞聲甘徇節。忠藎不為明主知，',64,'御定全唐詩/json/236.json','["崇蘭香死玉簪折，志士吞聲甘徇節。忠藎不為明主知，", "百鳥喧喧噪一鶚，上林高枝亦難托。甯嗟人世棄虞翻，", "桃花洞裏舉家去，此別相思複幾春。"]'),
('yuding-17','送褚大落第東歸','錢起','唐','御定全唐诗','yuding','','[]','離琴彈苦調，美人慘向隅。頃來荷策幹明主，',84,'御定全唐詩/json/236.json','["離琴彈苦調，美人慘向隅。頃來荷策幹明主，", "玉堂金馬隔青雲，墨客儒生皆白首。昨夢芳洲采白蘋，", "剡中風月久相憶，池上舊游應再得。酒熟甯孤芳杜春，", "他日東流一乘興，知君為我掃荊扉。"]'),
('yuding-18','送傅管記赴蜀軍','錢起','唐','御定全唐诗','yuding','','[]','終童之死誰繼出，燕頷儒生今俊逸。主將早知鸚鵡賦，',72,'御定全唐詩/json/236.json','["終童之死誰繼出，燕頷儒生今俊逸。主將早知鸚鵡賦，", "巴山雨色藏征旆，漢水猿聲咽短簫。賜璧腰金應可料，", "日暮黃雲千里昏，壯心輕別不銷魂。勸君用卻龍泉劍，"]'),
('yuding-19','送張少府','錢起','唐','御定全唐诗','yuding','','[]','愁雲破斜照，別酌勸行子。蓬驚馬首風，雁拂天邊水。',36,'御定全唐詩/json/236.json','["愁雲破斜照，別酌勸行子。蓬驚馬首風，雁拂天邊水。", "寸晷如三歲，離心在萬里。"]'),
('yuding-20','行路難','錢起','唐','御定全唐诗','yuding','','[]','君不見明星映空月，太陽朝升光盡歇。',50,'御定全唐詩/json/236.json','["君不見明星映空月，太陽朝升光盡歇。", "君不見凋零委路蓬，長風飄舉入雲中。", "由來人事何嘗定，且莫驕奢笑賤窮。"]'),
('yuding-21','盧龍塞行送韋掌記','錢起','唐','御定全唐诗','yuding','','[]','雨雪紛紛黑山外，行人共指盧龍塞。萬里飛沙咽鼓鼙，',40,'御定全唐詩/json/236.json','["雨雪紛紛黑山外，行人共指盧龍塞。萬里飛沙咽鼓鼙，", "聖主好文兼好武，封侯莫比漢皇年。"]'),
('yuding-22','效古秋夜長','錢起','唐','御定全唐诗','yuding','','[]','秋漢飛玉霜，北風掃荷香。含情紡織孤燈盡，',44,'御定全唐詩/json/236.json','["秋漢飛玉霜，北風掃荷香。含情紡織孤燈盡，", "誰家少婦事鴛機，錦幕雲屏深掩扉。白玉窗中聞落葉，"]'),
('yuding-23','臥病，李員外題扉而去','錢起','唐','御定全唐诗','yuding','','[]','僻陋病者居，蒿萊行徑失。誰知簪紱貴，能問幽憂疾。',84,'御定全唐詩/json/236.json','["僻陋病者居，蒿萊行徑失。誰知簪紱貴，能問幽憂疾。", "珂聲未駐門，蘭氣先入室。沉屙不冠帶，安得候蓬蓽。", "清揚去莫尋，離念頃來侵。雀棲高窗靜，日出修桐陰。", "枕上憶君子，悄悄唯苦心。"]'),
('yuding-24','酬王維春夜竹亭贈別','錢起','唐','御定全唐诗','yuding','','[]','山月隨客來，主人興不淺。今宵竹林下，誰覺花源遠。',36,'御定全唐詩/json/236.json','["山月隨客來，主人興不淺。今宵竹林下，誰覺花源遠。", "惆悵曙鶯啼，孤雲還絕巘。"]'),
('yuding-25','山中寄時校書','錢起','唐','御定全唐诗','yuding','','[]','蓬萊紫氣溫如玉，唯予知爾陽春曲，別來幾日芳蓀綠。',40,'御定全唐詩/json/236.json','["蓬萊紫氣溫如玉，唯予知爾陽春曲，別來幾日芳蓀綠。", "百花酒滿不見君，青山一望心斷續。"]'),
('yuding-26','送李四擢第歸覲省','錢起','唐','御定全唐诗','yuding','','[]','當年貴得意，文字各爭名。齊唱陽春曲，唯君金玉聲。',156,'御定全唐詩/json/236.json','["當年貴得意，文字各爭名。齊唱陽春曲，唯君金玉聲。", "懸黎寶中出，高價世難掩。鴻羽不低飛，龍津徒自險。", "直矜鸚鵡賦，不貴芳桂枝。少俊蔡邕許，長鳴唐舉知。", "梁城下熊軾，朱戟何暐耀。才子欲歸甯，棠花已含笑。", "高門知慶大，子孝覺親榮。獨攬還珠美，寧唯問絹情。", "離筵不盡醉，摻袂一何早。馬蹄西別輕，樹色東看好。", "行塵忽不見，惆悵青門道。"]'),
('yuding-27','過曹鈞隱居','錢起','唐','御定全唐诗','yuding','','[]','荃蕙有奇性，馨香道為人。不居眾芳下，甯老空林春。',72,'御定全唐詩/json/236.json','["荃蕙有奇性，馨香道為人。不居眾芳下，甯老空林春。", "之子秉高節，攻文還守真。素書寸陰盡，流水怨情新。", "濟濟振纓客，煙霄各致身。誰當舉玄晏，不使作良臣。"]'),
('yuding-28','哭曹鈞','錢起','唐','御定全唐诗','yuding','','[]','苦節推白首，憐君負此生。忠藎名空在，家貧道不行。',64,'御定全唐詩/json/236.json','["苦節推白首，憐君負此生。忠藎名空在，家貧道不行。", "朝來相憶訪蓬蓽，只謂淵明猶臥疾。忽見江南吊鶴來，", "一聲鄰笛殘陽裏，酹酒空堂淚滿衣。"]'),
('yuding-29','東陽郡齋中詣南山招韋十','錢起','唐','御定全唐诗','yuding','','[]','霽來海半山，隱映城上起。中峰落照時，殘雪翠微裏。',48,'御定全唐詩/json/236.json','["霽來海半山，隱映城上起。中峰落照時，殘雪翠微裏。", "同心久為別，孤興那對此。良會何遲遲，清揚瞻則邇。"]'),
('yuding-30','清泥驛迎獻王侍禦','錢起','唐','御定全唐诗','yuding','','[]','候館掃清晝，使車出明光。森森入郭樹，一道引飛霜。',48,'御定全唐詩/json/236.json','["候館掃清晝，使車出明光。森森入郭樹，一道引飛霜。", "仰視驄花白，多慚綬色黃。鷦鷯無羽翼，願假憲烏翔。"]'),
('yuding-31','沭陽古渡作','錢起','唐','御定全唐诗','yuding','','[]','日落問津處，雲霞殘碧空。牧牛避田燒，退鷁隨潮風。',48,'御定全唐詩/json/236.json','["日落問津處，雲霞殘碧空。牧牛避田燒，退鷁隨潮風。", "回首故鄉遠，臨流此路窮。翩翩青冥去，羨彼高飛鴻。"]'),
('yuding-32','臥疾，答劉道士','錢起','唐','御定全唐诗','yuding','','[]','白露蠶已絲，空林日淒清。寥寥晝扉掩，獨臥秋窗明。',48,'御定全唐詩/json/236.json','["白露蠶已絲，空林日淒清。寥寥晝扉掩，獨臥秋窗明。", "寶字比仙藥，羽人寄柴荊。長吟想風馭，恍若升蓬瀛。"]'),
('yuding-33','夢尋西山准上人','錢起','唐','御定全唐诗','yuding','','[]','別處秋泉聲，至今猶在耳。何嘗夢魂去，不見雪山子。',60,'御定全唐詩/json/236.json','["別處秋泉聲，至今猶在耳。何嘗夢魂去，不見雪山子。", "新月隔林時，千峰翠微裏。言忘心更寂，跡滅雲自起。", "覺來纓上塵，如洗功德水。"]'),
('yuding-34','長安旅宿','錢起','唐','御定全唐诗','yuding','','[]','九秋旅夜長，萬感何時歇。蕙花漸寒暮，心事猶楚越。',60,'御定全唐詩/json/236.json','["九秋旅夜長，萬感何時歇。蕙花漸寒暮，心事猶楚越。", "直躬邅世道，咫步隔天闕。每聞長樂鐘，載泣靈台月。", "明旦北門外，歸途堪白髮。"]'),
('yuding-35','過桐柏山','錢起','唐','御定全唐诗','yuding','','[]','秋風過楚山，山靜秋聲晚。賞心無定極，仙步亦清遠。',60,'御定全唐詩/json/236.json','["秋風過楚山，山靜秋聲晚。賞心無定極，仙步亦清遠。", "返照雲竇空，寒流石苔淺。羽人昔已去，靈跡欣方踐。", "投策謝歸途，世緣從此遣。"]'),
('yuding-36','李士曹廳對雨','錢起','唐','御定全唐诗','yuding','','[]','春雨暗重城，訟庭深更寂。終朝人吏少，滿院煙雲集。',60,'御定全唐詩/json/236.json','["春雨暗重城，訟庭深更寂。終朝人吏少，滿院煙雲集。", "濕鳥壓花枝，新苔宜砌石。掾曹富文史，清興對詞客。", "愛爾蕙蘭叢，芳香飽時澤。"]'),
('yuding-37','登勝果寺南樓，雨中望嚴協律','錢起','唐','御定全唐诗','yuding','','[]','微雨侵晚陽，連山半藏碧。林端陟香榭，雲外遲來客。',60,'御定全唐詩/json/236.json','["微雨侵晚陽，連山半藏碧。林端陟香榭，雲外遲來客。", "孤村凝片煙，去水生遠白。但佳川原趣，不覺城池夕。", "更喜眼中人，清光漸咫尺。"]'),
('yuding-38','冬夜題旅館','錢起','唐','御定全唐诗','yuding','','[]','退飛憶林藪，樂業羨黎庶。四海盡窮途，一枝無宿處。',60,'御定全唐詩/json/236.json','["退飛憶林藪，樂業羨黎庶。四海盡窮途，一枝無宿處。", "嚴冬北風急，中夜哀鴻去。孤燭思何深，寒窗坐難曙。", "勞歌待明發，惆悵盈百慮。"]'),
('yuding-39','自終南山晚歸','錢起','唐','御定全唐诗','yuding','','[]','采苓日往還，得性非樵隱。白水到初闊，青山辭尚近。',60,'御定全唐詩/json/236.json','["采苓日往還，得性非樵隱。白水到初闊，青山辭尚近。", "絕境勝無倪，歸途興不盡。沮溺時返顧，牛羊自相引。", "逍遙不外求，塵慮從茲泯。"]'),
('yuding-40','早渡伊川見舊鄰作','錢起','唐','御定全唐诗','yuding','','[]','鶤雞鳴早霜，秋水寒旅涉。漁人昔鄰舍，相見具舟楫。',60,'御定全唐詩/json/236.json','["鶤雞鳴早霜，秋水寒旅涉。漁人昔鄰舍，相見具舟楫。", "出浦興未盡，向山心更愜。村落通白雲，茅茨隱紅葉。", "東皋滿時稼，歸客欣複業。"]'),
('yuding-41','夕發箭場岩下作','錢起','唐','御定全唐诗','yuding','','[]','行役不遑安，在幽機轉發。山谷無明晦，溪霞自興沒。',60,'御定全唐詩/json/236.json','["行役不遑安，在幽機轉發。山谷無明晦，溪霞自興沒。", "朝櫛杉下風，夕飲石上月。懿爾青雲士，垂纓朝鳳闕。", "寧知采竹人，每食慚薇蕨。"]'),
('yuding-42','同李五夕次香山精舍訪憲上人','錢起','唐','御定全唐诗','yuding','','[]','彼岸聞山鐘，仙舟過苕水。松門入幽映，石徑趨迤邐。',60,'御定全唐詩/json/236.json','["彼岸聞山鐘，仙舟過苕水。松門入幽映，石徑趨迤邐。", "初月開草堂，遠公方覯止。忘言在閑夜，凝念得微理。", "泠泠功德池，相與滌心耳。"]'),
('yuding-43','雨中望海上，懷郁林觀中道侶','錢起','唐','御定全唐诗','yuding','','[]','山觀海頭雨，懸沫動煙樹。只疑蒼茫裏，鬱島欲飛去。',60,'御定全唐詩/json/236.json','["山觀海頭雨，懸沫動煙樹。只疑蒼茫裏，鬱島欲飛去。", "大塊怒天吳，驚潮蕩雲路。群真儼盈想，一葦不可渡。", "惆悵赤城期，願假輕鴻馭。"]'),
('yuding-44','廣德初鑾駕出關後登高愁望二首','錢起','唐','御定全唐诗','yuding','','[]','長安不可望，遠處邊愁起。輦轂混戎夷，山河空表裏。',144,'御定全唐詩/json/236.json','["長安不可望，遠處邊愁起。輦轂混戎夷，山河空表裏。", "黃雲壓城闕，斜照移烽壘。漢幟遠成霞，胡馬來如蟻。", "不知涿鹿戰，早晚蚩尤死。渴日候河清，沉憂催暮齒。", "愁看秦川色，慘慘雲景晦。乾坤暫運行，品物遺覆載。", "黃塵漲戎馬，紫氣隨龍旆。掩泣指關東，日月妖氛外。", "臣心寄遠水，朝海去如帶。周德更休明，天衢佇開泰。"]'),
('yuding-45','獨往覆釜山，寄郎士元','錢起','唐','御定全唐诗','yuding','','[]','賞心無遠近，芳月好登望。勝事引幽人，山下複山上。',72,'御定全唐詩/json/236.json','["賞心無遠近，芳月好登望。勝事引幽人，山下複山上。", "將尋洞中藥，複愛湖外嶂。古壁苔入雲，陰溪樹穿浪。", "誰言世緣絕，更惜知音曠。鶯啼綠蘿春，回首還惆悵。"]'),
('yuding-46','送王季友赴洪州幕下','錢起','唐','御定全唐诗','yuding','','[]','列郡皆用武，南征所從誰。諸侯重才略，見子如瓊枝。',72,'御定全唐詩/json/236.json','["列郡皆用武，南征所從誰。諸侯重才略，見子如瓊枝。", "撫劍感知己，出門方遠辭。煙波帶幕府，海日生紅旗。", "問我何功德，負恩留玉墀。銷魂把別袂，愧爾酬明時。"]'),
('yuding-47','客舍贈鄭賁','錢起','唐','御定全唐诗','yuding','','[]','結交意不薄，匪席言莫違。世義隨波久，人生知己稀。',72,'御定全唐詩/json/236.json','["結交意不薄，匪席言莫違。世義隨波久，人生知己稀。", "先鳴誓相達，未遇還相依。一望金門詔，三看黃鳥飛。", "暝投同旅食，朝出易儒衣。嵇向林廬接，攜手行將歸。"]'),
('yuding-48','山中春仲寄汝上王恒、潁川沈沖','錢起','唐','御定全唐诗','yuding','','[]','隱者守恬泊，春山日深淨。誰知蟠木材，得性無人境。',72,'御定全唐詩/json/236.json','["隱者守恬泊，春山日深淨。誰知蟠木材，得性無人境。", "座隅泉出洞，竹上雲起嶺。饑狖入山廚，飲虹過藥井。", "前溪堪放逸，仲月好風景。遊目來遠思，摘芳寄汝潁。"]'),
('yuding-49','南中春意','錢起','唐','御定全唐诗','yuding','','[]','入仕無知言，游方隨世道。平生願開濟，遇物幹懷抱。',72,'御定全唐詩/json/236.json','["入仕無知言，游方隨世道。平生願開濟，遇物幹懷抱。", "已阻青雲期，甘同散樗老。客游南海曲，坐見韶陽早。", "舊國別佳人，他鄉思芳草。惜無鴻鵠翅，安得淩蒼昊。"]'),
('yuding-50','東陵藥堂寄張道士','錢起','唐','御定全唐诗','yuding','','[]','木落蒼山空，當軒秋水色。清旦振衣坐，永吟意何極。',72,'御定全唐詩/json/236.json','["木落蒼山空，當軒秋水色。清旦振衣坐，永吟意何極。", "願言金丹壽，一假鸞鳳翼。日夕開真經，言忘心更默。", "玄都有仙子，采藥早相識。煙霞難再期，焚香空歎息。"]'),
('yuding-51','苦雨憶皇甫冉','錢起','唐','御定全唐诗','yuding','','[]','涼雨門巷深，窮居成習靜。獨吟愁霖雨，更使秋思永。',72,'御定全唐詩/json/236.json','["涼雨門巷深，窮居成習靜。獨吟愁霖雨，更使秋思永。", "疲痾苦昏墊，日夕開軒屏。草木森已悲，衾幬清且冷。", "如何游宦客，江海隨泛梗。延首長相思，憂襟孰能整。"]'),
('yuding-52','寄任山人','錢起','唐','御定全唐诗','yuding','','[]','天階崇黼黻，世路有趨競。獨抱中孚爻，誰知苦寒詠。',72,'御定全唐詩/json/236.json','["天階崇黼黻，世路有趨競。獨抱中孚爻，誰知苦寒詠。", "行潦難朝海，散材空遇聖。豈無鳴鳳時，其如問津命。", "所思青山郭，再夢綠蘿徑。林泉春可遊，羨爾得其性。"]'),
('yuding-53','登秦嶺半岩遇雨','錢起','唐','御定全唐诗','yuding','','[]','屏翳忽騰氣，浮陽慘無暉。千峰掛飛雨，百尺搖翠微。',72,'御定全唐詩/json/236.json','["屏翳忽騰氣，浮陽慘無暉。千峰掛飛雨，百尺搖翠微。", "震電閃雲徑，奔流翻石磯。倚岩假松蓋，臨水羨荷衣。", "不得采苓去，空思乘月歸。且憐東皋上，水色侵荊扉。"]'),
('yuding-54','杪秋南山西峰題准上人蘭若','錢起','唐','御定全唐诗','yuding','','[]','向山看霽色，步步豁幽性。返照亂流明，寒空千嶂淨。',72,'御定全唐詩/json/236.json','["向山看霽色，步步豁幽性。返照亂流明，寒空千嶂淨。", "石門有餘好，霞殘月欲映。上詣遠公廬，孤峰懸一徑。", "雲裏隔窗火，松下聞山磬。客到兩忘言，猿心與禪定。"]'),
('yuding-55','田園雨後贈鄰人','錢起','唐','御定全唐诗','yuding','','[]','安排常任性，偃臥晚開戶。樵客荷蓑歸，向來春山雨。',72,'御定全唐詩/json/236.json','["安排常任性，偃臥晚開戶。樵客荷蓑歸，向來春山雨。", "殘雲虹未落，返景霞初吐。時鳥鳴村墟，新泉繞林圃。", "堯年尚恬泊，鄰里成太古。室邇人遂遙，相思怨芳杜。"]'),
('yuding-56','天門谷題孫逸人石壁','錢起','唐','御定全唐诗','yuding','','[]','崖石亂流處，竹深斜照歸。主人臥磻石，心耳滌清暉。',72,'御定全唐詩/json/236.json','["崖石亂流處，竹深斜照歸。主人臥磻石，心耳滌清暉。", "春雷近作解，空谷半芳菲。雲棟彩虹宿，藥圃蝴蝶飛。", "惡囂慕嘉遁，幾夜瞻少微。相見竟何說，忘情同息機。"]'),
('yuding-57','藍溪休沐，寄趙八給事','錢起','唐','御定全唐诗','yuding','','[]','蟲鳴歸舊裏，田野秋農閒。即事敦夙尚，衡門方再關。',72,'御定全唐詩/json/236.json','["蟲鳴歸舊裏，田野秋農閒。即事敦夙尚，衡門方再關。", "夕陽入東籬，爽氣高前山。霜蕙後時老，巢禽知暝還。", "侍臣黃樞寵，鳴玉青雲間。肯想觀魚處，寒泉照發斑。"]'),
('yuding-58','遊輞川至南山，寄谷口王十六','錢起','唐','御定全唐诗','yuding','','[]','山色不厭遠，我行隨處深。跡幽青蘿徑，思絕孤霞岑。',72,'御定全唐詩/json/236.json','["山色不厭遠，我行隨處深。跡幽青蘿徑，思絕孤霞岑。", "獨鶴引過浦，鳴猿呼入林。褰裳百泉裏，一步一清心。", "王子在何處，隔雲雞犬音。折麻定延佇，乘月期招尋。"]'),
('yuding-59','藍田溪與漁者宿','錢起','唐','御定全唐诗','yuding','','[]','獨遊屢忘歸，況此隱淪處。濯發清泠泉，月明不能去。',72,'御定全唐詩/json/236.json','["獨遊屢忘歸，況此隱淪處。濯發清泠泉，月明不能去。", "更憐垂綸叟，靜若沙上鷺。一論白雲心，千里滄洲趣。", "蘆中夜火盡，浦口秋山曙。歎息分枝禽，何時更相遇。"]'),
('yuding-60','淮上別范大','錢起','唐','御定全唐诗','yuding','','[]','悲風隕涼葉，送歸怨南楚。窮年將別離，寸晷申宴語。',72,'御定全唐詩/json/236.json','["悲風隕涼葉，送歸怨南楚。窮年將別離，寸晷申宴語。", "長淮流不盡，征棹忽複舉。碧落半愁雲，黃鶴時顧侶。", "游宦且未達，前途各修阻。分袂一相嗟，良辰更何許。"]'),
('yuding-61','離居夜雨，奉寄李京兆','錢起','唐','御定全唐诗','yuding','','[]','永夜不可度，蛩吟秋雨滴。寂寞想章台，始歎雲泥隔。',72,'御定全唐詩/json/236.json','["永夜不可度，蛩吟秋雨滴。寂寞想章台，始歎雲泥隔。", "雷聲匪君車，猶時過我廬。電影非君燭，猶能明我目。", "如何瓊樹枝，夢裏看不足。望望佳期阻，愁生寒草綠。"]'),
('yuding-62','歎畢少府以持法無隱見系','錢起','唐','御定全唐诗','yuding','','[]','用法本禁邪，盡心翻自極。畢公在囹圄，世事何糾纆。',72,'御定全唐詩/json/236.json','["用法本禁邪，盡心翻自極。畢公在囹圄，世事何糾纆。", "翠鳳呈其瑞，虞羅寄鎩翼。囚中千念時，窗外百花色。", "落景閉圜扉，春蟲網叢棘。古人不念文，紛淚莫沾臆。"]'),
('yuding-63','小園招隱','錢起','唐','御定全唐诗','yuding','','[]','支離鮮兄弟，形影如手足。但遂飲冰節，甘辭代耕祿。',72,'御定全唐詩/json/236.json','["支離鮮兄弟，形影如手足。但遂飲冰節，甘辭代耕祿。", "斑衣在林巷，始覺無羈束。交柯低戶陰，閑鳥將雛宿。", "窮通世情阻，日夜苔徑綠。誰言北郭貧，能分晏嬰粟。"]'),
('yuding-64','過溫逸人舊居','錢起','唐','御定全唐诗','yuding','','[]','返真難合道，懷舊仍無吊。浮俗漸澆淳，斯人誰繼妙。',72,'御定全唐詩/json/236.json','["返真難合道，懷舊仍無吊。浮俗漸澆淳，斯人誰繼妙。", "聲容在心耳，寧覺阻言笑。玄堂閉幾春，拱木齊雲嶠。", "鶴傳居士舞，猿得蘇門嘯。酹酒片陽微，空山想埋照。"]'),
('yuding-65','縣內水亭晨興聽訟','錢起','唐','御定全唐诗','yuding','','[]','晨光起宿露，池上判黎氓。借問秋泉色，何如拙宦情。',72,'御定全唐詩/json/236.json','["晨光起宿露，池上判黎氓。借問秋泉色，何如拙宦情。", "磨鉛辱利用，策蹇愁前程。昨夜明月滿，中心如鵲驚。", "負恩時易失，多病績難成。會惜寒塘晚，霜風吹杜蘅。"]'),
('yuding-66','海畔秋思','錢起','唐','御定全唐诗','yuding','','[]','匡濟難道合，去留隨興牽。偶為謝客事，不顧平子田。',84,'御定全唐詩/json/236.json','["匡濟難道合，去留隨興牽。偶為謝客事，不顧平子田。", "魏闕賁翹楚，此身長棄捐。箕裘空在念，咄咄誰推賢。", "無用即明代，養痾仍壯年。日夕望佳期，帝鄉路幾千。", "秋風晨夜起，零落愁芳荃。"]'),
('yuding-67','太子李舍人城東別業','錢起','唐','御定全唐诗','yuding','','[]','南山轉群木，昏曉擁山翠。小澤近龍居，清蒼常雨氣。',84,'御定全唐詩/json/236.json','["南山轉群木，昏曉擁山翠。小澤近龍居，清蒼常雨氣。", "君家北原上，千金買勝事。丹闕退朝回，白雲迎賞至。", "新晴村落外，處處煙景異。片水明斷岸，餘霞入古寺。", "東皋指歸翼，目盡有餘意。"]'),
('yuding-68','穀口新居寄同省朋故','錢起','唐','御定全唐诗','yuding','','[]','種黍傍煙溪，榛蕪兼沮洳。亦知生計薄，所貴隱身處。',84,'御定全唐詩/json/236.json','["種黍傍煙溪，榛蕪兼沮洳。亦知生計薄，所貴隱身處。", "橡栗石上村，莓苔水中路。蕭然授衣日，得此還山趣。", "汲井愛秋泉，結茅因古樹。閑雲與幽鳥，對我不能去。", "寄謝鴛鷺群，狎鷗拙所慕。"]'),
('yuding-69','京兆尹廳前甘棠樹降甘露','錢起','唐','御定全唐诗','yuding','','[]','內史用堯意，理京宣惠慈。氣和祥則降，孰謂天難知。',84,'御定全唐詩/json/236.json','["內史用堯意，理京宣惠慈。氣和祥則降，孰謂天難知。", "濟旱露為兆，有如塤應篪。豈無夭桃樹，灑此甘棠枝。", "玉色與人淨，珠光臨筆垂。協風與之俱，物性皆熙熙。", "何必鳳池上，方看作霖時。"]'),
('yuding-70','秋夜作','錢起','唐','御定全唐诗','yuding','','[]','萬計各無成，寸心日悠漫。浮生竟何窮，巧曆不能算。',84,'御定全唐詩/json/236.json','["萬計各無成，寸心日悠漫。浮生竟何窮，巧曆不能算。", "流落四海間，辛勤百年半。商歌向秋月，哀韻兼浩歎。", "寤寐怨佳期，美人隔霄漢。寒雲度窮水，別業繞垂幔。", "窗中問談雞，長夜何時旦。"]'),
('yuding-71','觀村人牧山田','錢起','唐','御定全唐诗','yuding','','[]','六府且未盈，三農爭務作。貧民乏井稅，塉土皆墾鑿。',84,'御定全唐詩/json/236.json','["六府且未盈，三農爭務作。貧民乏井稅，塉土皆墾鑿。", "禾黍入寒雲，茫茫半山郭。秋來積霖雨，霜降方銍獲。", "中田聚黎甿，反景空村落。顧慚不耕者，微祿同衛鶴。", "庶追周任言，敢負謝生諾。"]'),
('yuding-72','裴侍郎湘川回，以青竹筒相遺，因而贈之','錢起','唐','御定全唐诗','yuding','','[]','楚竹青玉潤，從來湘水陰。緘書取直節，君子知虛心。',84,'御定全唐詩/json/236.json','["楚竹青玉潤，從來湘水陰。緘書取直節，君子知虛心。", "入用隨憲簡，積文不受金。體將丹鳳直，色映秋霜深。", "寧肯假伶倫，謬為龍鳳吟。唯將翰院客，昔秘瑤華音。", "長跪捧嘉貺，歲寒慚所欽。"]'),
('yuding-73','東城初陷，與薛員外、王補闕暝投南山佛寺','錢起','唐','御定全唐诗','yuding','','[]','日昃石門裏，松聲山寺寒。香雲空靜影，定水無驚湍。',84,'御定全唐詩/json/236.json','["日昃石門裏，松聲山寺寒。香雲空靜影，定水無驚湍。", "洗足解塵纓，忽覺天形寬。清鐘揚虛穀，微月深重巒。", "噫我朝露世，翻浮與波瀾。行運遘憂患，何緣親盤桓。", "庶將鏡中象，盡作無生觀。"]'),
('yuding-74','奉和張荊州巡農晚望','錢起','唐','御定全唐诗','yuding','','[]','太清霽雲雷，陽春陶物象。明牧行春令，仁風助升長。',84,'御定全唐詩/json/236.json','["太清霽雲雷，陽春陶物象。明牧行春令，仁風助升長。", "時和俗勤業，播殖農厥壤。陰陰桑陌連，漠漠水田廣。", "郡中忽無事，方外還獨往。日暮駐歸軒，湖山有佳賞。", "宣城傳逸韻，千載誰此響。"]'),
('yuding-75','送包何東游','錢起','唐','御定全唐诗','yuding','','[]','水國嘗獨往，送君還念茲。湖山遠近色，昏旦煙霞時。',96,'御定全唐詩/json/236.json','["水國嘗獨往，送君還念茲。湖山遠近色，昏旦煙霞時。", "子好謝公跡，常吟孤嶼詩。果乘扁舟去，若與白鷗期。", "野趣及春好，客遊欣此辭。入雲投館僻，采碧過帆遲。", "江上日回首，琴中勞別思。春鴻刷歸翼，一寄杜蘅枝。"]'),
('yuding-76','酬陶六辭秩歸舊居見柬','錢起','唐','御定全唐诗','yuding','','[]','靖節昔高尚，令孫嗣清徽。舊廬雲峰下，獻歲車騎歸。',96,'御定全唐詩/json/236.json','["靖節昔高尚，令孫嗣清徽。舊廬雲峰下，獻歲車騎歸。", "去俗因解綬，憶山得采薇。田疇春事起，裏巷相尋稀。", "淵明醉乘興，閑門只掩扉。花禽驚曙月，鄰女上鳴機。", "畢娶願已果，養恬志寧違。吾當掛朝服，同爾緝荷衣。"]'),
('yuding-77','奉使采箭簳竹穀中晨興赴嶺','錢起','唐','御定全唐诗','yuding','','[]','孤客倦夜坐，聞猿乘早發。背溪已斜漢，登棧尚殘月。',84,'御定全唐詩/json/236.json','["孤客倦夜坐，聞猿乘早發。背溪已斜漢，登棧尚殘月。", "重峰轉森爽，幽步更超越。雲木聳鶴巢，風蘿掃虎穴。", "人群徒自遠，世役終難歇。入山非買山，采竹異采蕨。", "誰見子牟意，悁勞書魏闕。"]'),
('yuding-78','同嚴逸人東溪泛舟','錢起','唐','御定全唐诗','yuding','','[]','子陵江海心，高跡此閑放。漁舟在溪水，曾是敦夙尚。',96,'御定全唐詩/json/236.json','["子陵江海心，高跡此閑放。漁舟在溪水，曾是敦夙尚。", "朝霽收雲物，垂綸獨清曠。寒花古岸傍，唳鶴晴沙上。", "紛吾好貞逸，不遠來相訪。已接方外遊，仍陪郢中唱。", "歡言盡佳酌，高興延秋望。日暮浩歌還，紅霞亂青嶂。"]'),
('yuding-79','過沈氏山居','錢起','唐','御定全唐诗','yuding','','[]','雞鳴孤煙起，靜者能蔔築。喬木出雲心，閑門掩山腹。',96,'御定全唐詩/json/236.json','["雞鳴孤煙起，靜者能蔔築。喬木出雲心，閑門掩山腹。", "貧交喜相見，把臂歡不足。空林留宴言，永日清耳目。", "泉聲冷尊俎，荷氣香童僕。往往仙犬鳴，樵人度深竹。", "酒酣出穀口，世網何羈束。始願今不從，區區折腰祿。"]'),
('yuding-80','贈柏岩老人','錢起','唐','御定全唐诗','yuding','','[]','日與麋鹿群，賢哉買山叟。龐眉忽相見，避世一何久。',96,'御定全唐詩/json/236.json','["日與麋鹿群，賢哉買山叟。龐眉忽相見，避世一何久。", "林棲古崖曲，野事佳春後。瓠葉覆荊扉，栗苞垂甕牖。", "獨歌還獨酌，不耕亦不耦。磽田隔雲溪，多雨長稂莠。", "煙霞得情性，身世同芻狗。寄謝營道人，天真此翁有。"]'),
('yuding-81','送薛判官赴蜀','錢起','唐','御定全唐诗','yuding','','[]','橫笛聲轉悲，羽觴酣欲別。舉目叩關遠，離心不可說。',96,'御定全唐詩/json/236.json','["橫笛聲轉悲，羽觴酣欲別。舉目叩關遠，離心不可說。", "邊陲勞帝念，日下降才傑。路極巴水長，天銜劍峰缺。", "單車動夙夜，越境正炎節。星橋過客稀，火井蒸雲熱。", "陰符能制勝，千里在坐決。始見儒者雄，長纓系餘孽。"]'),
('yuding-82','詔許昌崔明府拜補闕','錢起','唐','御定全唐诗','yuding','','[]','儒者久營道，詔書方問賢。至精一耀世，高步誰同年。',96,'御定全唐詩/json/236.json','["儒者久營道，詔書方問賢。至精一耀世，高步誰同年。", "何樹可棲鳳，高梧枝拂天。脫身鳧舄裏，載筆虎闈前。", "日月傳軒後，衣冠真列仙。則知驪龍珠，不秘清泠泉。", "才子貴難見，郢歌空複傳。惜哉效顰客，心想勞嬋娟。"]'),
('yuding-83','仲春晚尋覆釜山','錢起','唐','御定全唐诗','yuding','','[]','蝴蝶弄和風，飛花不知晚。王孫尋芳草，步步忘路遠。',96,'御定全唐詩/json/236.json','["蝴蝶弄和風，飛花不知晚。王孫尋芳草，步步忘路遠。", "況我愛青山，涉趣皆遊踐。縈回必中路，陰晦陽複顯。", "古岸生新泉，霞峰映雪巘。交枝花色異，奇石雲根淺。", "碧洞志忘歸，紫芝行可搴。應嗤嵇叔夜，林臥方沉湎。"]'),
('yuding-84','贈東鄰鄭少府','錢起','唐','御定全唐诗','yuding','','[]','一聞白雪唱，願見清揚久。誰謂結綬來，得陪趨府後。',96,'御定全唐詩/json/236.json','["一聞白雪唱，願見清揚久。誰謂結綬來，得陪趨府後。", "小邑藍溪上，卑棲愜所偶。忘言複連牆，片月亦攜手。", "草色同春徑，鶯聲共高柳。美景百花時，平生一杯酒。", "聖朝法天地，以我為芻狗。秩滿歸白雲，期君訪穀口。"]'),
('yuding-85','謝張法曹萬頃小山暇景見憶','錢起','唐','御定全唐诗','yuding','','[]','樂道隨去處，養和解朝簪。茅堂近丹闕，佳致亦何深。',96,'御定全唐詩/json/236.json','["樂道隨去處，養和解朝簪。茅堂近丹闕，佳致亦何深。", "退食不趨府，忘機還在林。清風亂流上，永日小山陰。", "解籜雨中竹，將雛花際禽。物華對幽寂，弦酌兼詠吟。", "自昔仰高步，及茲勞所欽。郢歌叨繼組，知己複知音。"]'),
('yuding-86','罷章陵令山居過中峰道者二首','錢起','唐','御定全唐诗','yuding','','[]','寧辭園令秩，不改淵明調。解印無與言，見山始一笑。',180,'御定全唐詩/json/236.json','["寧辭園令秩，不改淵明調。解印無與言，見山始一笑。", "幽人還絕境，誰道苦奔峭。隨雲剩渡溪，出門更垂釣。", "吾廬青霞裏，窗樹玄猿嘯。微月清風來，方知散發妙。", "丘壑趣如此，暮年始棲偃。賴遇無心雲，不笑歸來晚。", "鳴鳩拂紅枝，初服傍清畎。昨日山僧來，猶嫌嘉遁淺。", "托君紫陽家，路滅心更遠。梯雲創其居，抱犢上絕巘。", "杏田溪一曲，霞境峰幾轉。路石掛飛泉，謝公應在眼。", "願言攜手去，采藥長不返。"]'),
('yuding-87','登覆釜山遇道人二首','錢起','唐','御定全唐诗','yuding','','[]','晨策趣無涯，名山深轉秀。三休變覆景，萬轉迷宇宙。',144,'御定全唐詩/json/236.json','["晨策趣無涯，名山深轉秀。三休變覆景，萬轉迷宇宙。", "攀崖到天窗，入洞窮玉溜。側徑蹲怪石，飛蘿擲驚狖。", "花間煉藥人，雞犬和乳竇。散發便迎客，采芝仍滿袖。", "郭璞賦遊仙，始願今可就。", "真氣重嶂裏，知君嘉遁幽。山階壓丹穴，藥井通洑流。", "道者帶經出，洞中攜我遊。欲驂白霓去，且為紫芝留。", "忽憶武陵事，別家疑數秋。"]'),
('yuding-88','尋華山雲台觀道士','錢起','唐','御定全唐诗','yuding','','[]','秋日西山明，勝趣引孤策。桃源數曲盡，洞口兩岸坼。',108,'御定全唐詩/json/236.json','["秋日西山明，勝趣引孤策。桃源數曲盡，洞口兩岸坼。", "還從罔象來，忽得仙靈宅。霓裳誰之子，霞酌能止客。", "殘陽在翠微，攜手更登曆。林行拂煙雨，溪望亂金碧。", "飛鳥下天窗，嫋松際雲壁。稍尋玄蹤遠，宛入寥天寂。", "願言葛仙翁，終年煉玉液。"]'),
('yuding-89','海上臥病寄王臨','錢起','唐','御定全唐诗','yuding','','[]','離客窮海陰，蕭辰歸思結。一隨浮雲滯，幾怨黃鵠別。',108,'御定全唐詩/json/236.json','["離客窮海陰，蕭辰歸思結。一隨浮雲滯，幾怨黃鵠別。", "妙年即沉痾，生事多所闕。劍中負明義，枕上惜玄發。", "之子良史才，華簪偶時哲。相思千里道，愁望飛鳥絕。", "歲暮冰雪寒，淮湖不可越。百年去心慮，孤影守薄劣。", "獨餘慕侶情，金石無休歇。"]'),
('yuding-90','登玉山諸峰，偶至悟真寺','錢起','唐','御定全唐诗','yuding','','[]','郭南雲水佳，訟簡野情發。紫芝每相引，黃綬不能絏。',132,'御定全唐詩/json/236.json','["郭南雲水佳，訟簡野情發。紫芝每相引，黃綬不能絏。", "稍入石門幽，始知靈境絕。冥搜未寸晷，仙徑俄九折。", "蟠木蓋石樑，崩岩露雲穴。數峰拔昆侖，秀色與空澈。", "玉氣交晴虹，桂花留曙月。半岩采瑉者，一點如片雪。", "真賞無前程，奇觀寧暫輟。更聞東林磬，可聽不可說。", "興中尋覺化，寂爾諸象滅。"]'),
('yuding-91','長安客舍，贈李行父明府','錢起','唐','御定全唐诗','yuding','','[]','藏器待時少，知人自古難。遂令丹穴鳳，晚食金琅玕。',132,'御定全唐詩/json/236.json','["藏器待時少，知人自古難。遂令丹穴鳳，晚食金琅玕。", "誰謂兵戈際，鳴琴方一彈。理煩善用簡，濟猛能兼寬。", "夙夜念黎庶，寢興非宴安。洪波未靜壑，何樹不驚鸞。", "鳧舄傍京輦，甿心懸灌壇。高槐暗苦雨，長劍生秋寒。", "旅食還為客，饑年亦盡歡。親勞攜鬥水，往往救泥蟠。", "但恐酬明義，蹉跎芳歲闌。"]'),
('yuding-92','美楊侍禦清文見示','錢起','唐','御定全唐诗','yuding','','[]','伯牙道喪來，弦絕無人續。誰知絕唱後，更有難和曲。',132,'御定全唐詩/json/236.json','["伯牙道喪來，弦絕無人續。誰知絕唱後，更有難和曲。", "層峰與清流，逸勢競奔蹙。清文不出戶，仿像皆在目。", "霧雪看滿懷，蘭荃坐盈掬。孤光碧潭月，一片昆侖玉。", "初見歌陽春，韶光變枯木。再見吟白雪，便覺雲肅肅。", "則知造化源，方寸能展縮。斯文不易遇，清爽心豈足。", "願言書諸紳，可以為佩服。"]'),
('yuding-93','山居新種花藥，與道士同游賦詩','錢起','唐','御定全唐诗','yuding','','[]','自樂魚鳥性，甯求農牧資。淺深愛岩壑，疏鑿盡幽奇。',132,'御定全唐詩/json/236.json','["自樂魚鳥性，甯求農牧資。淺深愛岩壑，疏鑿盡幽奇。", "雨花相助好，鶯鳴春草時。種蘭入山翠，引葛上花枝。", "風露拆紅紫，緣溪複映池。新泉香杜若，片石引江蘺。", "宛謂武陵洞，潛應造化移。杖策攜煙客，滿袖掇芳蕤。", "蝴蝶舞留我，仙雞閑傍籬。但令黃精熟，不慮韶光遲。", "笑指雲蘿徑，樵人那得知。"]'),
('yuding-94','初黃綬赴藍田縣作','錢起','唐','御定全唐诗','yuding','','[]','蟠木無匠伯，終年棄山樊。苦心非良知，安得入君門。',144,'御定全唐詩/json/236.json','["蟠木無匠伯，終年棄山樊。苦心非良知，安得入君門。", "忽忝英達顧，寧窺造化恩。螢光起腐草，雲翼騰沉鯤。", "片石世何用，良工心所存。一叨尉京甸，三省慚黎元。", "賢尹正趨府，僕夫儼歸軒。眼中縣胥色，耳裏蒼生言。", "居人散山水，即景真桃源。鹿聚入田徑，雞鳴隔嶺村。", "餐和俗久清，到邑政空論。且嘉訟庭寂，前階滿芳蓀。"]'),
('yuding-95','歸義寺題震上人壁','錢起','唐','御定全唐诗','yuding','','[]','入穀逢雨花，香綠引幽步。招提饒泉石，萬轉同一趣。',156,'御定全唐詩/json/236.json','["入穀逢雨花，香綠引幽步。招提饒泉石，萬轉同一趣。", "向背森碧峰，淺深羅古樹。堯皇未登極，此地曾隱霧。", "秘讖得神謀，因高思虎踞。太陽忽臨照，物象俄光煦。", "梵王宮始開，長者金先布。白水入禪境，碭山通覺路。", "往往無心雲，猶起潛龍處。仍聞七祖後，佛子繼調禦。", "溪鳥投慧燈，山蟬飽甘露。不作解纓客，寧知舍筏喻。", "身世已悟空，歸途複何去。"]'),
('yuding-0','奉和聖制登會昌山應制','錢起','唐','御定全唐诗','yuding','','[]','睿想入希夷，真遊到具茨。玉鑾登嶂遠，雲輅出花遲。',48,'御定全唐詩/json/237.json','["睿想入希夷，真遊到具茨。玉鑾登嶂遠，雲輅出花遲。", "泉壑凝神處，陽和布澤時。六龍多順動，四海正雍熙。"]'),
('yuding-1','省中對雪寄元判官、拾遺昆季','錢起','唐','御定全唐诗','yuding','','[]','萬點瑤台雪，飛來錦帳前。瓊枝應比淨，鶴發敢爭先。',48,'御定全唐詩/json/237.json','["萬點瑤台雪，飛來錦帳前。瓊枝應比淨，鶴發敢爭先。", "散影成花月，流光透竹煙。今朝謝家興，幾處郢歌傳。"]'),
('yuding-2','山齋獨坐，喜玄上人夕至','錢起','唐','御定全唐诗','yuding','','[]','捨下虎溪徑，煙霞入暝開。柴門兼竹靜，山月與僧來。',48,'御定全唐詩/json/237.json','["捨下虎溪徑，煙霞入暝開。柴門兼竹靜，山月與僧來。", "心瑩紅蓮水，言忘綠茗杯。前峰曙更好，斜漢欲西回。"]'),
('yuding-3','秋夜寄張、韋二主簿','錢起','唐','御定全唐诗','yuding','','[]','涼夜褰簾好，輕雲過月初。碧空河色淺，紅葉露聲虛。',48,'御定全唐詩/json/237.json','["涼夜褰簾好，輕雲過月初。碧空河色淺，紅葉露聲虛。", "道阻天難問，機忘世易疏。不知雙翠鳳，棲棘複何如。"]'),
('yuding-4','歸故山路逢鄰居隱者','錢起','唐','御定全唐诗','yuding','','[]','握手雲棲路，潸然恨幾重。誰知綠林盜，長占彩霞峰。',48,'御定全唐詩/json/237.json','["握手雲棲路，潸然恨幾重。誰知綠林盜，長占彩霞峰。", "心死池塘草，聲悲石徑松。無因芳杜月，琴酒更相逢。"]'),
('yuding-5','落第，劉拾遺相送東歸','錢起','唐','御定全唐诗','yuding','','[]','不醉百花酒，傷心千里歸。獨收和氏玉，還采舊山薇。',48,'御定全唐詩/json/237.json','["不醉百花酒，傷心千里歸。獨收和氏玉，還采舊山薇。", "出處離心盡，榮枯會面稀。預愁芳草色，一徑入衡闈。"]'),
('yuding-6','和劉七讀書','錢起','唐','御定全唐诗','yuding','','[]','夜雨深館靜，苦心黃卷前。雲陰留墨沼，螢影傍華編。',48,'御定全唐詩/json/237.json','["夜雨深館靜，苦心黃卷前。雲陰留墨沼，螢影傍華編。", "夢鳥富清藻，通經仍妙年。何愁丹穴鳳，不飲玉池泉。"]'),
('yuding-7','早下江甯','錢起','唐','御定全唐诗','yuding','','[]','暮天微雨散，涼吹片帆輕。雲物高秋節，山川孤客情。',48,'御定全唐詩/json/237.json','["暮天微雨散，涼吹片帆輕。雲物高秋節，山川孤客情。", "霜蘋留楚水，寒雁別吳城。宿浦有歸夢，愁猿莫夜鳴。"]'),
('yuding-8','登複州南樓','錢起','唐','御定全唐诗','yuding','','[]','孤樹延春日，他山卷曙霞。客心湖上雁，歸思日邊花。',48,'御定全唐詩/json/237.json','["孤樹延春日，他山卷曙霞。客心湖上雁，歸思日邊花。", "行李迷方久，歸期涉歲賒。故人雲路隔，何處寄瑤華。"]'),
('yuding-9','江陵晦日陪諸官泛舟','錢起','唐','御定全唐诗','yuding','','[]','節物堪為樂，江湖有主人。舟行深更好，山趣久彌新。',48,'御定全唐詩/json/237.json','["節物堪為樂，江湖有主人。舟行深更好，山趣久彌新。", "尊酒平生意，煙花異國春。城南無夜月，長袖莫留賓。"]'),
('yuding-10','縣城秋夕','錢起','唐','御定全唐诗','yuding','','[]','山城日易夕，愁生先掩扉。俸薄不沽酒，家貧忘授衣。',48,'御定全唐詩/json/237.json','["山城日易夕，愁生先掩扉。俸薄不沽酒，家貧忘授衣。", "露重蕙花落，月冷莎雞飛。效拙慚無補，雲林歎再歸。"]'),
('yuding-11','秋夜梁七兵曹同宿二首','錢起','唐','御定全唐诗','yuding','','[]','一笑不可得，同心相見稀。摘菱頻貰酒，待月未扃扉。',96,'御定全唐詩/json/237.json','["一笑不可得，同心相見稀。摘菱頻貰酒，待月未扃扉。", "星影低驚鵲，蟲聲傍旅衣。卑棲歲已晚，共羨雁南飛。", "好欲棄吾道，今宵又遇君。老夫相勸酒，稚子待題文。", "月下誰家笛，城頭幾片雲。如何此幽興，明日重離群。"]'),
('yuding-12','和萬年成少府寓直','錢起','唐','御定全唐诗','yuding','','[]','赤縣新秋夜，文人藻思催。鐘聲自仙掖，月色近霜台。',48,'御定全唐詩/json/237.json','["赤縣新秋夜，文人藻思催。鐘聲自仙掖，月色近霜台。", "一葉兼螢度，孤雲帶雁來。明朝紫書下，應問長卿才。"]'),
('yuding-13','春夜過長孫繹別業','錢起','唐','御定全唐诗','yuding','','[]','佳期難再得，清夜此雲林。帶竹新泉冷，穿花片月深。',48,'御定全唐詩/json/237.json','["佳期難再得，清夜此雲林。帶竹新泉冷，穿花片月深。", "含毫凝逸思，酌水話幽心。不覺星河轉，山枝驚曙禽。"]'),
('yuding-14','題溫處士山居','錢起','唐','御定全唐诗','yuding','','[]','誰知白雲外，別有綠蘿春。苔繞溪邊徑，花深洞裏人。',48,'御定全唐詩/json/237.json','["誰知白雲外，別有綠蘿春。苔繞溪邊徑，花深洞裏人。", "逸妻看種藥，稚子伴垂綸。潁上逃堯者，何如此養真。"]'),
('yuding-15','題陳季壁','錢起','唐','御定全唐诗','yuding','','[]','郢人何苦調，飲水仍布衾。煙火晝不起，蓬蒿春欲深。',48,'御定全唐詩/json/237.json','["郢人何苦調，飲水仍布衾。煙火晝不起，蓬蒿春欲深。", "前庭少喬木，鄰舍聞新禽。雖有征賢詔，終傷不遇心。"]'),
('yuding-16','贈鄰居齊六司倉','錢起','唐','御定全唐诗','yuding','','[]','沉冥眾所遺，咫尺絕佳期。始覺衡門下，翛然太古時。',48,'御定全唐詩/json/237.json','["沉冥眾所遺，咫尺絕佳期。始覺衡門下，翛然太古時。", "雞聲共鄰巷，燭影隔茅茨。坐惜牛羊徑，芳蓀白露滋。"]'),
('yuding-17','送征雁','錢起','唐','御定全唐诗','yuding','','[]','秋空萬里淨，嘹唳獨南征。風急翻霜冷，雲開見月驚。',48,'御定全唐詩/json/237.json','["秋空萬里淨，嘹唳獨南征。風急翻霜冷，雲開見月驚。", "塞長怯去翼，影滅有餘聲。悵望遙天外，鄉愁滿目生。"]'),
('yuding-18','宴郁林觀張道士房','錢起','唐','御定全唐诗','yuding','','[]','滅跡人間世，忘歸象外情。竹壇秋月冷，山殿夜鐘清。',48,'御定全唐詩/json/237.json','["滅跡人間世，忘歸象外情。竹壇秋月冷，山殿夜鐘清。", "仙侶披雲集，霞杯達曙傾。同歡不可再，朝暮赤龍迎。"]'),
('yuding-19','秋夕與梁鍠文宴','錢起','唐','御定全唐诗','yuding','','[]','客到衡門下，林香蕙草時。好風能自至，明月不須期。',48,'御定全唐詩/json/237.json','["客到衡門下，林香蕙草時。好風能自至，明月不須期。", "秋日翻荷影，晴光脆柳枝。留歡美清夜，甯覺曉鐘遲。"]'),
('yuding-20','哭空寂寺玄上人','錢起','唐','御定全唐诗','yuding','','[]','淒然雙樹下，垂淚遠公房。燈續生前火，爐添沒後香。',48,'御定全唐詩/json/237.json','["淒然雙樹下，垂淚遠公房。燈續生前火，爐添沒後香。", "陰階明片雪，寒竹響空廊。寂滅應為樂，塵心徒自傷。"]'),
('yuding-21','題精舍寺','錢起','唐','御定全唐诗','yuding','','[]','勝景不易遇，入門神頓清。房房占山色，處處分泉聲。',48,'御定全唐詩/json/237.json','["勝景不易遇，入門神頓清。房房占山色，處處分泉聲。", "詩思竹間得，道心松下生。何時來此地，擺落世間情。"]'),
('yuding-22','開元觀遇張侍禦','錢起','唐','御定全唐诗','yuding','','[]','碧落忘歸處，佳期不厭逢。晚涼生玉井，新暑避煙松。',48,'御定全唐詩/json/237.json','["碧落忘歸處，佳期不厭逢。晚涼生玉井，新暑避煙松。", "欲醉流霞酌，還醒度竹鐘。更憐琪樹下，歷歷見遙峰。"]'),
('yuding-23','和人秋歸終南山別業','錢起','唐','御定全唐诗','yuding','','[]','舊居三顧後，晚節重幽尋。野徑到門盡，山窗連竹陰。',48,'御定全唐詩/json/237.json','["舊居三顧後，晚節重幽尋。野徑到門盡，山窗連竹陰。", "昔年鶯出穀，今日鳳歸林。物外淩雲操，誰能繼此心。"]'),
('yuding-24','故相國苗公挽歌','錢起','唐','御定全唐诗','yuding','','[]','灞陵誰寵葬，漢主念蕭何。盛業留青史，浮榮逐逝波。',48,'御定全唐詩/json/237.json','["灞陵誰寵葬，漢主念蕭何。盛業留青史，浮榮逐逝波。", "隴雲仍作雨，薤露已成歌。悽愴平津閣，秋風吊客過。"]'),
('yuding-25','酬劉員外雨中見寄','錢起','唐','御定全唐诗','yuding','','[]','苦雨滴蘭砌，秋風生葛衣。潢汙三徑絕，砧杵四鄰稀。',48,'御定全唐詩/json/237.json','["苦雨滴蘭砌，秋風生葛衣。潢汙三徑絕，砧杵四鄰稀。", "分與玄豹隱，不為湘燕飛。慚君角巾折，猶肯問衡闈。"]'),
('yuding-26','賦得歸雲送李山人歸華山','錢起','唐','御定全唐诗','yuding','','[]','秀色橫千里，歸雲積幾重。欲依毛女岫，初卷少姨峰。',48,'御定全唐詩/json/237.json','["秀色橫千里，歸雲積幾重。欲依毛女岫，初卷少姨峰。", "蓋影隨征馬，衣香拂臥龍。只應函穀上，真氣日溶溶。"]'),
('yuding-27','過裴長官新亭','錢起','唐','御定全唐诗','yuding','','[]','茅屋多新意，芳林昨試移。野人知石路，戲鳥認花枝。',48,'御定全唐詩/json/237.json','["茅屋多新意，芳林昨試移。野人知石路，戲鳥認花枝。", "慢水縈蓬戶，閑雲掛竹籬。到家成一醉，歸馬不能騎。"]'),
('yuding-28','寄郢州郎士元使君','錢起','唐','御定全唐诗','yuding','','[]','龍節知無事，江城不掩扉。詩傳過客遠，書到故人稀。',48,'御定全唐詩/json/237.json','["龍節知無事，江城不掩扉。詩傳過客遠，書到故人稀。", "坐嘯看潮起，行春送雁歸。望舒三五夜，思盡謝玄暉。"]'),
('yuding-29','過長孫宅與朗上人茶會','錢起','唐','御定全唐诗','yuding','','[]','偶與息心侶，忘歸才子家。玄談兼藻思，綠茗代榴花。',48,'御定全唐詩/json/237.json','["偶與息心侶，忘歸才子家。玄談兼藻思，綠茗代榴花。", "岸幘看雲卷，含毫任景斜。松喬若逢此，不復醉流霞。"]'),
('yuding-30','下第題長安客舍','錢起','唐','御定全唐诗','yuding','','[]','不遂青雲望，愁看黃鳥飛。梨花度寒食，客子未春衣。',48,'御定全唐詩/json/237.json','["不遂青雲望，愁看黃鳥飛。梨花度寒食，客子未春衣。", "世事隨時變，交情與我違。空餘主人柳，相見卻依依。"]'),
('yuding-31','陪考功王員外城東池亭宴','錢起','唐','御定全唐诗','yuding','','[]','無雙錦帳郎，絕境有林塘。鶴靜疏群羽，蓬開失眾芳。',48,'御定全唐詩/json/237.json','["無雙錦帳郎，絕境有林塘。鶴靜疏群羽，蓬開失眾芳。", "晴山看不厭，流水趣何長。日晚催歸騎，鐘聲下夕陽。"]'),
('yuding-32','過孫員外藍田山居','錢起','唐','御定全唐诗','yuding','','[]','不知香署客，謝病翠微間。去幄蘭將老，辭車雉亦閑。',48,'御定全唐詩/json/237.json','["不知香署客，謝病翠微間。去幄蘭將老，辭車雉亦閑。", "近窗雲出洞，當戶竹連山。對酒溪霞晚，家人采蕨還。"]'),
('yuding-33','秋園晚沐','錢起','唐','御定全唐诗','yuding','','[]','黃卷在窮巷，歸來生道心。五株衰柳下，三徑小園深。',48,'御定全唐詩/json/237.json','["黃卷在窮巷，歸來生道心。五株衰柳下，三徑小園深。", "倒薤翻成字，寒花不假林。龐眉謝群彥，獨酌且閑吟。"]'),
('yuding-34','窮秋對雨','錢起','唐','御定全唐诗','yuding','','[]','晦日連苦雨，動息更邅回。生事萍無定，愁心雲不開。',48,'御定全唐詩/json/237.json','["晦日連苦雨，動息更邅回。生事萍無定，愁心雲不開。", "翟門悲暝雀，墨灶上寒苔。始信宣城守，乘流畏曝腮。"]'),
('yuding-35','裴迪南門秋夜對月','錢起','唐','御定全唐诗','yuding','','[]','夜來詩酒興，月滿謝公樓。影閉重門靜，寒生獨樹秋。',48,'御定全唐詩/json/237.json','["夜來詩酒興，月滿謝公樓。影閉重門靜，寒生獨樹秋。", "鵲驚隨葉散，螢遠入煙流。今夕遙天末，清光幾處愁。"]'),
('yuding-36','和蜀縣段明府秋城望歸期','錢起','唐','御定全唐诗','yuding','','[]','制錦蜀江靜，飛鳧漢闕遙。一茲風靡草，再視露盈條。',48,'御定全唐詩/json/237.json','["制錦蜀江靜，飛鳧漢闕遙。一茲風靡草，再視露盈條。", "旅望多愁思，秋天更泬寥。河陽傳麗藻，清韻入歌謠。"]'),
('yuding-37','晚歸藍田，酬王維給事贈別','錢起','唐','御定全唐诗','yuding','','[]','卑棲卻得性，每與白雲歸。徇祿仍懷橘，看山免采薇。',48,'御定全唐詩/json/237.json','["卑棲卻得性，每與白雲歸。徇祿仍懷橘，看山免采薇。", "暮禽先去馬，新月待開扉。霄漢時回首，知音青瑣闈。"]'),
('yuding-38','再得華侍禦書，聞巴中臥病','錢起','唐','御定全唐诗','yuding','','[]','芳信來相續，同心遠更親。數重雲外樹，不隔眼中人。',48,'御定全唐詩/json/237.json','["芳信來相續，同心遠更親。數重雲外樹，不隔眼中人。", "夢寐花驄色，相思黃鳥春。更聞公幹病，一夜二毛新。"]'),
('yuding-39','宿新裏館','錢起','唐','御定全唐诗','yuding','','[]','愁人待曉雞，秋雨暗淒淒。度燭螢時滅，傳書雁漸低。',48,'御定全唐詩/json/237.json','["愁人待曉雞，秋雨暗淒淒。度燭螢時滅，傳書雁漸低。", "客來知計誤，夢裏泣津迷。無以逃悲思，寒螿處處啼。"]'),
('yuding-40','穀口書齋寄楊補闕','錢起','唐','御定全唐诗','yuding','','[]','泉壑帶茅茨，雲霞生薜帷。竹憐新雨後，山愛夕陽時。',48,'御定全唐詩/json/237.json','["泉壑帶茅茨，雲霞生薜帷。竹憐新雨後，山愛夕陽時。", "閑鷺棲常早，秋花落更遲。家童掃蘿徑，昨與故人期。"]'),
('yuding-41','衡門春夜','錢起','唐','御定全唐诗','yuding','','[]','不厭晴林下，微風度葛巾。寧唯北窗月，自謂上皇人。',48,'御定全唐詩/json/237.json','["不厭晴林下，微風度葛巾。寧唯北窗月，自謂上皇人。", "叢筱輕新暑，孤花占晚春。寄言莊叟蝶，與爾得天真。"]'),
('yuding-42','題吳通微主人','錢起','唐','御定全唐诗','yuding','','[]','食貧無盡日，有願幾時諧。長嘯秋光晚，誰知志士懷。',48,'御定全唐詩/json/237.json','["食貧無盡日，有願幾時諧。長嘯秋光晚，誰知志士懷。", "朝煙不起灶，寒葉欲連階。飲水仍留我，孤燈點夜齋。"]'),
('yuding-43','晚次宿預館','錢起','唐','御定全唐诗','yuding','','[]','鄉心不可問，秋氣又相逢。飄泊方千里，離悲複幾重。',48,'御定全唐詩/json/237.json','["鄉心不可問，秋氣又相逢。飄泊方千里，離悲複幾重。", "回雲隨去雁，寒露滴鳴蛩。延頸遙天末，如聞故國鐘。"]'),
('yuding-44','藍上茅茨期王維補闕','錢起','唐','御定全唐诗','yuding','','[]','山中人不見，雲去夕陽過。淺瀨寒魚少，叢蘭秋蝶多。',48,'御定全唐詩/json/237.json','["山中人不見，雲去夕陽過。淺瀨寒魚少，叢蘭秋蝶多。", "老年疏世事，幽性樂天和。酒熟思才子，溪頭望玉珂。"]'),
('yuding-45','春宵寓直','錢起','唐','御定全唐诗','yuding','','[]','養拙慣雲臥，為郎如鳥棲。不知仙閣峻，惟覺玉繩低。',48,'御定全唐詩/json/237.json','["養拙慣雲臥，為郎如鳥棲。不知仙閣峻，惟覺玉繩低。", "帳喜香煙暖，詩慚賜筆題。未央春漏促，殘夢謝晨雞。"]'),
('yuding-46','新昌裏言懷','錢起','唐','御定全唐诗','yuding','','[]','性拙偶從宦，心閑多掩扉。雖看北堂草，不望舊山薇。',48,'御定全唐詩/json/237.json','["性拙偶從宦，心閑多掩扉。雖看北堂草，不望舊山薇。", "花月霽來好，雲泉堪夢歸。如何建章漏，催著早朝衣。"]'),
('yuding-47','秋夜寄袁中丞、王員外','錢起','唐','御定全唐诗','yuding','','[]','一夕盈千念，方知別者勞。衰榮難會面，魂夢暫同袍。',48,'御定全唐詩/json/237.json','["一夕盈千念，方知別者勞。衰榮難會面，魂夢暫同袍。", "片月臨階早，晴河度雁高。應憐蔣生徑，秋露滿蓬蒿。"]'),
('yuding-48','九日閒居寄登高數子','錢起','唐','御定全唐诗','yuding','','[]','初服棲窮巷，重陽憶舊遊。門閑謝病日，心醉授衣秋。',48,'御定全唐詩/json/237.json','["初服棲窮巷，重陽憶舊遊。門閑謝病日，心醉授衣秋。", "酒盡寒花笑，庭空暝雀愁。今朝落帽客，幾處管弦留。"]'),
('yuding-49','晚入宣城界','錢起','唐','御定全唐诗','yuding','','[]','斜日片帆陰，春風孤客心。山來指樵路，岸去惜花林。',48,'御定全唐詩/json/237.json','["斜日片帆陰，春風孤客心。山來指樵路，岸去惜花林。", "海氣蒸雲黑，潮聲隔雨深。鄉愁不可道，浦宿聽猿吟。"]'),
('yuding-50','靜夜酬通上人問疾','錢起','唐','御定全唐诗','yuding','','[]','東林生早涼，高枕遠公房。大士看心後，中宵清漏長。',48,'御定全唐詩/json/237.json','["東林生早涼，高枕遠公房。大士看心後，中宵清漏長。", "驚蟬出暗柳，微月隱回廊。何事沈痾久，舍毫問藥王。"]'),
('yuding-51','奉陪使君十四叔晚憩大雲門寺','錢起','唐','御定全唐诗','yuding','','[]','野寺千家外，閑行晚暫過。炎氛臨水盡，夕照傍林多。',48,'御定全唐詩/json/237.json','["野寺千家外，閑行晚暫過。炎氛臨水盡，夕照傍林多。", "境對知心妄，人安覺政和。繩床搖麈尾，佳趣滿滄波。"]'),
('yuding-52','省中春暮酬嵩陽焦道士見招','錢起','唐','御定全唐诗','yuding','','[]','朝花飛暝林，對酒傷春心。流年催素發，不覺映華簪。',48,'御定全唐詩/json/237.json','["朝花飛暝林，對酒傷春心。流年催素發，不覺映華簪。", "垂老遇知己，酬恩看寸陰。如何紫芝客，相憶白雲深。"]'),
('yuding-53','酬苗發員外宿龍池寺見寄','錢起','唐','御定全唐诗','yuding','','[]','寧知待漏客，清夜此從容。暫別迎車雉，還隨護法龍。',48,'御定全唐詩/json/237.json','["寧知待漏客，清夜此從容。暫別迎車雉，還隨護法龍。", "香煙輕上月，林嶺靜聞鐘。郢曲傳甘露，塵心洗幾重。"]'),
('yuding-54','貞懿皇后挽詞','錢起','唐','御定全唐诗','yuding','','[]','淑麗詩傳美，徽章禮飾哀。有恩加象服，無日祀高禖。',48,'御定全唐詩/json/237.json','["淑麗詩傳美，徽章禮飾哀。有恩加象服，無日祀高禖。", "曉月孤秋殿，寒山出夜台。通靈深眷想，青鳥獨飛來。"]'),
('yuding-55','歲初歸舊山','錢起','唐','御定全唐诗','yuding','','[]','欲知愚穀好，久別與春還。鶯暖初歸樹，雲晴卻戀山。',48,'御定全唐詩/json/237.json','["欲知愚穀好，久別與春還。鶯暖初歸樹，雲晴卻戀山。", "石田耕種少，野客性情閑。求仲應難見，殘陽且掩關。"]'),
('yuding-56','鑾駕避狄歲寄別韓雲卿','錢起','唐','御定全唐诗','yuding','','[]','白髮壯心死，愁看國步移。關山慘無色，親愛忽驚離。',48,'御定全唐詩/json/237.json','["白髮壯心死，愁看國步移。關山慘無色，親愛忽驚離。", "影絕龍分劍，聲哀鳥戀枝。茫茫雲海外，相憶不相知。"]'),
('yuding-57','詠白油帽送客','錢起','唐','御定全唐诗','yuding','','[]','薄質慚加首，愁陰幸庇身。卷舒無定日，行止必依人。',48,'御定全唐詩/json/237.json','["薄質慚加首，愁陰幸庇身。卷舒無定日，行止必依人。", "已沐脂膏惠，甯辭雨露頻。雖同客衣色，不染洛陽塵。"]'),
('yuding-58','藍上採石芥寄前李明府','錢起','唐','御定全唐诗','yuding','','[]','淵明遺愛處，山芥綠芳初。玩此春陰色，猶滋夜雨餘。',48,'御定全唐詩/json/237.json','["淵明遺愛處，山芥綠芳初。玩此春陰色，猶滋夜雨餘。", "隔溪煙葉小，覆石雪花舒。采采還相贈，瑤華信不如。"]'),
('yuding-59','送贇法師往上都','錢起','唐','御定全唐诗','yuding','','[]','遠近化人天，王城指日邊。宰君迎說法，童子伴隨緣。',48,'御定全唐詩/json/237.json','["遠近化人天，王城指日邊。宰君迎說法，童子伴隨緣。", "到處花為雨，行時杖出泉。今宵松月下，門閉想安禪。"]'),
('yuding-60','送沈少府還江甯','錢起','唐','御定全唐诗','yuding','','[]','遠宦碧雲外，此行佳興牽。湖山入閭井，鷗鳥傍神仙。',48,'御定全唐詩/json/237.json','["遠宦碧雲外，此行佳興牽。湖山入閭井，鷗鳥傍神仙。", "斜日背鄉樹，春潮迎客船。江樓新詠發，應與政聲傳。"]'),
('yuding-61','送虞說擢第東游','錢起','唐','御定全唐诗','yuding','','[]','湖山不可厭，東望有餘情。片玉登科後，孤舟任興行。',48,'御定全唐詩/json/237.json','["湖山不可厭，東望有餘情。片玉登科後，孤舟任興行。", "月中嚴子瀨，花際楚王城。歲暮雲皋鶴，聞天更一鳴。"]'),
('yuding-62','送少微師西行','錢起','唐','御定全唐诗','yuding','','[]','隨緣忽西去，何日返東林。世路寧嗟別，空門久息心。',48,'御定全唐詩/json/237.json','["隨緣忽西去，何日返東林。世路寧嗟別，空門久息心。", "人煙一飯少，山雪獨行深。天外猿啼處，誰聞清梵音。"]'),
('yuding-63','送昆山孫少府','錢起','唐','御定全唐诗','yuding','','[]','徇祿近滄海，乘流看碧霄。誰知仙吏去，宛與世塵遙。',48,'御定全唐詩/json/237.json','["徇祿近滄海，乘流看碧霄。誰知仙吏去，宛與世塵遙。", "遠帆背歸鳥，孤舟抵上潮。懸知訟庭靜，窗竹日蕭蕭。"]'),
('yuding-64','送屈突司馬充安西書記','錢起','唐','御定全唐诗','yuding','','[]','制勝三軍勁，澄清萬里餘。星飛龐統驥，箭發魯連書。',48,'御定全唐詩/json/237.json','["制勝三軍勁，澄清萬里餘。星飛龐統驥，箭發魯連書。", "海月低雲旆，江霞入錦車。遙知太阿劍，計日斬鯨魚。"]'),
('yuding-65','送時暹避難適荊南','錢起','唐','御定全唐诗','yuding','','[]','三歎把離袂，七哀深我情。雲天愁遠別，豺虎擁前程。',48,'御定全唐詩/json/237.json','["三歎把離袂，七哀深我情。雲天愁遠別，豺虎擁前程。", "駐馬戀攜手，隔河聞哭聲。相思昏若夢，淚眼幾時明。"]'),
('yuding-66','送邊補闕東歸省覲','錢起','唐','御定全唐诗','yuding','','[]','東去有餘意，春風生賜衣。鳳凰銜詔下，才子采蘭歸。',48,'御定全唐詩/json/237.json','["東去有餘意，春風生賜衣。鳳凰銜詔下，才子采蘭歸。", "鬥酒百花裏，情人一笑稀。別離須計日，相望在彤闈。"]'),
('yuding-67','送彈琴李長史往洪州','錢起','唐','御定全唐诗','yuding','','[]','抱琴為傲吏，孤棹複南行。幾度秋江水，皆添白雪聲。',48,'御定全唐詩/json/237.json','["抱琴為傲吏，孤棹複南行。幾度秋江水，皆添白雪聲。", "佳期來客夢，幽思緩王程。佐牧無勞問，心和政自平。"]'),
('yuding-68','送宋征君讓官還山','錢起','唐','御定全唐诗','yuding','','[]','至人無滯跡，謁帝複思玄。魏闕辭花綬，春山有杏田。',48,'御定全唐詩/json/237.json','["至人無滯跡，謁帝複思玄。魏闕辭花綬，春山有杏田。", "紫霞開別酒，黃鶴舞離弦。今夜思君夢，遙遙入洞天。"]'),
('yuding-69','送陳供奉恩敕放歸覲省','錢起','唐','御定全唐诗','yuding','','[]','得意今如此，清光不可攀。臣心堯日下，鄉思楚雲間。',48,'御定全唐詩/json/237.json','["得意今如此，清光不可攀。臣心堯日下，鄉思楚雲間。", "楊柳依歸棹，芙蓉棲舊山。采蘭兼衣錦，何似買臣還。"]'),
('yuding-70','送外甥范勉赴任常州長史兼覲省','錢起','唐','御定全唐诗','yuding','','[]','憐君展驥去，能解倚門愁。就養仍榮祿，還鄉即晝遊。',48,'御定全唐詩/json/237.json','["憐君展驥去，能解倚門愁。就養仍榮祿，還鄉即晝遊。", "橘花低客舍，蓴菜繞歸舟。與報垂綸叟，知吾世網留。"]'),
('yuding-71','隴右送韋三還京','錢起','唐','御定全唐诗','yuding','','[]','春風起東道，握手望京關。柳色從鄉至，鶯聲送客還。',48,'御定全唐詩/json/237.json','["春風起東道，握手望京關。柳色從鄉至，鶯聲送客還。", "嘶驂顧近驛，歸路出他山。舉目情難盡，羈離失志間。"]'),
('yuding-72','送元評事歸山居','錢起','唐','御定全唐诗','yuding','','[]','憶家望雲路，東去獨依依。水宿隨漁火，山行到竹扉。',48,'御定全唐詩/json/237.json','["憶家望雲路，東去獨依依。水宿隨漁火，山行到竹扉。", "寒花催酒熟，山犬喜人歸。遙羨書窗下，千峰出翠微。"]'),
('yuding-73','送武進韋明府','錢起','唐','御定全唐诗','yuding','','[]','理邑想無事，鳴琴不下堂。井田通楚越，津市半漁商。',48,'御定全唐詩/json/237.json','["理邑想無事，鳴琴不下堂。井田通楚越，津市半漁商。", "盧橘垂殘雨，紅蓮拆早霜。送君催白首，臨水獨思鄉。"]'),
('yuding-74','送上官侍禦','錢起','唐','御定全唐诗','yuding','','[]','執簡朝方下，乘軺去不賒。感恩輕遠道，入幕比還家。',48,'御定全唐詩/json/237.json','["執簡朝方下，乘軺去不賒。感恩輕遠道，入幕比還家。", "碣石春雲色，邯鄲古樹花。飛書報明主，烽火靜天涯。"]'),
('yuding-75','送郭秀才制舉下第南游','錢起','唐','御定全唐诗','yuding','','[]','失志思浪跡，知君晦近名。出關塵漸遠，過郢興彌清。',48,'御定全唐詩/json/237.json','["失志思浪跡，知君晦近名。出關塵漸遠，過郢興彌清。", "山盡溪初廣，人閑舟自行。探幽無旅思，莫畏楚猿鳴。"]'),
('yuding-76','送夏侯審校書東歸','錢起','唐','御定全唐诗','yuding','','[]','楚鄉飛鳥沒，獨與碧雲還。破鏡催歸客，殘陽見舊山。',48,'御定全唐詩/json/237.json','["楚鄉飛鳥沒，獨與碧雲還。破鏡催歸客，殘陽見舊山。", "詩成流水上，夢盡落花間。儻寄相思字，愁人定解顏。"]'),
('yuding-77','送衛功曹赴荊南','錢起','唐','御定全唐诗','yuding','','[]','漢家仍用武，才子晚成名。惆悵江陵去，誰知魏闕情。',48,'御定全唐詩/json/237.json','["漢家仍用武，才子晚成名。惆悵江陵去，誰知魏闕情。", "碧雲愁楚水，春酒醉宜城。定想褰帷政，還聞坐嘯聲。"]'),
('yuding-78','送馬使君赴鄭州','錢起','唐','御定全唐诗','yuding','','[]','東土忽無事，專城複任賢。喜觀班瑞禮，還在偃兵年。',48,'御定全唐詩/json/237.json','["東土忽無事，專城複任賢。喜觀班瑞禮，還在偃兵年。", "膏雨帶滎水，歸人耕圃田。遙知下車日，萬井起新煙。"]'),
('yuding-79','送郎四補闕東歸','錢起','唐','御定全唐诗','yuding','','[]','無事共幹世，多時廢隱淪。相看戀簪組，不覺老風塵。',48,'御定全唐詩/json/237.json','["無事共幹世，多時廢隱淪。相看戀簪組，不覺老風塵。", "勸酒憐今別，傷心倍去春。徒言樹萱草，何處慰離人。"]'),
('yuding-80','送陸三出尉','錢起','唐','御定全唐诗','yuding','','[]','春草晚來色，東門愁送君。盛才仍下位，明代負奇文。',48,'御定全唐詩/json/237.json','["春草晚來色，東門愁送君。盛才仍下位，明代負奇文。", "且樂神仙道，終隨鴛鷺群。梅生寄黃綬，不日在青雲。"]'),
('yuding-81','送安都秀才北還','錢起','唐','御定全唐诗','yuding','','[]','年少工文客，言離卻解顏。不嗟荊寶退，能喜彩衣還。',48,'御定全唐詩/json/237.json','["年少工文客，言離卻解顏。不嗟荊寶退，能喜彩衣還。", "新月來前館，高陽出故關。相思東北望，燕趙隔青山。"]'),
('yuding-82','送褚十一澡擢第歸吳覲省','錢起','唐','御定全唐诗','yuding','','[]','林表吳山色，詩人思不忘。向家流水便，懷橘彩衣香。',48,'御定全唐詩/json/237.json','["林表吳山色，詩人思不忘。向家流水便，懷橘彩衣香。", "滿酌留歸騎，前程未夕陽。愴茲江海去，誰惜杜蘅芳。"]'),
('yuding-83','送費秀才歸衡州','錢起','唐','御定全唐诗','yuding','','[]','南望瀟湘渚，詞人遠憶家。客心隨楚水，歸棹宿江花。',48,'御定全唐詩/json/237.json','["南望瀟湘渚，詞人遠憶家。客心隨楚水，歸棹宿江花。", "不畏心期阻，惟愁面會賒。雲天有飛翼，方寸佇瑤華。"]'),
('yuding-84','送陸郎中','錢起','唐','御定全唐诗','yuding','','[]','事邊仍戀主，舉酒複悲歌。粉署含香別，轅門載筆過。',48,'御定全唐詩/json/237.json','["事邊仍戀主，舉酒複悲歌。粉署含香別，轅門載筆過。", "鶯聲出漢苑，柳色過漳河。相憶情難盡，離居春草多。"]'),
('yuding-85','送僧歸日本','錢起','唐','御定全唐诗','yuding','','[]','上國隨緣住，來途若夢行。浮天滄海遠，去世法舟輕。',48,'御定全唐詩/json/237.json','["上國隨緣住，來途若夢行。浮天滄海遠，去世法舟輕。", "水月通禪觀，魚龍聽梵聲。惟憐一燈影，萬里眼中明。"]'),
('yuding-86','送楊皞擢第游江南','錢起','唐','御定全唐诗','yuding','','[]','行人臨水去，新詠複新悲。萬里高秋月，孤山遠別時。',48,'御定全唐詩/json/237.json','["行人臨水去，新詠複新悲。萬里高秋月，孤山遠別時。", "掛帆嚴子瀨，酹酒敬亭祠。歲晏無芳杜，如何寄所思。"]'),
('yuding-87','送田倉曹歸覲','錢起','唐','御定全唐诗','yuding','','[]','青絲絡驄馬，去府望梁城。節下趨庭處，秋來懷橘情。',48,'御定全唐詩/json/237.json','["青絲絡驄馬，去府望梁城。節下趨庭處，秋來懷橘情。", "別筵寒日晚，歸路碧雲生。千里相思夜，愁看新月明。"]'),
('yuding-88','送張管書記','錢起','唐','御定全唐诗','yuding','','[]','邊事多勞役，儒衣逐鼓鼙。日寒關樹外，峰盡塞雲西。',48,'御定全唐詩/json/237.json','["邊事多勞役，儒衣逐鼓鼙。日寒關樹外，峰盡塞雲西。", "河廣篷難度，天遙雁漸低。班超封定遠，之子去思齊。"]'),
('yuding-89','送蕭常侍北使','錢起','唐','御定全唐诗','yuding','','[]','絳節引雕戈，鳴騶動玉珂。戎城去日遠，漢使來年多。',48,'御定全唐詩/json/237.json','["絳節引雕戈，鳴騶動玉珂。戎城去日遠，漢使來年多。", "雁宿常連雪，沙飛半渡河。明光朝即邇，杕杜早成歌。"]'),
('yuding-90','送李棲桐道舉擢第還鄉省侍','錢起','唐','御定全唐诗','yuding','','[]','幾年深道要，一舉過賢關。名與玄珠出，鄉宜晝錦還。',48,'御定全唐詩/json/237.json','["幾年深道要，一舉過賢關。名與玄珠出，鄉宜晝錦還。", "蓮舟同宿浦，柳岸向家山。欲見寧親孝，儒衣稚子斑。"]'),
('yuding-91','送柳道士','錢起','唐','御定全唐诗','yuding','','[]','去世能成道，遊仙不定家。歸期千歲鶴，行邁五雲車。',48,'御定全唐詩/json/237.json','["去世能成道，遊仙不定家。歸期千歲鶴，行邁五雲車。", "海上春應盡，壺中日未斜。不知相憶處，琪樹幾枝花。"]'),
('yuding-92','送陸珽侍禦使新羅','錢起','唐','御定全唐诗','yuding','','[]','衣冠周柱史，才學我鄉人。受命辭雲陛，傾城送使臣。',48,'御定全唐詩/json/237.json','["衣冠周柱史，才學我鄉人。受命辭雲陛，傾城送使臣。", "去程滄海月，歸思上林春。始覺儒風遠，殊方禮樂新。"]'),
('yuding-93','重送陸侍禦使日本','錢起','唐','御定全唐诗','yuding','','[]','萬里三韓國，行人滿目愁。辭天使星遠，臨水澗霜秋。',48,'御定全唐詩/json/237.json','["萬里三韓國，行人滿目愁。辭天使星遠，臨水澗霜秋。", "雲佩迎仙島，虹旌過蜃樓。定知懷魏闕，回首海西頭。"]'),
('yuding-94','送陸贄擢第還蘇州','錢起','唐','御定全唐诗','yuding','','[]','鄉路歸何早，雲間喜擅名。思親盧橘熟，帶雨客帆輕。',48,'御定全唐詩/json/237.json','["鄉路歸何早，雲間喜擅名。思親盧橘熟，帶雨客帆輕。", "夜火臨津驛，晨鐘隔浦城。華亭養仙羽，計日再飛鳴。"]'),
('yuding-95','送虞說擢第南歸覲省','錢起','唐','御定全唐诗','yuding','','[]','南風起別袂，心到衡湘間。歸客楚山遠，孤舟雲水閑。',48,'御定全唐詩/json/237.json','["南風起別袂，心到衡湘間。歸客楚山遠，孤舟雲水閑。", "愛君採蓮處，花島連家山。得意且甯省，人生難此還。"]'),
('yuding-96','送原公南游','錢起','唐','御定全唐诗','yuding','','[]','有意兼程去，飄然二翼輕。故鄉多久別，春草不傷情。',48,'御定全唐詩/json/237.json','["有意兼程去，飄然二翼輕。故鄉多久別，春草不傷情。", "洗缽泉初暖，焚香曉更清。自言難解縛，何日伴師行。"]'),
('yuding-97','送萬兵曹赴廣陵','錢起','唐','御定全唐诗','yuding','','[]','秋日思還客，臨流語別離。楚城將坐嘯，郢曲有餘悲。',48,'御定全唐詩/json/237.json','["秋日思還客，臨流語別離。楚城將坐嘯，郢曲有餘悲。", "山晚桂花老，江寒蘋葉衰。應須楊得意，更誦長卿辭。"]'),
('yuding-98','送李判官赴桂州幕','錢起','唐','御定全唐诗','yuding','','[]','欲知儒道貴，縫掖見諸侯。且感千金諾，甯辭萬里遊。',48,'御定全唐詩/json/237.json','["欲知儒道貴，縫掖見諸侯。且感千金諾，甯辭萬里遊。", "雁峰侵瘴遠，桂水出雲流。坐惜離居晚，相思綠蕙秋。"]'),
('yuding-99','題蘇公林亭','錢起','唐','御定全唐诗','yuding','','[]','平津東閣在，別是竹林期。萬葉秋聲裏，千家落照時。',48,'御定全唐詩/json/237.json','["平津東閣在，別是竹林期。萬葉秋聲裏，千家落照時。", "門隨深巷靜，窗過遠鐘遲。客位苔生處，依然又賦詩。"]'),
('yuding-100','賦得寒雲輕重色，送子恂入京','錢起','唐','御定全唐诗','yuding','','[]','無限寒雲色，蒼茫淺更深。從龍如有瑞，捧日不成陰。',48,'御定全唐詩/json/237.json','["無限寒雲色，蒼茫淺更深。從龍如有瑞，捧日不成陰。", "積翠全低嶺，虛明半出林。帝鄉遙在目，鐵馬又駸駸。"]'),
('yuding-101','賦得叢蘭曙後色，送梁侍禦入京','錢起','唐','御定全唐诗','yuding','','[]','曙色傳芳意，分明錦繡叢。蘭生霽後日，花發夜來風。',48,'御定全唐詩/json/237.json','["曙色傳芳意，分明錦繡叢。蘭生霽後日，花發夜來風。", "不向三峰裏，全勝一縣中。遙知大苑內，應待五花驄。"]'),
('yuding-102','賦得餘冰','錢起','唐','御定全唐诗','yuding','','[]','曉日餘冰上，春池一鏡明。多從履處薄，偏向飲時清。',48,'御定全唐詩/json/237.json','["曉日餘冰上，春池一鏡明。多從履處薄，偏向飲時清。", "比雪光仍在，因風片不成。更隨舟楫去，猶可助堅貞。"]'),
('yuding-103','賦得浦口望斜月，送皇甫判官','錢起','唐','御定全唐诗','yuding','','[]','起見西樓月，依依向浦斜。動搖生淺浪，明滅照寒沙。',48,'御定全唐詩/json/237.json','["起見西樓月，依依向浦斜。動搖生淺浪，明滅照寒沙。", "水渚猶疑雪，梅林不辨花。送君無可贈，持此代瑤華。"]'),
('yuding-104','賦得綿綿思遠道，送岑判官入嶺','錢起','唐','御定全唐诗','yuding','','[]','極目煙霞外，孤舟一使星。興中尋白雪，夢裏過滄溟。',48,'御定全唐詩/json/237.json','["極目煙霞外，孤舟一使星。興中尋白雪，夢裏過滄溟。", "夜月松江戍，秋風竹塢亭。不知行遠近，芳草日青青。"]'),
('yuding-105','江甯春夜裴使君席送蕭員外','錢起','唐','御定全唐诗','yuding','','[]','花院日扶疏，江雲自卷舒。主人熊軾任，歸客雉門車。',48,'御定全唐詩/json/237.json','["花院日扶疏，江雲自卷舒。主人熊軾任，歸客雉門車。", "曙月稀星裏，春煙紫禁餘。行看石頭戍，記得是南徐。"]'),
('yuding-106','送薛八謫居','錢起','唐','御定全唐诗','yuding','','[]','東水將孤客，南行路幾千。虹翻潮上雨，鳥落瘴中天。',48,'御定全唐詩/json/237.json','["東水將孤客，南行路幾千。虹翻潮上雨，鳥落瘴中天。", "謫去寧留恨，思歸豈待年。銜杯且一醉，別淚莫潸然。"]'),
('yuding-107','送衡陽歸客','錢起','唐','御定全唐诗','yuding','','[]','歸客愛鳴榔，南征憶舊鄉。江山追宋玉，雲雨憶荊王。',48,'御定全唐詩/json/237.json','["歸客愛鳴榔，南征憶舊鄉。江山追宋玉，雲雨憶荊王。", "醉裏宜城近，歌中郢路長。憐君從此去，日夕望三湘。"]'),
('yuding-108','送員外侍禦入朝','錢起','唐','御定全唐诗','yuding','','[]','別思亂無緒，妖氛猶未清。含香五夜客，持賦十年兄。',48,'御定全唐詩/json/237.json','["別思亂無緒，妖氛猶未清。含香五夜客，持賦十年兄。", "霜拂金波樹，星回玉鬥城。自憐江上鶴，垂翅羨飛鳴。"]'),
('yuding-109','送李諫議歸荊州','錢起','唐','御定全唐诗','yuding','','[]','歸舟同不系，纖草剩忘憂。禁掖曾通籍，江城舊列侯。',48,'御定全唐詩/json/237.json','["歸舟同不系，纖草剩忘憂。禁掖曾通籍，江城舊列侯。", "暮帆依夏口，春雨夢荊州。何日朝雲陛，隨君拜冕旒。"]'),
('yuding-110','送元中丞江淮轉運','錢起','唐','御定全唐诗','yuding','','[]','薄稅歸天府，輕徭賴使臣。歡沾賜帛老，恩及卷綃人。',48,'御定全唐詩/json/237.json','["薄稅歸天府，輕徭賴使臣。歡沾賜帛老，恩及卷綃人。", "去問殊官俗，來經幾劫春。東南禦亭上，莫問有風塵。"]'),
('yuding-111','送唐別駕赴郢州','錢起','唐','御定全唐诗','yuding','','[]','少年從事好，此去別愁輕。滿座詩人興，隨君郢路行。',48,'御定全唐詩/json/237.json','["少年從事好，此去別愁輕。滿座詩人興，隨君郢路行。", "蒹葭侵驛樹，雲水抱山城。遙愛下車日，江皋春草生。"]'),
('yuding-112','送鄭巨及第後歸覲','錢起','唐','御定全唐诗','yuding','','[]','多才白華子，初擅桂枝名。嘉慶送歸客，新秋帶雨行。',48,'御定全唐詩/json/237.json','["多才白華子，初擅桂枝名。嘉慶送歸客，新秋帶雨行。", "離人背水去，喜鵲近家迎。別贈難為此，衰年畏後生。"]'),
('yuding-113','宿遠上人蘭若','錢起','唐','御定全唐诗','yuding','','[]','香花閉一林，真士此看心。行道白雲近，燃燈翠壁深。',48,'御定全唐詩/json/237.json','["香花閉一林，真士此看心。行道白雲近，燃燈翠壁深。", "梵筵清水月，禪坐冷山陰。更說東溪好，明朝乘興尋。"]'),
('yuding-114','酬元秘書晚出藍溪見寄','錢起','唐','御定全唐诗','yuding','','[]','野興引才子，獨行幽徑遲。雲留下山處，鳥靜出溪時。',48,'御定全唐詩/json/237.json','["野興引才子，獨行幽徑遲。雲留下山處，鳥靜出溪時。", "拙宦不忘隱，歸休常在茲。知音倘相訪，炊黍掃茅茨。"]');
